export enum UserRole {
  BOARD_MEMBER = 'board_member',
  MANAGER = 'manager'
}

export interface User {
  email: string;
  role: UserRole;
  isAuthenticated: boolean;
}

export interface Recording {
  id: string;
  title: string;
  timestamp: string; // ISO String
  duration: number; // in seconds
  note: string;
  blobId: string; // Reference to IndexedDB key
  status: 'ready' | 'uploading' | 'shared';
}

export interface AuthState {
  step: 'email' | 'code' | 'authenticated';
  email: string;
  loading: boolean;
  error?: string;
}

export interface AudioContextType {
  isRecording: boolean;
  recordingTime: number;
  analyserData: Uint8Array | null;
}

const DB_NAME = 'frontsteps_notes_db';
const STORE_NAME = 'audio_blobs';
const DB_VERSION = 1;

export const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME);
      }
    };

    request.onsuccess = (event) => {
      resolve((event.target as IDBOpenDBRequest).result);
    };

    request.onerror = (event) => {
      reject((event.target as IDBOpenDBRequest).error);
    };
  });
};

export const saveAudioBlob = async (id: string, blob: Blob): Promise<void> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_NAME], 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.put(blob, id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

export const getAudioBlob = async (id: string): Promise<Blob | undefined> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_NAME], 'readonly');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.get(id);

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const deleteAudioBlob = async (id: string): Promise<void> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_NAME], 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.delete(id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

import { Recording, User } from '../types';

const RECORDINGS_KEY = 'frontsteps_recordings_meta';
const USER_KEY = 'frontsteps_user_session';

export const getRecordingsMeta = (): Recording[] => {
  try {
    const data = localStorage.getItem(RECORDINGS_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    console.error("Failed to load recordings", e);
    return [];
  }
};

export const saveRecordingsMeta = (recordings: Recording[]): void => {
  localStorage.setItem(RECORDINGS_KEY, JSON.stringify(recordings));
};

export const getUserSession = (): User | null => {
  try {
    const data = localStorage.getItem(USER_KEY);
    return data ? JSON.parse(data) : null;
  } catch (e) {
    return null;
  }
};

export const saveUserSession = (user: User): void => {
  localStorage.setItem(USER_KEY, JSON.stringify(user));
};

export const clearUserSession = (): void => {
  localStorage.removeItem(USER_KEY);
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Mic, Square, Loader2 } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string) => void;
}

export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);

  const startRecording = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Use a mimeType supported by the browser, prioritize mp4/webm
      const mimeType = MediaRecorder.isTypeSupported('audio/mp4')
        ? 'audio/mp4'
        : 'audio/webm';

      const recorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      recorder.onstop = async () => {
        setIsProcessing(true);
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const blobId = `rec_${Date.now()}`;

        // Save to IndexedDB
        try {
            await saveAudioBlob(blobId, blob);

            // Generate a friendly name
            const now = new Date();
            const defaultName = `Recording ${now.toLocaleDateString()} ${now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}`;

            onRecordingComplete(blobId, duration, defaultName);
        } catch (err) {
            setError("Failed to save recording. Storage might be full.");
            console.error(err);
        } finally {
            setIsProcessing(false);
            setDuration(0);
        }

        // Clean up tracks
        streamRef.current?.getTracks().forEach(track => track.stop());
      };

      recorder.start();
      setIsRecording(true);

      // Start timer
      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => {
        setDuration(Math.floor((Date.now() - startTime) / 1000));
      }, 1000);

    } catch (err) {
      console.error(err);
      setError("Microphone access denied or unavailable.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
      }
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    };
  }, []);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col items-center justify-center space-y-6">

      {/* Visualization Area */}
      <div className="relative flex items-center justify-center h-32 w-full">
        {isRecording ? (
          <div className="flex items-center space-x-1">
             <span className="w-2 h-8 bg-fs-primary rounded-full animate-pulse-slow" style={{ animationDelay: '0ms' }}></span>
             <span className="w-2 h-12 bg-fs-primary rounded-full animate-pulse-slow" style={{ animationDelay: '100ms' }}></span>
             <span className="w-2 h-16 bg-fs-primary rounded-full animate-pulse-slow" style={{ animationDelay: '200ms' }}></span>
             <span className="w-2 h-10 bg-fs-primary rounded-full animate-pulse-slow" style={{ animationDelay: '300ms' }}></span>
             <span className="w-2 h-6 bg-fs-primary rounded-full animate-pulse-slow" style={{ animationDelay: '400ms' }}></span>
          </div>
        ) : (
          <div className="text-slate-400 text-sm font-medium">
             {isProcessing ? "Processing audio..." : "Tap microphone to start recording"}
          </div>
        )}
      </div>

      {/* Timer */}
      <div className="text-4xl font-mono font-bold text-slate-700 tracking-wider">
        {formatTime(duration)}
      </div>

      {/* Controls */}
      <div className="flex items-center justify-center">
        {isProcessing ? (
           <div className="flex items-center space-x-2 text-fs-primary font-semibold">
             <Loader2 className="w-6 h-6 animate-spin" />
             <span>Saving...</span>
           </div>
        ) : !isRecording ? (
          <button 
            onClick={startRecording}
            className="group relative flex items-center justify-center w-20 h-20 bg-fs-primary hover:bg-emerald-600 rounded-full shadow-lg hover:shadow-xl transition-all duration-200 focus:outline-none focus:ring-4 focus:ring-emerald-200"
          >
            <Mic className="w-8 h-8 text-white" />
            <span className="absolute -bottom-8 text-xs font-semibold text-slate-500 opacity-0 group-hover:opacity-100 transition-opacity">Record</span>
          </button>
        ) : (
          <button 
            onClick={stopRecording}
            className="group relative flex items-center justify-center w-20 h-20 bg-red-500 hover:bg-red-600 rounded-full shadow-lg hover:shadow-xl transition-all duration-200 focus:outline-none focus:ring-4 focus:ring-red-200"
          >
            <Square className="w-8 h-8 text-white fill-current" />
            <span className="absolute -bottom-8 text-xs font-semibold text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">Stop</span>
          </button>
        )}
      </div>

      {error && (
        <p className="text-red-500 text-sm bg-red-50 px-3 py-1 rounded-full">{error}</p>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Play, Pause, Share2, FileText, Clock, Edit2, Check, Download } from 'lucide-react';
import { Recording, User, UserRole } from '../types';
import { getAudioBlob } from '../services/dbService';

interface RecordingListProps {
  recordings: Recording[];
  currentUser: User;
  onUpdateRecording: (updated: Recording) => void;
  onShare: (recording: Recording) => void;
}

export const RecordingList: React.FC<RecordingListProps> = ({ 
  recordings, 
  currentUser,
  onUpdateRecording,
  onShare
}) => {
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNote, setEditNote] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);

  // Clean up audio on unmount
  useEffect(() => {
    return () => {
      if (audioEl) {
        audioEl.pause();
        audioEl.src = '';
      }
    };
  }, [audioEl]);

  const handlePlay = async (recording: Recording) => {
    if (playingId === recording.id && audioEl) {
      audioEl.pause();
      setPlayingId(null);
      return;
    }

    if (audioEl) {
      audioEl.pause();
    }

    try {
      const blob = await getAudioBlob(recording.blobId);
      if (!blob) {
        alert("Audio file not found.");
        return;
      }

      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);

      audio.onended = () => setPlayingId(null);
      audio.play();

      setAudioEl(audio);
      setPlayingId(recording.id);
    } catch (e) {
      console.error("Error playing audio", e);
    }
  };

  const handleStartEdit = (rec: Recording) => {
    setEditingId(rec.id);
    setEditTitle(rec.title);
    setEditNote(rec.note);
    setExpandedId(rec.id);
  };

  const handleSaveEdit = (rec: Recording) => {
    onUpdateRecording({
      ...rec,
      title: editTitle,
      note: editNote
    });
    setEditingId(null);
  };

  const handleDownload = async (rec: Recording) => {
      try {
        const blob = await getAudioBlob(rec.blobId);
        if (blob) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.mp3`; // Naming it MP3 for user convenience, even if underlying is webm
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
      } catch (e) {
          console.error(e);
      }
  };

  if (recordings.length === 0) {
    return (
        <div className="text-center py-12 px-4">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileText className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-medium text-slate-900">No recordings yet</h3>
            <p className="text-slate-500 max-w-sm mx-auto mt-2">
                Tap the microphone button above to start recording your board meeting.
            </p>
        </div>
    );
  }

  return (
    <div className="space-y-4">
      {recordings.map((rec) => (
        <div key={rec.id} className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden transition-all duration-200 hover:shadow-md">
          <div className="p-4">

            {/* Header / Title */}
            <div className="flex items-start justify-between mb-2">
              <div className="flex-1 mr-4">
                {editingId === rec.id ? (
                    <input 
                        type="text" 
                        value={editTitle}
                        onChange={(e) => setEditTitle(e.target.value)}
                        className="w-full text-lg font-semibold text-slate-900 border-b-2 border-fs-primary focus:outline-none bg-transparent"
                        autoFocus
                    />
                ) : (
                    <h3 className="text-lg font-semibold text-slate-900 leading-tight">
                        {rec.title}
                    </h3>
                )}
                <div className="flex items-center text-xs text-slate-500 mt-1 space-x-3">
                    <span className="flex items-center">
                        <Clock className="w-3 h-3 mr-1" />
                        {new Date(rec.timestamp).toLocaleDateString()}
                    </span>
                    <span className="font-mono bg-slate-100 px-1.5 py-0.5 rounded">
                        {Math.floor(rec.duration / 60)}:{String(rec.duration % 60).padStart(2, '0')}
                    </span>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex items-center space-x-1">
                 {editingId === rec.id ? (
                     <button 
                        onClick={() => handleSaveEdit(rec)}
                        className="p-2 text-fs-primary hover:bg-emerald-50 rounded-full"
                    >
                        <Check className="w-5 h-5" />
                     </button>
                 ) : (
                     <button 
                        onClick={() => handleStartEdit(rec)}
                        className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full"
                    >
                        <Edit2 className="w-4 h-4" />
                     </button>
                 )}
              </div>
            </div>

            {/* Notes Section */}
            {(expandedId === rec.id || rec.note) && (
                 <div className="mt-3 bg-slate-50 rounded p-3 text-sm">
                    {editingId === rec.id ? (
                        <textarea 
                            value={editNote}
                            onChange={(e) => setEditNote(e.target.value)}
                            placeholder="Add meeting notes, agenda items, or action points..."
                            className="w-full bg-transparent focus:outline-none min-h-[60px] text-slate-700 resize-none"
                        />
                    ) : (
                        <p className="text-slate-600 whitespace-pre-wrap">
                            {rec.note || <span className="text-slate-400 italic">No notes added.</span>}
                        </p>
                    )}
                 </div>
            )}

            {/* Expanded Controls for non-editing state */}
            {editingId !== rec.id && (
                <div className="mt-4 flex items-center justify-between border-t border-slate-100 pt-3">
                     <button 
                        onClick={() => handlePlay(rec)}
                        className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                            playingId === rec.id 
                            ? 'bg-slate-900 text-white' 
                            : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                        }`}
                     >
                         {playingId === rec.id ? <Pause className="w-4 h-4 mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                         {playingId === rec.id ? 'Pause' : 'Play'}
                     </button>

                     <div className="flex space-x-2">
                        <button 
                            onClick={() => handleDownload(rec)}
                            className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                            title="Download MP3"
                        >
                            <Download className="w-5 h-5" />
                        </button>
                        <button 
                            onClick={() => onShare(rec)}
                            disabled={rec.status === 'shared'}
                            className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                rec.status === 'shared'
                                ? 'bg-green-100 text-green-700 cursor-default'
                                : 'bg-fs-primary text-white hover:bg-emerald-600 shadow-sm'
                            }`}
                        >
                            {rec.status === 'shared' ? (
                                <>
                                    <Check className="w-4 h-4 mr-2" />
                                    Shared to ALLi
                                </>
                            ) : (
                                <>
                                    <Share2 className="w-4 h-4 mr-2" />
                                    Share to ALLi
                                </>
                            )}
                        </button>
                     </div>
                </div>
            )}

          </div>
        </div>
      ))}
    </div>
  );
};

import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { Mail, ArrowRight, Loader2, ShieldCheck } from 'lucide-react';

interface AuthScreenProps {
  onLogin: (user: User) => void;
}

export const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin }) => {
  const [step, setStep] = useState<'email' | 'code'>('email');
