                    <span className="text-2xl font-bold text-white tracking-tight">FRONTST<span className="text-fs-primary">Ξ</span>PS</span>
                 </div>
             </div>
             <h2 className="text-xl font-semibold text-white">Note Taker</h2>
             <p className="text-slate-400 text-sm mt-2">Secure recording companion for ALLi</p>
        </div>

        <div className="p-8">
            {step === 'email' ? (
                <form onSubmit={handleSendCode} className="space-y-6">
