                        <label className="block text-sm font-medium text-slate-700 mb-2">Login as</label>
                        <div className="grid grid-cols-2 gap-3">
                            <button
                                type="button"
                                onClick={() => setSelectedRole(UserRole.BOARD_MEMBER)}
                                className={`py-2 px-3 text-sm font-medium rounded-md border transition-all ${
                                    selectedRole === UserRole.BOARD_MEMBER 
