import React, { useState, useEffect } from 'react';
import { User, Recording, UserRole } from './types';
import { getRecordingsMeta, saveRecordingsMeta, getUserSession, saveUserSession, clearUserSession } from './services/storageService';
import { AuthScreen } from './components/AuthScreen';
import { Recorder } from './components/Recorder';
import { RecordingList } from './components/RecordingList';
import { LogOut, LayoutGrid, Menu } from 'lucide-react';
import { transcribeAudio } from './services/aiService';
import { getAudioBlob } from './services/dbService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [recordings, setRecordings] = useState<Recording[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Initialize app
  useEffect(() => {
    const session = getUserSession();
    if (session) {
      setUser(session);
    }
    const savedRecs = getRecordingsMeta();
    setRecordings(savedRecs);
    setIsLoading(false);
  }, []);

  // Persist recordings when changed
  useEffect(() => {
    if (!isLoading) {
      saveRecordingsMeta(recordings);
    }
  }, [recordings, isLoading]);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    saveUserSession(newUser);
  };

  const handleLogout = () => {
    setUser(null);
    clearUserSession();
  };

  const handleRecordingComplete = async (blobId: string, duration: number, defaultName: string) => {
    const newRecording: Recording = {
      id: crypto.randomUUID(),
      title: defaultName,
      timestamp: new Date().toISOString(),
      duration: duration,
      note: '',
      blobId: blobId,
      status: 'ready',
      isTranscribing: true,
    };
    setRecordings(prev => [newRecording, ...prev]);

    try {
      const blob = await getAudioBlob(blobId);
      if (blob) {
        const transcription = await transcribeAudio(blob);
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, transcription, isTranscribing: false } 
            : rec
        ));
      } else {
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, isTranscribing: false } 
            : rec
        ));
      }
    } catch (error) {
      console.error('Transcription failed', error);
      setRecordings(prev => prev.map(rec => 
        rec.id === newRecording.id 
          ? { ...rec, isTranscribing: false } 
          : rec
      ));
    }
  };

  const handleUpdateRecording = (updated: Recording) => {
    setRecordings(prev => prev.map(r => r.id === updated.id ? updated : r));
  };

  const handleShare = async (rec: Recording) => {
    // Mock API Push to ALLi
    const confirmShare = window.confirm(`Push "${rec.title}" to ALLi? This will make it available to the board.`);
    if (!confirmShare) return;

    // Optimistic update
    handleUpdateRecording({ ...rec, status: 'shared' });

    // Mock redirection based on Role
    setTimeout(() => {
      if (user?.role === UserRole.BOARD_MEMBER) {
        // Deep link simulation
        alert("Redirecting to FRONTSTEPS Community App...");
        // In real app: window.location.href = 'frontsteps://community/recordings...'
      } else if (user?.role === UserRole.MANAGER) {
        window.open('https://suite.frontsteps.com/#/steps/overview', '_blank');
      }
    }, 1000);
  };

  if (isLoading) return null;

  if (!user) {
    return <AuthScreen onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">

      {/* Sidebar (Desktop) / Header (Mobile) */}
      <div className="md:w-64 bg-fs-dark flex-shrink-0 md:h-screen flex flex-col justify-between">
        <div className="p-6">
           <div className="flex items-center space-x-2 mb-8">
               <div className="h-8 w-8 bg-fs-primary rounded-md flex items-center justify-center text-white font-bold text-xl">N</div>
               <span className="text-xl font-bold text-white tracking-tight">FRONTSTEPS</span>
           </div>

           <div className="md:block hidden space-y-2">
              <div className="flex items-center space-x-3 text-white bg-slate-800 px-3 py-2 rounded-lg">
                 <LayoutGrid className="w-5 h-5 text-fs-primary" />
                 <span className="text-sm font-medium">Recordings</span>
              </div>
           </div>
        </div>

        {/* User Profile Snippet */}
        <div className="p-4 bg-fs-darker border-t border-slate-800">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-3 overflow-hidden">
               <div className="w-8 h-8 rounded-full bg-slate-600 flex items-center justify-center text-white text-xs">
                 {user.email.substring(0,2).toUpperCase()}
               </div>
               <div className="flex flex-col min-w-0">
                  <span className="text-sm text-white truncate font-medium">{user.email.split('@')[0]}</span>
                  <span className="text-xs text-slate-400 capitalize">{user.role.replace('_', ' ')}</span>
               </div>
            </div>
            <button onClick={handleLogout} className="text-slate-400 hover:text-white p-1">
               <LogOut className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-hidden">

        {/* Mobile Header */}
        <div className="md:hidden bg-white border-b border-slate-200 p-4 flex items-center justify-between">
            <span className="font-bold text-slate-800">My Recordings</span>
            <Menu className="w-6 h-6 text-slate-600" />
        </div>

        {/* Scrollable Area */}
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
            <div className="max-w-3xl mx-auto space-y-8">

                {/* Introduction for new users */}
                <div className="mb-6">
                    <h1 className="text-2xl font-bold text-slate-900">Board Meeting Recorder</h1>
                    <p className="text-slate-500 mt-1">Record, note, and push directly to ALLi.</p>
                </div>

                {/* Recorder Widget */}
                <Recorder onRecordingComplete={handleRecordingComplete} />

                <div className="border-t border-slate-200 pt-6">
                    <div className="flex items-center justify-between mb-4">
                        <h2 className="text-lg font-semibold text-slate-800">Recent Recordings</h2>
                        <span className="text-xs font-medium bg-slate-100 text-slate-600 px-2 py-1 rounded-full">
                           {recordings.length} Saved
                        </span>
                    </div>

                    <RecordingList 
                        recordings={recordings}
                        currentUser={user}
                        onUpdateRecording={handleUpdateRecording}
                        onShare={handleShare}
                    />
                </div>
            </div>
        </main>
      </div>

    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') {
        // Remove data URL prefix (e.g., "data:audio/webm;base64,")
        const base64 = reader.result.split(',')[1];
        resolve(base64);
      } else {
        reject(new Error('Failed to convert blob to base64'));
      }
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const transcribeAudio = async (audioBlob: Blob): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const base64Data = await blobToBase64(audioBlob);

    // Determine mime type from blob if possible, default to webm
    const mimeType = audioBlob.type || 'audio/webm';

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          {
            text: "Transcribe this board meeting audio."
          }
        ]
      },
      config: {
        systemInstruction: "You are an expert transcriber and minute-taker for HOA board meetings. Your goal is to provide a highly accurate, speaker-diarized transcript.\n\nRules:\n1. Identify different speakers based on voice, tone, and context. Label them clearly (e.g., 'Speaker 1:', 'Speaker 2:', or by name if mentioned).\n2. Format the output as a script with clear line breaks between speakers.\n3. Remove non-essential filler words (um, uh) to keep it professional.\n4. CRITICAL: At the very end, analyze the content for tasks, votes, and decisions. Add a section titled '### ACTION ITEMS' and list them as bullet points. If none, omit this section.",
      }
    });

    return response.text || "No transcription generated.";
  } catch (error) {
    console.error("Transcription failed:", error);
    return "Transcription failed. Please try again later.";
  }
};

import React, { useState, useEffect } from 'react';
import { Play, Pause, Share2, FileText, Clock, Edit2, Check, Download, Loader2, Sparkles, Copy, ChevronDown, ChevronUp, ListChecks, User as UserIcon } from 'lucide-react';
import { Recording, User } from '../types';
import { getAudioBlob } from '../services/dbService';

interface RecordingListProps {
  recordings: Recording[];
  currentUser: User;
  onUpdateRecording: (updated: Recording) => void;
  onShare: (recording: Recording) => void;
}

export const RecordingList: React.FC<RecordingListProps> = ({ 
  recordings, 
  currentUser,
  onUpdateRecording,
  onShare
}) => {
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNote, setEditNote] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  // Track which transcripts are fully expanded
  const [transcriptExpandedIds, setTranscriptExpandedIds] = useState<Set<string>>(new Set());

  // Clean up audio on unmount
  useEffect(() => {
    return () => {
      if (audioEl) {
        audioEl.pause();
        audioEl.src = '';
      }
    };
  }, [audioEl]);

  const handlePlay = async (recording: Recording) => {
    if (playingId === recording.id && audioEl) {
      audioEl.pause();
      setPlayingId(null);
      return;
    }

    if (audioEl) {
      audioEl.pause();
    }

    try {
      const blob = await getAudioBlob(recording.blobId);
      if (!blob) {
        alert("Audio file not found.");
        return;
      }

      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);

      audio.onended = () => setPlayingId(null);
      audio.play();

      setAudioEl(audio);
      setPlayingId(recording.id);
    } catch (e) {
      console.error("Error playing audio", e);
    }
  };

  const handleStartEdit = (rec: Recording) => {
    setEditingId(rec.id);
    setEditTitle(rec.title);
    setEditNote(rec.note);
    setExpandedId(rec.id);
  };

  const handleSaveEdit = (rec: Recording) => {
    onUpdateRecording({
      ...rec,
      title: editTitle,
      note: editNote
    });
    setEditingId(null);
  };

  const handleDownload = async (rec: Recording) => {
      try {
        const blob = await getAudioBlob(rec.blobId);
        if (blob) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.mp3`; 
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
      } catch (e) {
          console.error(e);
      }
  };

  const handleCopyTranscript = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
        setCopiedId(id);
        setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const toggleTranscript = (id: string) => {
    setTranscriptExpandedIds(prev => {
        const next = new Set(prev);
        if (next.has(id)) {
            next.delete(id);
        } else {
            next.add(id);
        }
        return next;
    });
  };

  // Helper to render transcript with speaker labels
  const renderFormattedTranscript = (text: string) => {
      if (!text) return <span className="text-slate-400 italic">Transcript not available.</span>;

      // Split by newlines to handle paragraphs/lines
      const lines = text.split('\n');

      return (
          <div className="space-y-3">
              {lines.map((line, idx) => {
                  const trimmed = line.trim();
                  if (!trimmed) return null;

                  // Detect "Speaker Name:" pattern
                  // We look for a colon in the first 30 chars as a heuristic
                  const colonIndex = trimmed.indexOf(':');
                  if (colonIndex > 0 && colonIndex < 30) {
                      const speaker = trimmed.substring(0, colonIndex).trim().replace(/\*/g, ''); // Remove markdown bold if present
                      const content = trimmed.substring(colonIndex + 1).trim();

                      return (
                          <div key={idx} className="flex flex-col sm:flex-row sm:items-start gap-1 sm:gap-3">
                              <div className="flex-shrink-0 mt-0.5">
                                <span className="inline-flex items-center bg-slate-100 text-slate-600 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider border border-slate-200">
                                    <UserIcon className="w-3 h-3 mr-1 opacity-50" />
                                    {speaker}
                                </span>
                              </div>
                              <p className="text-slate-700 leading-relaxed text-sm flex-1">{content}</p>
                          </div>
                      );
                  }

                  // Default paragraph if no speaker detected
                  return <p key={idx} className="text-slate-700 leading-relaxed text-sm">{trimmed}</p>;
              })}
          </div>
      );
  };

  if (recordings.length === 0) {
    return (
        <div className="text-center py-12 px-4">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileText className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-medium text-slate-900">No recordings yet</h3>
            <p className="text-slate-500 max-w-sm mx-auto mt-2">
                Tap the microphone button above to start recording your board meeting.
            </p>
        </div>
    );
  }

  return (
    <div className="space-y-4">
      {recordings.map((rec) => {
        // Parse Action Items if present
        const parts = rec.transcription ? rec.transcription.split('### ACTION ITEMS') : [];
        const mainTranscript = parts[0] ? parts[0].trim() : '';
        const actionItems = parts[1] ? parts[1].trim() : null;
        const isTranscriptExpanded = transcriptExpandedIds.has(rec.id);

        return (
        <div key={rec.id} className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden transition-all duration-200 hover:shadow-md">
          <div className="p-4">

            {/* Header / Title */}
            <div className="flex items-start justify-between mb-2">
              <div className="flex-1 mr-4">
                {editingId === rec.id ? (
                    <input 
                        type="text" 
                        value={editTitle}
                        onChange={(e) => setEditTitle(e.target.value)}
                        className="w-full text-lg font-semibold text-slate-900 border-b-2 border-fs-primary focus:outline-none bg-transparent"
                        autoFocus
                    />
                ) : (
                    <h3 className="text-lg font-semibold text-slate-900 leading-tight">
                        {rec.title}
                    </h3>
                )}
                <div className="flex items-center text-xs text-slate-500 mt-1 space-x-3">
                    <span className="flex items-center">
                        <Clock className="w-3 h-3 mr-1" />
                        {new Date(rec.timestamp).toLocaleDateString()}
                    </span>
                    <span className="font-mono bg-slate-100 px-1.5 py-0.5 rounded">
                        {Math.floor(rec.duration / 60)}:{String(rec.duration % 60).padStart(2, '0')}
                    </span>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex items-center space-x-1">
                 {editingId === rec.id ? (
                     <button 
                        onClick={() => handleSaveEdit(rec)}
                        className="p-2 text-fs-primary hover:bg-emerald-50 rounded-full"
                    >
                        <Check className="w-5 h-5" />
                     </button>
                 ) : (
                     <button 
                        onClick={() => handleStartEdit(rec)}
                        className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full"
                    >
                        <Edit2 className="w-4 h-4" />
                     </button>
                 )}
              </div>
            </div>

            {/* Notes Section */}
            {(expandedId === rec.id || rec.note) && (
                 <div className="mt-3 bg-slate-50 rounded p-3 text-sm">
                    <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1">Notes</h4>
                    {editingId === rec.id ? (
                        <textarea 
                            value={editNote}
                            onChange={(e) => setEditNote(e.target.value)}
                            placeholder="Add meeting notes, agenda items, or action points..."
                            className="w-full bg-transparent focus:outline-none min-h-[60px] text-slate-700 resize-none"
                        />
                    ) : (
                        <p className="text-slate-600 whitespace-pre-wrap">
                            {rec.note || <span className="text-slate-400 italic">No notes added.</span>}
                        </p>
                    )}
                 </div>
            )}

            {/* AI Insights & Transcription */}
            {(expandedId === rec.id || rec.transcription || rec.isTranscribing) && (
                <div className="mt-4 border-t border-slate-100 pt-3">
                    {/* Action Items Highlight */}
                    {actionItems && (
                        <div className="mb-4 bg-amber-50 border border-amber-200 rounded-md p-3">
                            <div className="flex items-center mb-2">
                                <ListChecks className="w-4 h-4 text-amber-600 mr-2" />
                                <h4 className="text-xs font-bold text-amber-800 uppercase tracking-wide">Action Items</h4>
                            </div>
                            <div className="text-amber-900 text-sm whitespace-pre-wrap pl-6">
                                {actionItems}
                            </div>
                        </div>
                    )}

                    {/* Transcript Header & Toggle */}
                    <div 
                        className="flex items-center justify-between cursor-pointer py-2 hover:bg-slate-50 rounded transition-colors"
                        onClick={() => toggleTranscript(rec.id)}
                    >
                        <div className="flex items-center">
                           <Sparkles className="w-3 h-3 text-purple-500 mr-2" />
                           <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide">Transcript</h4>
                        </div>
                        <div className="flex items-center space-x-2">
                             {rec.transcription && !rec.isTranscribing && isTranscriptExpanded && (
                                <button 
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            handleCopyTranscript(rec.transcription!, rec.id);
                                        }}
                                        className="flex items-center text-xs text-slate-400 hover:text-fs-primary transition-colors mr-2"
                                        title="Copy transcript"
                                >
                                    {copiedId === rec.id ? <Check className="w-3 h-3 mr-1" /> : <Copy className="w-3 h-3 mr-1" />}
                                    {copiedId === rec.id ? 'Copied' : 'Copy'}
                                </button>
                             )}
                             {isTranscriptExpanded ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
                        </div>
                    </div>

                    {/* Collapsible Transcript Body */}
                    {rec.isTranscribing ? (
                        <div className="flex items-center space-x-2 text-slate-500 py-3 px-2 bg-slate-50/50 rounded animate-pulse">
                            <Loader2 className="w-4 h-4 animate-spin" />
                            <span className="text-sm italic">Generating transcript...</span>
                        </div>
                    ) : (
                        isTranscriptExpanded && (
                            <div className="mt-2 bg-white p-2 rounded border border-slate-50">
                                {renderFormattedTranscript(mainTranscript)}
                            </div>
                        )
                    )}
                </div>
            )}

            {/* Expanded Controls for non-editing state */}
            {editingId !== rec.id && (
                <div className="mt-4 flex items-center justify-between border-t border-slate-100 pt-3">
                     <button 
                        onClick={() => handlePlay(rec)}
                        className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                            playingId === rec.id 
                            ? 'bg-slate-900 text-white' 
                            : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                        }`}
                     >
                         {playingId === rec.id ? <Pause className="w-4 h-4 mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                         {playingId === rec.id ? 'Pause' : 'Play'}
                     </button>

                     <div className="flex space-x-2">
                        <button 
                            onClick={() => handleDownload(rec)}
                            className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                            title="Download MP3"
                        >
                            <Download className="w-5 h-5" />
                        </button>
                        <button 
                            onClick={() => onShare(rec)}
                            disabled={rec.status === 'shared'}
                            className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                rec.status === 'shared'
                                ? 'bg-green-100 text-green-700 cursor-default'
                                : 'bg-fs-primary text-white hover:bg-emerald-600 shadow-sm'
                            }`}
                        >
                            {rec.status === 'shared' ? (
                                <>
                                    <Check className="w-4 h-4 mr-2" />
                                    Shared to ALLi
                                </>
                            ) : (
                                <>
                                    <Share2 className="w-4 h-4 mr-2" />
                                    Share to ALLi
                                </>
                            )}
                        </button>
                     </div>
                </div>
            )}

          </div>
        </div>
        );
      })}
    </div>
  );
};

