                         <div className="flex items-center justify-center space-x-6">
                            {/* Discard Button */}
                            <button 
                                onClick={handleDiscard} 
                                disabled={isProcessing}
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
                                title="Discard"
                            >
                                <Trash2 className="w-6 h-6 mb-1" />
                                <span className="text-[10px] font-medium uppercase tracking-wide">Discard</span>
                            </button>

                            {/* Play/Pause Button */}
                            <button 
                                onClick={togglePlay} 
                                className="w-20 h-20 bg-fs-dark text-white rounded-full flex items-center justify-center hover:bg-slate-800 shadow-xl shadow-slate-900/20 transition-transform hover:scale-105"
                            >
                                {isPlaying ? <Pause className="w-8 h-8 fill-current" /> : <Play className="w-8 h-8 fill-current ml-1" />}
                            </button>

                            {/* Save Button */}
                            <button 
                                onClick={handleSave} 
                                disabled={isProcessing} 
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-fs-primary hover:bg-emerald-50 transition-all"
                                title="Save"
                            >
                                {isProcessing ? (
                                    <Loader2 className="w-6 h-6 animate-spin mb-1" />
                                ) : (
                                    <Check className="w-6 h-6 mb-1" />
                                )}
                                <span className="text-[10px] font-medium uppercase tracking-wide">{isProcessing ? 'Saving' : 'Save'}</span>
                            </button>
                         </div>
                    </div>
                )}
            </div>

            {/* Footer Hints */}
            {!isRecording && !isProcessing && !recordedBlob && (
                 <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Ready to capture
                    </p>
                 </div>
            )}

            {recordedBlob && !isProcessing && (
                <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Review before saving
                    </p>
                </div>
            )}
        </div>

        {/* Error Toast */}
        {error && (
            <div className="absolute -bottom-16 left-0 right-0 flex justify-center">
                <div className="bg-red-100 text-red-700 px-4 py-2 rounded-full text-sm font-medium shadow-sm border border-red-200 animate-bounce">
                    {error}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SignalHigh, Play, Pause, Trash2, Check, RotateCcw } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string) => void;
}

export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete }) => {
  // Recording State
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0); // Total duration of recording

  // Preview State
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0); // Current playback time

  // Processing State
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Refs for logic
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Refs for Visualizer
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  const startRecording = async () => {
    setError(null);
    setRecordedBlob(null);
    setAudioUrl(null);
    setCurrentTime(0);
    setDuration(0);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const mimeType = MediaRecorder.isTypeSupported('audio/webm')
        ? 'audio/webm'
        : 'audio/mp4';

      const recorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const url = URL.createObjectURL(blob);
        setRecordedBlob(blob);
        setAudioUrl(url);
        setIsRecording(false);

        // Stop all tracks
        streamRef.current?.getTracks().forEach(track => track.stop());
        streamRef.current = null;

        if (timerIntervalRef.current) {
            clearInterval(timerIntervalRef.current);
            timerIntervalRef.current = null;
        }
      };

      recorder.start();
      setIsRecording(true);

      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => {
        setDuration(Math.floor((Date.now() - startTime) / 1000));
      }, 1000);

    } catch (err) {
      console.error(err);
      setError("Microphone access denied. Please allow permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      // State updates happen in onstop handler
    }
  };

  const handleDiscard = () => {
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    setRecordedBlob(null);
    setAudioUrl(null);
    setDuration(0);
    setCurrentTime(0);
    setIsPlaying(false);
  };

  const handleSave = async () => {
    if (!recordedBlob) return;

    setIsProcessing(true);
    const blobId = `rec_${Date.now()}`;

    try {
        await saveAudioBlob(blobId, recordedBlob);

        const now = new Date();
        const defaultName = `Board Meeting ${now.toLocaleDateString()}`;

        // Cleanup URL before finishing
        if (audioUrl) URL.revokeObjectURL(audioUrl);
        setRecordedBlob(null);
        setAudioUrl(null);

        onRecordingComplete(blobId, duration, defaultName);
    } catch (err) {
        setError("Failed to save recording. Storage might be full.");
        console.error(err);
    } finally {
        setIsProcessing(false);
        setDuration(0);
    }
  };

  // Visualizer Logic
  useEffect(() => {
    if (isRecording && streamRef.current && canvasRef.current) {
        // Initialize AudioContext
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const audioCtx = new AudioContextClass();
        const analyser = audioCtx.createAnalyser();
        const source = audioCtx.createMediaStreamSource(streamRef.current);

        source.connect(analyser);
        analyser.fftSize = 256; 
        analyser.smoothingTimeConstant = 0.5;

        audioContextRef.current = audioCtx;
        analyserRef.current = analyser;

        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Handle High DPI displays
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
        ctx.scale(dpr, dpr);

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        const draw = () => {
            animationFrameRef.current = requestAnimationFrame(draw);
            analyser.getByteFrequencyData(dataArray);

            ctx.clearRect(0, 0, rect.width, rect.height);

            // Configuration for bars
            const bars = 24; // Number of bars to draw
            const gap = 4;
            const totalGapSpace = (bars - 1) * gap;
            const availableWidth = rect.width * 0.8; // Use 80% of width for visual
            const barWidth = (availableWidth - totalGapSpace) / bars;
            const startX = (rect.width - availableWidth) / 2;

            // Step through frequency data
            // We focus on the lower half of the frequency spectrum (0 -> bufferLength/2) for voice
            const step = Math.floor((bufferLength / 2) / bars);

            for (let i = 0; i < bars; i++) {
                let sum = 0;
                for (let j = 0; j < step; j++) {
                    sum += dataArray[(i * step) + j];
                }
                const avg = sum / step;

                // Calculate height relative to canvas height, with a minimum
                // scale factor to make it look responsive
                const barHeight = Math.max(4, (avg / 255) * rect.height * 0.9);

                const x = startX + (i * (barWidth + gap));
                const y = (rect.height - barHeight) / 2; // Center vertically

                ctx.fillStyle = '#ef4444'; // Red-500

                // Draw rounded rectangle
                ctx.beginPath();
                if (typeof ctx.roundRect === 'function') {
                    ctx.roundRect(x, y, barWidth, barHeight, 4);
                } else {
                    ctx.rect(x, y, barWidth, barHeight);
                }
                ctx.fill();
            }
        };

        draw();

        return () => {
            if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
            if (audioCtx.state !== 'closed') audioCtx.close();
        };
    }
  }, [isRecording]);

  // Audio Playback Logic
  useEffect(() => {
    if (audioUrl) {
        const audio = new Audio(audioUrl);
        audioRef.current = audio;

        audio.ontimeupdate = () => {
            setCurrentTime(audio.currentTime);
        };

        audio.onended = () => {
            setIsPlaying(false);
            setCurrentTime(0);
        };

        return () => {
            audio.pause();
            audioRef.current = null;
        };
    }
  }, [audioUrl]);

  const togglePlay = () => {
    if (audioRef.current) {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
      const time = parseFloat(e.target.value);
      if (audioRef.current) {
          audioRef.current.currentTime = time;
          setCurrentTime(time);
      }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (audioUrl) URL.revokeObjectURL(audioUrl);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
    };
  }, []);

  return (
    <div className="w-full relative group">
        {/* Main Card */}
        <div className={`relative w-full max-w-lg mx-auto bg-white rounded-3xl shadow-2xl transition-all duration-500 overflow-hidden border border-slate-100 ${isRecording ? 'shadow-fs-primary/20 scale-[1.02]' : 'shadow-slate-200/50'}`}>

            {/* Header Status Bar */}
            <div className={`absolute top-0 left-0 right-0 h-1.5 transition-colors duration-500 ${isRecording ? 'bg-red-500' : (recordedBlob ? 'bg-fs-primary' : 'bg-transparent')}`} />

            {/* Content Area */}
            <div className="p-8 md:p-12 flex flex-col items-center justify-center min-h-[360px]">

                {!recordedBlob ? (
                    /* RECORDING STATE UI */
                    <>
                        <div className="h-24 w-full flex items-center justify-center mb-6">
                            {isRecording ? (
                                <canvas ref={canvasRef} className="w-full h-full max-w-[300px]" />
                            ) : (
                                <div className="flex flex-col items-center justify-center text-slate-300">
                                    <div className="w-20 h-20 rounded-full border-4 border-slate-100 flex items-center justify-center mb-2">
                                        <SignalHigh className="w-10 h-10" />
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="flex flex-col items-center mb-8">
                            <div className={`text-6xl font-mono font-bold tracking-wider tabular-nums transition-colors duration-300 ${isRecording ? 'text-slate-800' : 'text-slate-300'}`}>
                                {formatTime(duration)}
                            </div>
                            {isRecording && (
                                <div className="flex items-center mt-3 text-red-500 font-medium text-sm animate-pulse">
                                    <div className="w-2 h-2 bg-red-500 rounded-full mr-2" />
                                    Recording in progress
                                </div>
                            )}
                        </div>

                        <div className="relative">
                            {isRecording && (
                                <div className="absolute inset-0 rounded-full border border-red-200 animate-ping opacity-75 scale-150 pointer-events-none" />
                            )}

                            {!isRecording ? (
                                <button 
                                    onClick={startRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-fs-primary hover:bg-emerald-600 text-white shadow-lg hover:shadow-xl hover:shadow-emerald-500/30 transition-all duration-300 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-emerald-100"
                                >
                                    <Mic className="w-10 h-10" />
                                </button>
                            ) : (
                                <button 
                                    onClick={stopRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-white border-4 border-red-500 hover:bg-red-50 text-red-500 shadow-lg transition-all duration-200 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-red-100"
                                >
                                    <Square className="w-8 h-8 fill-current" />
                                </button>
                            )}
                        </div>
                    </>
                ) : (
                    /* PREVIEW STATE UI */
                    <div className="w-full flex flex-col items-center animate-in fade-in duration-300">
                         <h3 className="text-lg font-semibold text-slate-700 mb-6">Preview Recording</h3>

                         {/* Playback Controls */}
                         <div className="w-full max-w-xs mb-8">
                            <div className="flex justify-between text-xs text-slate-500 font-mono mb-2 px-1">
                                <span>{formatTime(currentTime)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>
                            <input 
                                type="range"
                                min="0"
                                max={duration}
                                step="0.1"
                                value={currentTime}
                                onChange={handleSeek}
                                className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-fs-primary focus:outline-none focus:ring-2 focus:ring-fs-primary/30"
                            />
                         </div>

                         <div className="flex items-center justify-center space-x-6">
                            {/* Discard Button */}
                            <button 
                                onClick={handleDiscard} 
                                disabled={isProcessing}
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
                                title="Discard"
                            >
                                <Trash2 className="w-6 h-6 mb-1" />
                                <span className="text-[10px] font-medium uppercase tracking-wide">Discard</span>
                            </button>

                            {/* Play/Pause Button */}
                            <button 
                                onClick={togglePlay} 
                                className="w-20 h-20 bg-fs-dark text-white rounded-full flex items-center justify-center hover:bg-slate-800 shadow-xl shadow-slate-900/20 transition-transform hover:scale-105"
                            >
                                {isPlaying ? <Pause className="w-8 h-8 fill-current" /> : <Play className="w-8 h-8 fill-current ml-1" />}
                            </button>

                            {/* Save Button */}
                            <button 
                                onClick={handleSave} 
                                disabled={isProcessing} 
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-fs-primary hover:bg-emerald-50 transition-all"
                                title="Save"
                            >
                                {isProcessing ? (
                                    <Loader2 className="w-6 h-6 animate-spin mb-1" />
                                ) : (
                                    <Check className="w-6 h-6 mb-1" />
                                )}
                                <span className="text-[10px] font-medium uppercase tracking-wide">{isProcessing ? 'Saving' : 'Save'}</span>
                            </button>
                         </div>
                    </div>
                )}
            </div>

            {/* Footer Hints */}
            {!isRecording && !isProcessing && !recordedBlob && (
                 <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Ready to capture
                    </p>
                 </div>
            )}

            {recordedBlob && !isProcessing && (
                <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Review before saving
                    </p>
                </div>
            )}
        </div>

        {/* Error Toast */}
        {error && (
            <div className="absolute -bottom-16 left-0 right-0 flex justify-center">
                <div className="bg-red-100 text-red-700 px-4 py-2 rounded-full text-sm font-medium shadow-sm border border-red-200 animate-bounce">
                    {error}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Play, Pause, Share2, FileText, Clock, Edit2, Check, Download, Loader2, Sparkles, Copy, ChevronDown, ChevronUp, ListChecks, User as UserIcon, Search, X } from 'lucide-react';
import { Recording, User } from '../types';
import { getAudioBlob } from '../services/dbService';

interface RecordingListProps {
  recordings: Recording[];
  currentUser: User;
  onUpdateRecording: (updated: Recording) => void;
  onShare: (recording: Recording) => void;
}

export const RecordingList: React.FC<RecordingListProps> = ({ 
  recordings, 
  currentUser,
  onUpdateRecording,
  onShare
}) => {
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNote, setEditNote] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Track which transcripts are fully expanded
  const [transcriptExpandedIds, setTranscriptExpandedIds] = useState<Set<string>>(new Set());

  // Clean up audio on unmount
  useEffect(() => {
    return () => {
      if (audioEl) {
        audioEl.pause();
        audioEl.src = '';
      }
    };
  }, [audioEl]);

  const handlePlay = async (recording: Recording) => {
    if (playingId === recording.id && audioEl) {
      audioEl.pause();
      setPlayingId(null);
      return;
    }

    if (audioEl) {
      audioEl.pause();
    }

    try {
      const blob = await getAudioBlob(recording.blobId);
      if (!blob) {
        alert("Audio file not found.");
        return;
      }

      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);

      audio.onended = () => setPlayingId(null);
      audio.play();

      setAudioEl(audio);
      setPlayingId(recording.id);
    } catch (e) {
      console.error("Error playing audio", e);
    }
  };

  const handleStartEdit = (rec: Recording) => {
    setEditingId(rec.id);
    setEditTitle(rec.title);
    setEditNote(rec.note);
    setExpandedId(rec.id);
  };

  const handleSaveEdit = (rec: Recording) => {
    onUpdateRecording({
      ...rec,
      title: editTitle,
      note: editNote
    });
    setEditingId(null);
  };

  const handleDownload = async (rec: Recording) => {
      try {
        const blob = await getAudioBlob(rec.blobId);
        if (blob) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.mp3`; 
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
      } catch (e) {
          console.error(e);
      }
  };

  const handleCopyTranscript = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
        setCopiedId(id);
        setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const toggleTranscript = (id: string) => {
    setTranscriptExpandedIds(prev => {
        const next = new Set(prev);
        if (next.has(id)) {
            next.delete(id);
        } else {
            next.add(id);
        }
        return next;
    });
  };

  // Helper to render transcript with speaker labels
  const renderFormattedTranscript = (text: string) => {
      if (!text) return <span className="text-slate-400 italic">Transcript not available.</span>;

      // Split by newlines to handle paragraphs/lines
      const lines = text.split('\n');

      return (
          <div className="space-y-3">
              {lines.map((line, idx) => {
                  const trimmed = line.trim();
                  if (!trimmed) return null;

                  // Detect "Speaker Name:" pattern
                  // We look for a colon in the first 30 chars as a heuristic
                  const colonIndex = trimmed.indexOf(':');
                  if (colonIndex > 0 && colonIndex < 30) {
                      const speaker = trimmed.substring(0, colonIndex).trim().replace(/\*/g, ''); // Remove markdown bold if present
                      const content = trimmed.substring(colonIndex + 1).trim();

                      return (
                          <div key={idx} className="flex flex-col sm:flex-row sm:items-start gap-1 sm:gap-3">
                              <div className="flex-shrink-0 mt-0.5">
                                <span className="inline-flex items-center bg-slate-100 text-slate-600 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider border border-slate-200">
                                    <UserIcon className="w-3 h-3 mr-1 opacity-50" />
                                    {speaker}
                                </span>
                              </div>
                              <p className="text-slate-700 leading-relaxed text-sm flex-1">{content}</p>
                          </div>
                      );
                  }

                  // Default paragraph if no speaker detected
                  return <p key={idx} className="text-slate-700 leading-relaxed text-sm">{trimmed}</p>;
              })}
          </div>
      );
  };

  if (recordings.length === 0) {
    return (
        <div className="text-center py-12 px-4">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileText className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-medium text-slate-900">No recordings yet</h3>
            <p className="text-slate-500 max-w-sm mx-auto mt-2">
                Tap the microphone button above to start recording your board meeting.
            </p>
        </div>
    );
  }

  const filteredRecordings = recordings.filter(rec => {
      const query = searchQuery.toLowerCase();
      return (
          rec.title.toLowerCase().includes(query) || 
          (rec.note && rec.note.toLowerCase().includes(query))
      );
  });

  return (
    <div className="space-y-6">
      {/* Search Bar */}
      <div className="relative max-w-md">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-slate-400" />
        </div>
        <input 
            type="text"
            placeholder="Search by title or notes..."
            className="block w-full pl-10 pr-10 py-2.5 border border-slate-300 rounded-lg leading-5 bg-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-fs-primary/50 focus:border-fs-primary sm:text-sm transition-shadow shadow-sm"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
        />
        {searchQuery && (
            <button 
                onClick={() => setSearchQuery('')}
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600"
            >
                <X className="h-4 w-4" />
