import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SignalHigh, Play, Pause, Trash2, Check, RotateCcw } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string) => void;
}

export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete }) => {
  // Recording State
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0); // Total duration of recording

  // Preview State
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0); // Current playback time

  // Processing State
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Refs for logic
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Refs for Visualizer
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  const startRecording = async () => {
    setError(null);
    setRecordedBlob(null);
    setAudioUrl(null);
    setCurrentTime(0);
    setDuration(0);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const mimeType = MediaRecorder.isTypeSupported('audio/webm')
        ? 'audio/webm'
        : 'audio/mp4';

      const recorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const url = URL.createObjectURL(blob);
        setRecordedBlob(blob);
        setAudioUrl(url);
        setIsRecording(false);

        // Stop all tracks
        streamRef.current?.getTracks().forEach(track => track.stop());
        streamRef.current = null;

        if (timerIntervalRef.current) {
            clearInterval(timerIntervalRef.current);
            timerIntervalRef.current = null;
        }
      };

      recorder.start();
      setIsRecording(true);

      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => {
        setDuration(Math.floor((Date.now() - startTime) / 1000));
      }, 1000);

    } catch (err) {
      console.error(err);
      setError("Microphone access denied. Please allow permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      // State updates happen in onstop handler
    }
  };

  const handleDiscard = () => {
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    setRecordedBlob(null);
    setAudioUrl(null);
    setDuration(0);
    setCurrentTime(0);
    setIsPlaying(false);
  };

  const handleSave = async () => {
    if (!recordedBlob) return;

    setIsProcessing(true);
    const blobId = `rec_${Date.now()}`;

    try {
        await saveAudioBlob(blobId, recordedBlob);

        const now = new Date();
        const defaultName = `Board Meeting ${now.toLocaleDateString()}`;

        // Cleanup URL before finishing
        if (audioUrl) URL.revokeObjectURL(audioUrl);
        setRecordedBlob(null);
        setAudioUrl(null);

        onRecordingComplete(blobId, duration, defaultName);
    } catch (err) {
        setError("Failed to save recording. Storage might be full.");
        console.error(err);
    } finally {
        setIsProcessing(false);
        setDuration(0);
    }
  };

  // Visualizer Logic
  useEffect(() => {
    if (isRecording && streamRef.current && canvasRef.current) {
        // Initialize AudioContext
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const audioCtx = new AudioContextClass();
        const analyser = audioCtx.createAnalyser();
        const source = audioCtx.createMediaStreamSource(streamRef.current);

        source.connect(analyser);
        analyser.fftSize = 256; 
        analyser.smoothingTimeConstant = 0.5;

        audioContextRef.current = audioCtx;
        analyserRef.current = analyser;

        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Handle High DPI displays
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
        ctx.scale(dpr, dpr);

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        const draw = () => {
            animationFrameRef.current = requestAnimationFrame(draw);
            analyser.getByteFrequencyData(dataArray);

            ctx.clearRect(0, 0, rect.width, rect.height);

            // Configuration for bars
            const bars = 24; // Number of bars to draw
            const gap = 4;
            const totalGapSpace = (bars - 1) * gap;
            const availableWidth = rect.width * 0.8; // Use 80% of width for visual
            const barWidth = (availableWidth - totalGapSpace) / bars;
            const startX = (rect.width - availableWidth) / 2;

            // Step through frequency data
            // We focus on the lower half of the frequency spectrum (0 -> bufferLength/2) for voice
            const step = Math.floor((bufferLength / 2) / bars);

            for (let i = 0; i < bars; i++) {
                let sum = 0;
                for (let j = 0; j < step; j++) {
                    sum += dataArray[(i * step) + j];
                }
                const avg = sum / step;

                // Calculate height relative to canvas height, with a minimum
                // scale factor to make it look responsive
                const barHeight = Math.max(4, (avg / 255) * rect.height * 0.9);

                const x = startX + (i * (barWidth + gap));
                const y = (rect.height - barHeight) / 2; // Center vertically

                ctx.fillStyle = '#ef4444'; // Red-500

                // Draw rounded rectangle
                ctx.beginPath();
                if (typeof ctx.roundRect === 'function') {
                    ctx.roundRect(x, y, barWidth, barHeight, 4);
                } else {
                    ctx.rect(x, y, barWidth, barHeight);
                }
                ctx.fill();
            }
        };

        draw();

        return () => {
            if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
            if (audioCtx.state !== 'closed') audioCtx.close();
        };
    }
  }, [isRecording]);

  // Audio Playback Logic
  useEffect(() => {
    if (audioUrl) {
        const audio = new Audio(audioUrl);
        audioRef.current = audio;

        // Update duration when metadata loads for precise seek bar
        audio.onloadedmetadata = () => {
            if (audio.duration && !isNaN(audio.duration) && audio.duration !== Infinity) {
                setDuration(audio.duration);
            }
        };

        audio.ontimeupdate = () => {
            setCurrentTime(audio.currentTime);
        };

        audio.onended = () => {
            setIsPlaying(false);
            setCurrentTime(0);
        };

        return () => {
            audio.pause();
            audioRef.current = null;
        };
    }
  }, [audioUrl]);

  const togglePlay = () => {
    if (audioRef.current) {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
      const time = parseFloat(e.target.value);
      if (audioRef.current) {
          audioRef.current.currentTime = time;
          setCurrentTime(time);
      }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (audioUrl) URL.revokeObjectURL(audioUrl);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
    };
  }, []);

  return (
    <div className="w-full relative group">
        {/* Main Card */}
        <div className={`relative w-full max-w-lg mx-auto bg-white rounded-3xl shadow-2xl transition-all duration-500 overflow-hidden border border-slate-100 ${isRecording ? 'shadow-fs-primary/20 scale-[1.02]' : 'shadow-slate-200/50'}`}>

            {/* Header Status Bar */}
            <div className={`absolute top-0 left-0 right-0 h-1.5 transition-colors duration-500 ${isRecording ? 'bg-red-500' : (recordedBlob ? 'bg-fs-primary' : 'bg-transparent')}`} />

            {/* Content Area */}
            <div className="p-8 md:p-12 flex flex-col items-center justify-center min-h-[360px]">

                {!recordedBlob ? (
                    /* RECORDING STATE UI */
                    <>
                        <div className="h-24 w-full flex items-center justify-center mb-6">
                            {isRecording ? (
                                <canvas ref={canvasRef} className="w-full h-full max-w-[300px]" />
                            ) : (
                                <div className="flex flex-col items-center justify-center text-slate-300">
                                    <div className="w-20 h-20 rounded-full border-4 border-slate-100 flex items-center justify-center mb-2">
                                        <SignalHigh className="w-10 h-10" />
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="flex flex-col items-center mb-8">
                            <div className={`text-6xl font-mono font-bold tracking-wider tabular-nums transition-colors duration-300 ${isRecording ? 'text-slate-800' : 'text-slate-300'}`}>
                                {formatTime(duration)}
                            </div>
                            {isRecording && (
                                <div className="flex items-center mt-3 text-red-500 font-medium text-sm animate-pulse">
                                    <div className="w-2 h-2 bg-red-500 rounded-full mr-2" />
                                    Recording in progress
                                </div>
                            )}
                        </div>

                        <div className="relative">
                            {isRecording && (
                                <div className="absolute inset-0 rounded-full border border-red-200 animate-ping opacity-75 scale-150 pointer-events-none" />
                            )}

                            {!isRecording ? (
                                <button 
                                    onClick={startRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-fs-primary hover:bg-emerald-600 text-white shadow-lg hover:shadow-xl hover:shadow-emerald-500/30 transition-all duration-300 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-emerald-100"
                                >
                                    <Mic className="w-10 h-10" />
                                </button>
                            ) : (
                                <button 
                                    onClick={stopRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-white border-4 border-red-500 hover:bg-red-50 text-red-500 shadow-lg transition-all duration-200 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-red-100"
                                >
                                    <Square className="w-8 h-8 fill-current" />
                                </button>
                            )}
                        </div>
                    </>
                ) : (
                    /* PREVIEW STATE UI */
                    <div className="w-full flex flex-col items-center animate-in fade-in duration-300">
                         <h3 className="text-lg font-semibold text-slate-700 mb-6">Preview Recording</h3>

                         {/* Playback Controls */}
                         <div className="w-full max-w-xs mb-8">
                            <div className="flex justify-between text-xs text-slate-500 font-mono mb-2 px-1">
                                <span>{formatTime(currentTime)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>
                            <input 
                                type="range"
                                min="0"
                                max={duration}
                                step="0.1"
                                value={currentTime}
                                onChange={handleSeek}
                                className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-fs-primary focus:outline-none focus:ring-2 focus:ring-fs-primary/30"
                            />
                         </div>

                         <div className="flex items-center justify-center space-x-6">
                            {/* Discard Button */}
                            <button 
                                onClick={handleDiscard} 
                                disabled={isProcessing}
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
                                title="Discard"
                            >
                                <Trash2 className="w-6 h-6 mb-1" />
                                <span className="text-[10px] font-medium uppercase tracking-wide">Discard</span>
                            </button>

                            {/* Play/Pause Button */}
                            <button 
                                onClick={togglePlay} 
                                className="w-20 h-20 bg-fs-dark text-white rounded-full flex items-center justify-center hover:bg-slate-800 shadow-xl shadow-slate-900/20 transition-transform hover:scale-105"
                            >
                                {isPlaying ? <Pause className="w-8 h-8 fill-current" /> : <Play className="w-8 h-8 fill-current ml-1" />}
                            </button>

                            {/* Save Button */}
                            <button 
                                onClick={handleSave} 
                                disabled={isProcessing} 
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-fs-primary hover:bg-emerald-50 transition-all"
                                title="Save"
                            >
                                {isProcessing ? (
                                    <Loader2 className="w-6 h-6 animate-spin mb-1" />
                                ) : (
                                    <Check className="w-6 h-6 mb-1" />
                                )}
                                <span className="text-[10px] font-medium uppercase tracking-wide">{isProcessing ? 'Saving' : 'Save'}</span>
                            </button>
                         </div>
                    </div>
                )}
            </div>

            {/* Footer Hints */}
            {!isRecording && !isProcessing && !recordedBlob && (
                 <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Ready to capture
                    </p>
                 </div>
            )}

            {recordedBlob && !isProcessing && (
                <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Review before saving
                    </p>
                 </div>
            )}
        </div>

        {/* Error Toast */}
        {error && (
            <div className="absolute -bottom-16 left-0 right-0 flex justify-center">
                <div className="bg-red-100 text-red-700 px-4 py-2 rounded-full text-sm font-medium shadow-sm border border-red-200 animate-bounce">
                    {error}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Play, Pause, Share2, FileText, Clock, Edit2, Check, Download, Loader2, Sparkles, Copy, ChevronDown, ChevronUp, ListChecks, Search, X, FileDown } from 'lucide-react';
import { Recording, User } from '../types';
import { getAudioBlob } from '../services/dbService';

interface RecordingListProps {
  recordings: Recording[];
  currentUser: User | null;
  onUpdateRecording: (updated: Recording) => void;
  onShare: (recording: Recording) => void;
}

// Helper: Generate consistent colors for speakers based on name hash
const getSpeakerColor = (name: string) => {
  const colors = [
    'bg-blue-100 text-blue-700 border-blue-200',
    'bg-emerald-100 text-emerald-700 border-emerald-200',
    'bg-amber-100 text-amber-700 border-amber-200',
    'bg-purple-100 text-purple-700 border-purple-200',
    'bg-pink-100 text-pink-700 border-pink-200',
    'bg-indigo-100 text-indigo-700 border-indigo-200',
    'bg-cyan-100 text-cyan-700 border-cyan-200',
    'bg-rose-100 text-rose-700 border-rose-200',
  ];
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return colors[Math.abs(hash) % colors.length];
};

// Helper: Simple Markdown Parser for Bold and Italics
const parseMarkdown = (text: string) => {
  // Split by bold (**...**)
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return parts.map((part, i) => {
    if (part.startsWith('**') && part.endsWith('**')) {
      return <strong key={i} className="font-bold text-slate-900">{part.slice(2, -2)}</strong>;
    }
    // Split by italic (*...*) inside non-bold parts
    const subParts = part.split(/(\*.*?\*)/g);
    return subParts.map((subPart, j) => {
       if (subPart.startsWith('*') && subPart.endsWith('*') && subPart.length > 2) {
         return <em key={`${i}-${j}`} className="italic text-slate-800">{subPart.slice(1, -1)}</em>;
       }
       return subPart;
    });
  });
};

export const RecordingList: React.FC<RecordingListProps> = ({ 
  recordings, 
  currentUser,
  onUpdateRecording,
  onShare
}) => {
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNote, setEditNote] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Track which transcripts are fully expanded
  const [transcriptExpandedIds, setTranscriptExpandedIds] = useState<Set<string>>(new Set());

  // Clean up audio on unmount
  useEffect(() => {
    return () => {
      if (audioEl) {
        audioEl.pause();
        audioEl.src = '';
      }
    };
  }, [audioEl]);

  const handlePlay = async (recording: Recording) => {
    if (playingId === recording.id && audioEl) {
      audioEl.pause();
      setPlayingId(null);
      return;
    }

    if (audioEl) {
      audioEl.pause();
    }

    try {
      const blob = await getAudioBlob(recording.blobId);
      if (!blob) {
        alert("Audio file not found.");
        return;
      }

      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);

      audio.onended = () => setPlayingId(null);
      audio.play();

      setAudioEl(audio);
      setPlayingId(recording.id);
    } catch (e) {
      console.error("Error playing audio", e);
    }
  };

  const handleStartEdit = (rec: Recording) => {
    setEditingId(rec.id);
    setEditTitle(rec.title);
    setEditNote(rec.note);
    setExpandedId(rec.id);
  };

  const handleSaveEdit = (rec: Recording) => {
    onUpdateRecording({
      ...rec,
      title: editTitle,
      note: editNote
    });
    setEditingId(null);
  };

  const handleDownload = async (rec: Recording) => {
      try {
        const blob = await getAudioBlob(rec.blobId);
        if (blob) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.mp3`; 
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
      } catch (e) {
          console.error(e);
      }
  };

  const handleExportReport = (rec: Recording) => {
    const date = new Date(rec.timestamp).toLocaleDateString();
    const time = new Date(rec.timestamp).toLocaleTimeString();
    const duration = `${Math.floor(rec.duration / 60)} minutes ${rec.duration % 60} seconds`;

    let content = `FRONTSTEPS NOTE TAKER REPORT\n`;
    content += `==================================================\n`;
    content += `Title:    ${rec.title}\n`;
    content += `Date:     ${date} at ${time}\n`;
    content += `Duration: ${duration}\n`;
    content += `==================================================\n\n`;

    if (rec.note) {
        content += `NOTES\n`;
        content += `-----\n`;
        content += `${rec.note}\n\n`;
    }

    if (rec.transcription) {
        content += `TRANSCRIPT & AI INSIGHTS\n`;
        content += `------------------------\n`;
        content += `${rec.transcription}\n`;
    } else {
         content += `(No transcript available)\n`;
    }

    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_report.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCopyTranscript = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
        setCopiedId(id);
        setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const toggleTranscript = (id: string) => {
    setTranscriptExpandedIds(prev => {
        const next = new Set(prev);
        if (next.has(id)) {
            next.delete(id);
        } else {
            next.add(id);
        }
        return next;
    });
  };

  // Helper to render transcript with speaker labels and markdown
  const renderFormattedTranscript = (text: string) => {
      if (!text) return <span className="text-slate-400 italic">Transcript not available.</span>;

      // Split by newlines to handle paragraphs/lines
      const lines = text.split('\n');

      return (
          <div className="space-y-6">
              {lines.map((line, idx) => {
                  const trimmed = line.trim();
                  if (!trimmed) return null;

                  // Detect "Speaker Name:" pattern
                  // Matches "**Speaker Name:** Content" or "Speaker Name: Content"
                  // We look for a colon in the first 40 chars as a heuristic
                  const colonIndex = trimmed.indexOf(':');

                  if (colonIndex > 0 && colonIndex < 40) {
                      const rawSpeaker = trimmed.substring(0, colonIndex);
                      // Clean up markdown chars from speaker name (e.g. **Speaker**)
                      const speakerName = rawSpeaker.replace(/[\*\_]/g, '').trim();
                      const content = trimmed.substring(colonIndex + 1).trim();

                      // Generate initials
                      const initials = speakerName.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
                      const colorClass = getSpeakerColor(speakerName);

                      return (
                          <div key={idx} className="flex flex-row items-start gap-3 group">
                              <div className={`flex-shrink-0 mt-1 w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold border ${colorClass} shadow-sm select-none`}>
                                  {initials}
                              </div>
                              <div className="flex-1 min-w-0">
                                  <span className={`inline-block mb-1.5 px-2.5 py-0.5 rounded-md text-[11px] font-bold uppercase tracking-wider border ${colorClass}`}>
                                      {speakerName}
                                  </span>
                                  <p className="text-slate-700 leading-relaxed text-sm">
                                      {parseMarkdown(content)}
                                  </p>
                              </div>
                          </div>
                      );
                  }

                  // Default paragraph if no speaker detected
                  // Indent slightly to align better with text in speaker blocks
                  return (
                      <p key={idx} className="text-slate-700 leading-relaxed text-sm pl-0 sm:pl-12">
                          {parseMarkdown(trimmed)}
                      </p>
                  );
              })}
          </div>
      );
  };

  if (recordings.length === 0) {
    return (
        <div className="text-center py-12 px-4">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileText className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-medium text-slate-900">No recordings yet</h3>
            <p className="text-slate-500 max-w-sm mx-auto mt-2">
                Tap the microphone button above to start recording your board meeting.
            </p>
        </div>
    );
  }

  const filteredRecordings = recordings.filter(rec => {
      const query = searchQuery.toLowerCase();
      return (
          rec.title.toLowerCase().includes(query) || 
          (rec.note && rec.note.toLowerCase().includes(query))
      );
  });

  return (
    <div className="space-y-6">
      {/* Search Bar */}
      <div className="relative max-w-md">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-slate-400" />
        </div>
        <input 
            type="text"
            placeholder="Search by title or notes..."
            className="block w-full pl-10 pr-10 py-2.5 border border-slate-300 rounded-lg leading-5 bg-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-fs-primary/50 focus:border-fs-primary sm:text-sm transition-shadow shadow-sm"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
        />
        {searchQuery && (
            <button 
                onClick={() => setSearchQuery('')}
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600"
            >
                <X className="h-4 w-4" />
            </button>
        )}
      </div>

      {filteredRecordings.length === 0 ? (
          <div className="text-center py-12 bg-white rounded-lg border border-dashed border-slate-300">
              <Search className="w-8 h-8 mx-auto mb-2 text-slate-300" />
              <p className="text-slate-500 text-sm">No recordings found for "{searchQuery}"</p>
              <button 
                onClick={() => setSearchQuery('')}
                className="mt-2 text-fs-primary text-sm font-medium hover:underline"
              >
                  Clear search
              </button>
          </div>
      ) : (
          <div className="space-y-4">
            {filteredRecordings.map((rec) => {
                // Parse Action Items if present
                const parts = rec.transcription ? rec.transcription.split('### ACTION ITEMS') : [];
                const mainTranscript = parts[0] ? parts[0].trim() : '';
                const actionItems = parts[1] ? parts[1].trim() : null;
                const isTranscriptExpanded = transcriptExpandedIds.has(rec.id);

                return (
                <div key={rec.id} className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden transition-all duration-200 hover:shadow-md">
                <div className="p-4">

                    {/* Header / Title */}
                    <div className="flex items-start justify-between mb-2">
                    <div className="flex-1 mr-4">
                        {editingId === rec.id ? (
                            <input 
                                type="text" 
                                value={editTitle}
                                onChange={(e) => setEditTitle(e.target.value)}
                                className="w-full text-lg font-semibold text-slate-900 border-b-2 border-fs-primary focus:outline-none bg-transparent"
                                autoFocus
                            />
                        ) : (
                            <h3 className="text-lg font-semibold text-slate-900 leading-tight">
                                {rec.title}
                            </h3>
                        )}
                        <div className="flex items-center text-xs text-slate-500 mt-1 space-x-3">
                            <span className="flex items-center">
                                <Clock className="w-3 h-3 mr-1" />
                                {new Date(rec.timestamp).toLocaleDateString()}
                            </span>
                            <span className="font-mono bg-slate-100 px-1.5 py-0.5 rounded">
                                {Math.floor(rec.duration / 60)}:{String(rec.duration % 60).padStart(2, '0')}
                            </span>
                        </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex items-center space-x-1">
                        {editingId === rec.id ? (
                            <button 
                                onClick={() => handleSaveEdit(rec)}
                                className="p-2 text-fs-primary hover:bg-emerald-50 rounded-full"
                            >
                                <Check className="w-5 h-5" />
                            </button>
                        ) : (
                            <button 
                                onClick={() => handleStartEdit(rec)}
                                className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full"
                            >
                                <Edit2 className="w-4 h-4" />
                            </button>
                        )}
                    </div>
                    </div>

                    {/* Notes Section */}
                    {(expandedId === rec.id || rec.note) && (
                        <div className="mt-3 bg-slate-50 rounded p-3 text-sm">
                            <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1">Notes</h4>
                            {editingId === rec.id ? (
                                <textarea 
                                    value={editNote}
                                    onChange={(e) => setEditNote(e.target.value)}
                                    placeholder="Add meeting notes, agenda items, or action points..."
                                    className="w-full bg-transparent focus:outline-none min-h-[60px] text-slate-700 resize-none"
                                />
                            ) : (
                                <p className="text-slate-600 whitespace-pre-wrap">
                                    {rec.note || <span className="text-slate-400 italic">No notes added.</span>}
                                </p>
                            )}
                        </div>
                    )}

                    {/* AI Insights & Transcription */}
                    {(expandedId === rec.id || rec.transcription || rec.isTranscribing) && (
                        <div className="mt-4 border-t border-slate-100 pt-3">
                            {/* Action Items Highlight */}
                            {actionItems && (
                                <div className="mb-4 bg-amber-50 border border-amber-200 rounded-md p-3">
                                    <div className="flex items-center mb-2">
                                        <ListChecks className="w-4 h-4 text-amber-600 mr-2" />
                                        <h4 className="text-xs font-bold text-amber-800 uppercase tracking-wide">Action Items</h4>
                                    </div>
                                    <div className="text-amber-900 text-sm whitespace-pre-wrap pl-6">
                                        {actionItems}
                                    </div>
                                </div>
                            )}

                            {/* Transcript Header & Toggle */}
                            <div 
                                className="flex items-center justify-between cursor-pointer py-2 hover:bg-slate-50 rounded transition-colors"
                                onClick={() => toggleTranscript(rec.id)}
                            >
                                <div className="flex items-center">
                                <Sparkles className="w-3 h-3 text-purple-500 mr-2" />
                                <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide">Transcript</h4>
                                </div>
                                <div className="flex items-center space-x-2">
                                    {rec.transcription && !rec.isTranscribing && isTranscriptExpanded && (
                                        <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleCopyTranscript(rec.transcription!, rec.id);
                                                }}
                                                className="flex items-center text-xs text-slate-400 hover:text-fs-primary transition-colors mr-2"
                                                title="Copy transcript"
                                        >
                                            {copiedId === rec.id ? <Check className="w-3 h-3 mr-1" /> : <Copy className="w-3 h-3 mr-1" />}
                                            {copiedId === rec.id ? 'Copied' : 'Copy'}
                                        </button>
                                    )}
                                    {isTranscriptExpanded ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
                                </div>
                            </div>

                            {/* Collapsible Transcript Body */}
                            {rec.isTranscribing ? (
                                <div className="flex items-center space-x-2 text-slate-500 py-3 px-2 bg-slate-50/50 rounded animate-pulse">
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                    <span className="text-sm italic">Generating transcript...</span>
                                </div>
                            ) : (
                                isTranscriptExpanded && (
                                    <div className="mt-2 bg-white p-3 sm:p-4 rounded-lg border border-slate-100 shadow-inner bg-slate-50/30">
                                        {renderFormattedTranscript(mainTranscript)}
                                    </div>
                                )
                            )}
                        </div>
                    )}

                    {/* Expanded Controls for non-editing state */}
                    {editingId !== rec.id && (
                        <div className="mt-4 flex items-center justify-between border-t border-slate-100 pt-3">
                            <button 
                                onClick={() => handlePlay(rec)}
                                className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                    playingId === rec.id 
                                    ? 'bg-slate-900 text-white' 
                                    : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                                }`}
                            >
                                {playingId === rec.id ? <Pause className="w-4 h-4 mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                                {playingId === rec.id ? 'Pause' : 'Play'}
                            </button>

                            <div className="flex space-x-2">
                                <button 
                                    onClick={() => handleDownload(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                                    title="Download MP3"
                                >
                                    <Download className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => handleExportReport(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                                    title="Export Transcript & Notes"
                                >
                                    <FileDown className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => onShare(rec)}
                                    disabled={rec.status === 'shared'}
                                    className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                        rec.status === 'shared'
                                        ? 'bg-green-100 text-green-700 cursor-default'
                                        : 'bg-fs-primary text-white hover:bg-emerald-600 shadow-sm'
                                    }`}
                                >
                                    {rec.status === 'shared' ? (
                                        <>
                                            <Check className="w-4 h-4 mr-2" />
                                            Shared to ALLi
                                        </>
                                    ) : (
                                        <>
                                            <Share2 className="w-4 h-4 mr-2" />
                                            Share to ALLi
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>
                    )}

                </div>
                </div>
                );
            })}
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { Mail, ArrowRight, Loader2, ShieldCheck, X } from 'lucide-react';

interface AuthScreenProps {
  onLogin: (user: User) => void;
  onCancel: () => void;
}

export const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin, onCancel }) => {
  const [step, setStep] = useState<'email' | 'code'>('email');
  const [email, setEmail] = useState('');
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [selectedRole, setSelectedRole] = useState<UserRole>(UserRole.BOARD_MEMBER);

  const handleSendCode = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;
    setLoading(true);
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1500));
    setLoading(false);
    setStep('code');
  };

  const handleVerifyCode = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!code) return;
    setLoading(true);
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Create mock user session
    const user: User = {
        email,
        role: selectedRole,
        isAuthenticated: true
    };

    setLoading(false);
    onLogin(user);
  };

  return (
    <div className="fixed inset-0 z-50 min-h-screen bg-fs-dark/95 backdrop-blur-sm flex flex-col items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-2xl overflow-hidden relative">

        {/* Close Button */}
        <button 
          onClick={onCancel}
          className="absolute top-4 right-4 p-2 text-slate-400 hover:text-white hover:bg-slate-800/50 rounded-full transition-colors z-10"
          title="Cancel login"
        >
          <X className="w-5 h-5" />
        </button>

        {/* Header */}
        <div className="bg-fs-darker p-8 text-center border-b border-slate-800">
             <div className="flex justify-center mb-4">
                 {/* Logo Placeholder */}
                 <div className="flex items-center space-x-2">
                    <span className="text-2xl font-bold text-white tracking-tight">FRONTST<span className="text-fs-primary">Ξ</span>PS</span>
                 </div>
             </div>
             <h2 className="text-xl font-semibold text-white">Note Taker</h2>
             <p className="text-slate-400 text-sm mt-2">Secure recording companion for ALLi</p>
        </div>

        <div className="p-8">
            {step === 'email' ? (
                <form onSubmit={handleSendCode} className="space-y-6">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-2">Login as</label>
                        <div className="grid grid-cols-2 gap-3">
                            <button
                                type="button"
                                onClick={() => setSelectedRole(UserRole.BOARD_MEMBER)}
                                className={`py-2 px-3 text-sm font-medium rounded-md border transition-all ${
                                    selectedRole === UserRole.BOARD_MEMBER 
                                    ? 'bg-fs-dark text-white border-fs-dark' 
                                    : 'bg-white text-slate-600 border-slate-200 hover:border-slate-300'
                                }`}
                            >
                                Board Member
                            </button>
                            <button
                                type="button"
                                onClick={() => setSelectedRole(UserRole.MANAGER)}
                                className={`py-2 px-3 text-sm font-medium rounded-md border transition-all ${
                                    selectedRole === UserRole.MANAGER 
                                    ? 'bg-fs-dark text-white border-fs-dark' 
                                    : 'bg-white text-slate-600 border-slate-200 hover:border-slate-300'
                                }`}
                            >
                                Manager
                            </button>
                        </div>
                    </div>

                    <div>
                        <label htmlFor="email" className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <Mail className="h-5 w-5 text-slate-400" />
                            </div>
                            <input
                                id="email"
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                className="block w-full pl-10 pr-3 py-3 border border-slate-300 rounded-lg focus:ring-fs-primary focus:border-fs-primary text-sm"
                                placeholder="name@community.com"
                                required
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex justify-center items-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <>Continue <ArrowRight className="ml-2 w-4 h-4" /></>}
                    </button>

                    <p className="text-xs text-center text-slate-400">
                        Powered by WorkOS Passwordless Auth
                    </p>
                </form>
            ) : (
                <form onSubmit={handleVerifyCode} className="space-y-6">
                    <div className="text-center mb-6">
                        <div className="bg-green-50 w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-3">
                            <Mail className="w-6 h-6 text-green-600" />
                        </div>
                        <h3 className="text-lg font-medium text-slate-900">Check your email</h3>
                        <p className="text-sm text-slate-500 mt-1">We sent a verification code to <span className="font-medium text-slate-800">{email}</span></p>
                    </div>

                    <div>
                        <label htmlFor="code" className="block text-sm font-medium text-slate-700 mb-1">Verification Code</label>
                        <input
                            id="code"
                            type="text"
                            value={code}
                            onChange={(e) => setCode(e.target.value)}
                            className="block w-full text-center tracking-[0.5em] text-2xl font-mono py-3 border border-slate-300 rounded-lg focus:ring-fs-primary focus:border-fs-primary"
                            placeholder="123456"
                            maxLength={6}
                            required
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex justify-center items-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-fs-primary hover:bg-emerald-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <><ShieldCheck className="mr-2 w-4 h-4" /> Verify & Login</>}
                    </button>

                    <button 
                        type="button"
                        onClick={() => setStep('email')}
                        className="w-full text-sm text-slate-500 hover:text-slate-800"
                    >
                        Back to email
                    </button>
                </form>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Recording, UserRole } from './types';
import { getRecordingsMeta, saveRecordingsMeta, getUserSession, saveUserSession, clearUserSession } from './services/storageService';
import { AuthScreen } from './components/AuthScreen';
import { Recorder } from './components/Recorder';
import { RecordingList } from './components/RecordingList';
import { LogOut, LayoutGrid, Menu, Mic, List, History, UserCircle2, LogIn } from 'lucide-react';
import { transcribeAudio } from './services/aiService';
import { getAudioBlob } from './services/dbService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [recordings, setRecordings] = useState<Recording[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [currentView, setCurrentView] = useState<'record' | 'history'>('record');
  const [showAuth, setShowAuth] = useState(false);
  const [pendingShareRecording, setPendingShareRecording] = useState<Recording | null>(null);

  // Initialize app
  useEffect(() => {
    const session = getUserSession();
    if (session) {
      setUser(session);
    }
    const savedRecs = getRecordingsMeta();
    setRecordings(savedRecs);
    setIsLoading(false);
  }, []);

  // Persist recordings when changed
  useEffect(() => {
    if (!isLoading) {
      saveRecordingsMeta(recordings);
    }
  }, [recordings, isLoading]);

  // Handle pending share action after successful login
  useEffect(() => {
    if (user && pendingShareRecording) {
      performShare(pendingShareRecording);
      setPendingShareRecording(null);
    }
  }, [user]);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    saveUserSession(newUser);
    setShowAuth(false);
  };

  const handleLogout = () => {
    setUser(null);
    clearUserSession();
  };

  const handleRecordingComplete = async (blobId: string, duration: number, defaultName: string) => {
    const newRecording: Recording = {
      id: crypto.randomUUID(),
      title: defaultName,
      timestamp: new Date().toISOString(),
      duration: duration,
      note: '',
      blobId: blobId,
      status: 'ready',
      isTranscribing: true,
    };

    // Optimistically switch to history to show progress
    setRecordings(prev => [newRecording, ...prev]);
    setCurrentView('history');

    try {
      const blob = await getAudioBlob(blobId);
      if (blob) {
        const transcription = await transcribeAudio(blob);
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, transcription, isTranscribing: false } 
            : rec
        ));
      } else {
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, isTranscribing: false } 
            : rec
        ));
      }
    } catch (error) {
      console.error('Transcription failed', error);
      setRecordings(prev => prev.map(rec => 
        rec.id === newRecording.id 
          ? { ...rec, isTranscribing: false } 
          : rec
      ));
    }
  };

  const handleUpdateRecording = (updated: Recording) => {
    setRecordings(prev => prev.map(r => r.id === updated.id ? updated : r));
  };

  const performShare = (rec: Recording) => {
    // Mock API Push to ALLi
    const confirmShare = window.confirm(`Push "${rec.title}" to ALLi? This will make it available to the board.`);
    if (!confirmShare) return;

    // Optimistic update
    handleUpdateRecording({ ...rec, status: 'shared' });

    // Mock redirection based on Role
    setTimeout(() => {
      if (user?.role === UserRole.BOARD_MEMBER) {
        // Deep link simulation
        alert("Redirecting to FRONTSTEPS Community App...");
      } else if (user?.role === UserRole.MANAGER) {
        window.open('https://suite.frontsteps.com/#/steps/overview', '_blank');
      } else {
        // Fallback for edge cases
        alert("Shared to ALLi successfully.");
      }
    }, 1000);
  };

  const handleShareClick = (rec: Recording) => {
    if (!user) {
      setPendingShareRecording(rec);
      setShowAuth(true);
      return;
    }
    performShare(rec);
  };

  if (isLoading) return null;

  return (
    <div className="h-screen bg-slate-50 flex flex-col md:flex-row overflow-hidden relative">

      {/* Auth Modal */}
      {showAuth && (
        <AuthScreen 
            onLogin={handleLogin} 
            onCancel={() => {
                setShowAuth(false);
                setPendingShareRecording(null);
            }} 
        />
      )}

      {/* Sidebar (Desktop) */}
      <div className="hidden md:flex md:w-64 bg-fs-dark flex-shrink-0 flex-col justify-between shadow-xl z-10">
        <div className="p-6">
           <div className="flex items-center space-x-2 mb-8">
               <div className="h-8 w-8 bg-fs-primary rounded-md flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-fs-primary/30">N</div>
               <span className="text-xl font-bold text-white tracking-tight">FRONTSTEPS</span>
           </div>

           <nav className="space-y-2">
              <button 
                onClick={() => setCurrentView('record')}
                className={`w-full flex items-center space-x-3 px-3 py-3 rounded-lg transition-all duration-200 ${
                    currentView === 'record' 
                    ? 'bg-slate-800 text-white shadow-md border-l-4 border-fs-primary' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                }`}
              >
                 <Mic className={`w-5 h-5 ${currentView === 'record' ? 'text-fs-primary' : ''}`} />
                 <span className="text-sm font-medium">Record</span>
              </button>

              <button 
                onClick={() => setCurrentView('history')}
                className={`w-full flex items-center space-x-3 px-3 py-3 rounded-lg transition-all duration-200 ${
                    currentView === 'history' 
                    ? 'bg-slate-800 text-white shadow-md border-l-4 border-fs-primary' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                }`}
              >
                 <History className={`w-5 h-5 ${currentView === 'history' ? 'text-fs-primary' : ''}`} />
                 <span className="text-sm font-medium">History</span>
                 {recordings.length > 0 && (
                    <span className="ml-auto text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded-full">
                        {recordings.length}
                    </span>
                 )}
              </button>
           </nav>
        </div>

        {/* User Profile Snippet */}
        <div className="p-4 bg-fs-darker border-t border-slate-800">
          <div className="flex items-center justify-between">
            {user ? (
                <>
                    <div className="flex items-center space-x-3 overflow-hidden">
                    <div className="w-8 h-8 rounded-full bg-slate-600 flex items-center justify-center text-white text-xs ring-2 ring-slate-700">
                        {user.email.substring(0,2).toUpperCase()}
                    </div>
                    <div className="flex flex-col min-w-0">
                        <span className="text-sm text-white truncate font-medium">{user.email.split('@')[0]}</span>
                        <span className="text-xs text-slate-400 capitalize">{user.role.replace('_', ' ')}</span>
                    </div>
                    </div>
                    <button onClick={handleLogout} className="text-slate-400 hover:text-white p-2 hover:bg-slate-800 rounded-full transition-colors" title="Logout">
                    <LogOut className="w-4 h-4" />
                    </button>
                </>
            ) : (
                <div className="flex items-center justify-between w-full">
                    <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-slate-400 border border-slate-600">
                            <UserCircle2 className="w-5 h-5" />
                        </div>
                        <div className="flex flex-col">
                            <span className="text-sm text-slate-300 font-medium">Guest User</span>
