                  // We look for a colon in the first 40 chars as a heuristic
                  const colonIndex = trimmed.indexOf(':');

                  if (colonIndex > 0 && colonIndex < 40) {
                      const rawSpeaker = trimmed.substring(0, colonIndex);
                      // Clean up markdown chars from speaker name (e.g. **Speaker**)
                      const speakerName = rawSpeaker.replace(/[\*\_]/g, '').trim();
                      const content = trimmed.substring(colonIndex + 1).trim();

                      // Generate initials
                      const initials = speakerName.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
                      const colorClass = getSpeakerColor(speakerName);

                      return (
                          <div key={idx} className="flex flex-row items-start gap-3 group">
                              <div className={`flex-shrink-0 mt-1 w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold border ${colorClass} shadow-sm select-none`}>
                                  {initials}
                              </div>
                              <div className="flex-1 min-w-0">
                                  <span className={`inline-block mb-1.5 px-2.5 py-0.5 rounded-md text-[11px] font-bold uppercase tracking-wider border ${colorClass}`}>
                                      {speakerName}
                                  </span>
                                  <p className="text-slate-700 leading-relaxed text-sm">
                                      {parseMarkdown(content)}
                                  </p>
                              </div>
                          </div>
                      );
                  }

                  // Default paragraph if no speaker detected
                  // Indent slightly to align better with text in speaker blocks
                  return (
                      <p key={idx} className="text-slate-700 leading-relaxed text-sm pl-0 sm:pl-12">
                          {parseMarkdown(trimmed)}
                      </p>
                  );
              })}
          </div>
      );
  };

  if (recordings.length === 0) {
    return (
        <div className="text-center py-12 px-4">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileText className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-medium text-slate-900">No recordings yet</h3>
            <p className="text-slate-500 max-w-sm mx-auto mt-2">
                Tap the microphone button above to start recording your board meeting.
            </p>
        </div>
    );
  }

  const filteredRecordings = recordings.filter(rec => {
      const query = searchQuery.toLowerCase();
      return (
          rec.title.toLowerCase().includes(query) || 
          (rec.note && rec.note.toLowerCase().includes(query)) ||
          (rec.transcription && rec.transcription.toLowerCase().includes(query))
      );
  });

  return (
    <div className="space-y-6">
      {/* Search Bar */}
      <div className="relative max-w-md">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-slate-400" />
        </div>
        <input 
            type="text"
            placeholder="Search by title, notes, or transcript..."
            className="block w-full pl-10 pr-10 py-2.5 border border-slate-300 rounded-lg leading-5 bg-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-fs-primary/50 focus:border-fs-primary sm:text-sm transition-shadow shadow-sm"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
        />
        {searchQuery && (
            <button 
                onClick={() => setSearchQuery('')}
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600"
            >
                <X className="h-4 w-4" />
            </button>
        )}
      </div>

      {filteredRecordings.length === 0 ? (
          <div className="text-center py-12 bg-white rounded-lg border border-dashed border-slate-300">
              <Search className="w-8 h-8 mx-auto mb-2 text-slate-300" />
              <p className="text-slate-500 text-sm">No recordings found for "{searchQuery}"</p>
              <button 
                onClick={() => setSearchQuery('')}
                className="mt-2 text-fs-primary text-sm font-medium hover:underline"
              >
                  Clear search
              </button>
          </div>
      ) : (
          <div className="space-y-4">
            {filteredRecordings.map((rec) => {
                // Parse Action Items if present
                const parts = rec.transcription ? rec.transcription.split('### ACTION ITEMS') : [];
                const mainTranscript = parts[0] ? parts[0].trim() : '';
                const actionItems = parts[1] ? parts[1].trim() : null;
                const isTranscriptExpanded = transcriptExpandedIds.has(rec.id);

                return (
                <div key={rec.id} className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden transition-all duration-200 hover:shadow-md hover:bg-slate-50 hover:border-slate-300">
                <div className="p-4">

                    {/* Header / Title */}
                    <div className="flex items-start justify-between mb-2">
                    <div className="flex-1 mr-4">
                        {editingId === rec.id ? (
                            <input 
                                type="text" 
                                value={editTitle}
                                onChange={(e) => setEditTitle(e.target.value)}
                                className="w-full text-lg font-semibold text-slate-900 border-b-2 border-fs-primary focus:outline-none bg-transparent"
                                autoFocus
                            />
                        ) : (
                            <h3 className="text-lg font-semibold text-slate-900 leading-tight">
                                {rec.title}
                            </h3>
                        )}
                        <div className="flex items-center text-xs text-slate-500 mt-1 space-x-3">
                            <span className="flex items-center">
                                <Clock className="w-3 h-3 mr-1" />
                                {new Date(rec.timestamp).toLocaleDateString()}
                            </span>
                            <span className="font-mono bg-slate-100 px-1.5 py-0.5 rounded">
                                {Math.floor(rec.duration / 60)}:{String(rec.duration % 60).padStart(2, '0')}
                            </span>
                        </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex items-center space-x-1">
                        {editingId === rec.id ? (
                            <button 
                                onClick={() => handleSaveEdit(rec)}
                                className="p-2 text-fs-primary hover:bg-emerald-50 rounded-full"
                            >
                                <Check className="w-5 h-5" />
                            </button>
                        ) : (
                            <button 
                                onClick={() => handleStartEdit(rec)}
                                className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full"
                            >
                                <Edit2 className="w-4 h-4" />
                            </button>
                        )}
                    </div>
                    </div>

                    {/* Notes Section */}
                    {(expandedId === rec.id || rec.note) && (
                        <div className="mt-3 bg-slate-50 rounded p-3 text-sm">
                            <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1">Notes</h4>
                            {editingId === rec.id ? (
                                <textarea 
                                    value={editNote}
                                    onChange={(e) => setEditNote(e.target.value)}
                                    placeholder="Add meeting notes, agenda items, or action points..."
                                    className="w-full bg-transparent focus:outline-none min-h-[60px] text-slate-700 resize-none"
                                />
                            ) : (
                                <p className="text-slate-600 whitespace-pre-wrap">
                                    {rec.note || <span className="text-slate-400 italic">No notes added.</span>}
                                </p>
                            )}
                        </div>
                    )}

                    {/* AI Insights & Transcription */}
                    {(expandedId === rec.id || rec.transcription || rec.isTranscribing) && (
                        <div className="mt-4 border-t border-slate-100 pt-3">
                            {/* Action Items Highlight */}
                            {actionItems && (
                                <div className="mb-4 bg-amber-50 border border-amber-200 rounded-md p-3">
                                    <div className="flex items-center mb-2">
                                        <ListChecks className="w-4 h-4 text-amber-600 mr-2" />
                                        <h4 className="text-xs font-bold text-amber-800 uppercase tracking-wide">Action Items</h4>
                                    </div>
                                    <div className="text-amber-900 text-sm whitespace-pre-wrap pl-6">
                                        {actionItems}
                                    </div>
                                </div>
                            )}

                            {/* Transcript Header & Toggle */}
                            <div 
                                className="flex items-center justify-between cursor-pointer py-2 hover:bg-slate-50 rounded transition-colors"
                                onClick={() => toggleTranscript(rec.id)}
                            >
                                <div className="flex items-center">
                                <Sparkles className="w-3 h-3 text-purple-500 mr-2" />
                                <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide">Transcript</h4>
                                </div>
                                <div className="flex items-center space-x-2">
                                    {rec.transcription && !rec.isTranscribing && isTranscriptExpanded && (
                                        <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleCopyTranscript(rec.transcription!, rec.id);
                                                }}
                                                className="flex items-center text-xs text-slate-400 hover:text-fs-primary transition-colors mr-2"
                                                title="Copy transcript"
                                        >
                                            {copiedId === rec.id ? <Check className="w-3 h-3 mr-1" /> : <Copy className="w-3 h-3 mr-1" />}
                                            {copiedId === rec.id ? 'Copied' : 'Copy'}
                                        </button>
                                    )}
                                    {isTranscriptExpanded ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
                                </div>
                            </div>

                            {/* Collapsible Transcript Body */}
                            {rec.isTranscribing ? (
                                <div className="flex items-center space-x-2 text-slate-500 py-3 px-2 bg-slate-50/50 rounded animate-pulse">
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                    <span className="text-sm italic">Generating transcript...</span>
                                </div>
                            ) : (
                                isTranscriptExpanded && (
                                    <div className="mt-2 bg-white p-3 sm:p-4 rounded-lg border border-slate-100 shadow-inner bg-slate-50/30">
                                        {renderFormattedTranscript(mainTranscript)}
                                    </div>
                                )
                            )}
                        </div>
                    )}

                    {/* Expanded Controls for non-editing state */}
                    {editingId !== rec.id && (
                        <div className="mt-4 flex items-center justify-between border-t border-slate-100 pt-3">
                            <button 
                                onClick={() => handlePlay(rec)}
                                className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                    playingId === rec.id 
                                    ? 'bg-slate-900 text-white' 
                                    : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                                }`}
                            >
                                {playingId === rec.id ? <Pause className="w-4 h-4 mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                                {playingId === rec.id ? 'Pause' : 'Play'}
                            </button>

                            <div className="flex space-x-2">
                                <button 
                                    onClick={() => handleDownload(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                                    title="Download MP3"
                                >
                                    <Download className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => handleExportReport(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                                    title="Export Transcript & Notes"
                                >
                                    <FileDown className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => onShare(rec)}
                                    disabled={rec.status === 'shared'}
                                    className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                        rec.status === 'shared'
                                        ? 'bg-green-100 text-green-700 cursor-default'
                                        : 'bg-fs-primary text-white hover:bg-emerald-600 shadow-sm'
                                    }`}
                                >
                                    {rec.status === 'shared' ? (
                                        <>
                                            <Check className="w-4 h-4 mr-2" />
                                            Shared to ALLi
                                        </>
                                    ) : (
                                        <>
                                            <Share2 className="w-4 h-4 mr-2" />
                                            Share to ALLi
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>
                    )}

                </div>
                </div>
                );
            })}
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Play, Pause, Share2, FileText, Clock, Edit2, Check, Download, Loader2, Sparkles, Copy, ChevronDown, ChevronUp, ListChecks, Search, X, FileDown } from 'lucide-react';
import { Recording, User } from '../types';
import { getAudioBlob } from '../services/dbService';

interface RecordingListProps {
  recordings: Recording[];
  currentUser: User | null;
  onUpdateRecording: (updated: Recording) => void;
  onShare: (recording: Recording) => void;
}

// Helper: Generate consistent colors for speakers based on name hash
const getSpeakerColor = (name: string) => {
  const colors = [
    'bg-blue-100 text-blue-700 border-blue-200',
    'bg-emerald-100 text-emerald-700 border-emerald-200',
    'bg-amber-100 text-amber-700 border-amber-200',
    'bg-purple-100 text-purple-700 border-purple-200',
    'bg-pink-100 text-pink-700 border-pink-200',
    'bg-indigo-100 text-indigo-700 border-indigo-200',
    'bg-cyan-100 text-cyan-700 border-cyan-200',
    'bg-rose-100 text-rose-700 border-rose-200',
  ];
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return colors[Math.abs(hash) % colors.length];
};

// Helper: Simple Markdown Parser for Bold and Italics
const parseMarkdown = (text: string) => {
  // Split by bold (**...**)
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return parts.map((part, i) => {
    if (part.startsWith('**') && part.endsWith('**')) {
      return <strong key={i} className="font-bold text-slate-900">{part.slice(2, -2)}</strong>;
    }
    // Split by italic (*...*) inside non-bold parts
    const subParts = part.split(/(\*.*?\*)/g);
    return subParts.map((subPart, j) => {
       if (subPart.startsWith('*') && subPart.endsWith('*') && subPart.length > 2) {
         return <em key={`${i}-${j}`} className="italic text-slate-800">{subPart.slice(1, -1)}</em>;
       }
       return subPart;
    });
  });
};

export const RecordingList: React.FC<RecordingListProps> = ({ 
  recordings, 
  currentUser,
  onUpdateRecording,
  onShare
}) => {
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNote, setEditNote] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Track which transcripts are fully expanded
  const [transcriptExpandedIds, setTranscriptExpandedIds] = useState<Set<string>>(new Set());

  // Clean up audio on unmount
  useEffect(() => {
    return () => {
      if (audioEl) {
        audioEl.pause();
        audioEl.src = '';
      }
    };
  }, [audioEl]);

  const handlePlay = async (recording: Recording) => {
    if (playingId === recording.id && audioEl) {
      audioEl.pause();
      setPlayingId(null);
      return;
    }

    if (audioEl) {
      audioEl.pause();
    }

    try {
      const blob = await getAudioBlob(recording.blobId);
      if (!blob) {
        alert("Audio file not found.");
        return;
      }

      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);

      audio.onended = () => setPlayingId(null);
      audio.play();

      setAudioEl(audio);
      setPlayingId(recording.id);
    } catch (e) {
      console.error("Error playing audio", e);
    }
  };

  const handleStartEdit = (rec: Recording) => {
    setEditingId(rec.id);
    setEditTitle(rec.title);
    setEditNote(rec.note);
    setExpandedId(rec.id);
  };

  const handleSaveEdit = (rec: Recording) => {
    onUpdateRecording({
      ...rec,
      title: editTitle,
      note: editNote
    });
    setEditingId(null);
  };

  const handleDownload = async (rec: Recording) => {
      try {
        const blob = await getAudioBlob(rec.blobId);
        if (blob) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.mp3`; 
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
      } catch (e) {
          console.error(e);
      }
  };

  const handleExportReport = (rec: Recording) => {
    const date = new Date(rec.timestamp).toLocaleDateString();
    const time = new Date(rec.timestamp).toLocaleTimeString();
    const duration = `${Math.floor(rec.duration / 60)} minutes ${rec.duration % 60} seconds`;

    let content = `FRONTSTEPS NOTE TAKER REPORT\n`;
    content += `==================================================\n`;
    content += `Title:    ${rec.title}\n`;
    content += `Date:     ${date} at ${time}\n`;
    content += `Duration: ${duration}\n`;
    content += `==================================================\n\n`;

    if (rec.note) {
        content += `NOTES\n`;
        content += `-----\n`;
        content += `${rec.note}\n\n`;
    }

    if (rec.transcription) {
        content += `TRANSCRIPT & AI INSIGHTS\n`;
        content += `------------------------\n`;
        content += `${rec.transcription}\n`;
    } else {
         content += `(No transcript available)\n`;
    }

    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_report.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCopyTranscript = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
        setCopiedId(id);
        setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const toggleTranscript = (id: string) => {
    setTranscriptExpandedIds(prev => {
        const next = new Set(prev);
        if (next.has(id)) {
            next.delete(id);
        } else {
            next.add(id);
        }
        return next;
    });
  };

  // Helper to render transcript with speaker labels and markdown
  const renderFormattedTranscript = (text: string) => {
      if (!text) return <span className="text-slate-400 italic">Transcript not available.</span>;

      // Split by newlines to handle paragraphs/lines
      const lines = text.split('\n');

      return (
          <div className="space-y-6">
              {lines.map((line, idx) => {
                  const trimmed = line.trim();
                  if (!trimmed) return null;

                  // Detect "Speaker Name:" pattern
                  // Matches "**Speaker Name:** Content" or "Speaker Name: Content"
                  // We look for a colon in the first 40 chars as a heuristic
                  const colonIndex = trimmed.indexOf(':');

                  if (colonIndex > 0 && colonIndex < 40) {
                      const rawSpeaker = trimmed.substring(0, colonIndex);
                      // Clean up markdown chars from speaker name (e.g. **Speaker**)
                      const speakerName = rawSpeaker.replace(/[\*\_]/g, '').trim();
                      const content = trimmed.substring(colonIndex + 1).trim();

                      // Generate initials
                      const initials = speakerName.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
                      const colorClass = getSpeakerColor(speakerName);

                      return (
                          <div key={idx} className="flex flex-row items-start gap-3 group">
                              <div className={`flex-shrink-0 mt-1 w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold border ${colorClass} shadow-sm select-none`}>
                                  {initials}
                              </div>
                              <div className="flex-1 min-w-0">
                                  <span className={`inline-block mb-1.5 px-2.5 py-0.5 rounded-md text-[11px] font-bold uppercase tracking-wider border ${colorClass}`}>
                                      {speakerName}
                                  </span>
                                  <p className="text-slate-700 leading-relaxed text-sm">
                                      {parseMarkdown(content)}
                                  </p>
                              </div>
                          </div>
                      );
                  }

                  // Default paragraph if no speaker detected
                  // Indent slightly to align better with text in speaker blocks
                  return (
                      <p key={idx} className="text-slate-700 leading-relaxed text-sm pl-0 sm:pl-12">
                          {parseMarkdown(trimmed)}
                      </p>
                  );
              })}
          </div>
      );
  };

  if (recordings.length === 0) {
    return (
        <div className="text-center py-12 px-4">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileText className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-medium text-slate-900">No recordings yet</h3>
            <p className="text-slate-500 max-w-sm mx-auto mt-2">
                Tap the microphone button above to start recording your board meeting.
            </p>
        </div>
    );
  }

  const filteredRecordings = recordings.filter(rec => {
      const query = searchQuery.toLowerCase();
      const matchTitle = rec.title.toLowerCase().includes(query);
      const matchNote = rec.note && rec.note.toLowerCase().includes(query);
      const matchTranscript = rec.transcription && rec.transcription.toLowerCase().includes(query);

      return matchTitle || matchNote || matchTranscript;
  });

  return (
    <div className="space-y-6">
      {/* Search Bar */}
      <div className="relative max-w-md">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-slate-400" />
        </div>
        <input 
            type="text"
            placeholder="Search by title, notes, or transcript..."
            className="block w-full pl-10 pr-10 py-2.5 border border-slate-300 rounded-lg leading-5 bg-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-fs-primary/50 focus:border-fs-primary sm:text-sm transition-shadow shadow-sm"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
        />
        {searchQuery && (
            <button 
                onClick={() => setSearchQuery('')}
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600"
            >
                <X className="h-4 w-4" />
            </button>
        )}
      </div>

      {filteredRecordings.length === 0 ? (
          <div className="text-center py-12 bg-white rounded-lg border border-dashed border-slate-300">
              <Search className="w-8 h-8 mx-auto mb-2 text-slate-300" />
              <p className="text-slate-500 text-sm">No recordings found for "{searchQuery}"</p>
              <button 
                onClick={() => setSearchQuery('')}
                className="mt-2 text-fs-primary text-sm font-medium hover:underline"
              >
                  Clear search
              </button>
          </div>
      ) : (
          <div className="space-y-4">
            {filteredRecordings.map((rec) => {
                // Parse Action Items if present
                const parts = rec.transcription ? rec.transcription.split('### ACTION ITEMS') : [];
                const mainTranscript = parts[0] ? parts[0].trim() : '';
                const actionItems = parts[1] ? parts[1].trim() : null;
                const isTranscriptExpanded = transcriptExpandedIds.has(rec.id);

                // Determine if there is a match in the transcript for the current search query
                const query = searchQuery.toLowerCase();
                const matchInTranscript = query && rec.transcription && rec.transcription.toLowerCase().includes(query);

                return (
                <div key={rec.id} className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden transition-all duration-200 hover:shadow-md hover:bg-slate-50 hover:border-slate-300">
                <div className="p-4">

                    {/* Header / Title */}
                    <div className="flex items-start justify-between mb-2">
                    <div className="flex-1 mr-4">
                        {editingId === rec.id ? (
                            <input 
                                type="text" 
                                value={editTitle}
                                onChange={(e) => setEditTitle(e.target.value)}
                                className="w-full text-lg font-semibold text-slate-900 border-b-2 border-fs-primary focus:outline-none bg-transparent"
                                autoFocus
                            />
                        ) : (
                            <h3 className="text-lg font-semibold text-slate-900 leading-tight">
                                {rec.title}
                            </h3>
                        )}
                        <div className="flex items-center text-xs text-slate-500 mt-1 space-x-3">
                            <span className="flex items-center">
                                <Clock className="w-3 h-3 mr-1" />
                                {new Date(rec.timestamp).toLocaleDateString()}
                            </span>
                            <span className="font-mono bg-slate-100 px-1.5 py-0.5 rounded">
                                {Math.floor(rec.duration / 60)}:{String(rec.duration % 60).padStart(2, '0')}
                            </span>
                        </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex items-center space-x-1">
                        {editingId === rec.id ? (
                            <button 
                                onClick={() => handleSaveEdit(rec)}
                                className="p-2 text-fs-primary hover:bg-emerald-50 rounded-full"
                            >
                                <Check className="w-5 h-5" />
                            </button>
                        ) : (
                            <button 
                                onClick={() => handleStartEdit(rec)}
                                className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full"
                            >
                                <Edit2 className="w-4 h-4" />
                            </button>
                        )}
                    </div>
                    </div>

                    {/* Notes Section */}
                    {(expandedId === rec.id || rec.note) && (
                        <div className="mt-3 bg-slate-50 rounded p-3 text-sm">
                            <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1">Notes</h4>
                            {editingId === rec.id ? (
                                <textarea 
                                    value={editNote}
                                    onChange={(e) => setEditNote(e.target.value)}
                                    placeholder="Add meeting notes, agenda items, or action points..."
                                    className="w-full bg-transparent focus:outline-none min-h-[60px] text-slate-700 resize-none"
                                />
                            ) : (
                                <p className="text-slate-600 whitespace-pre-wrap">
                                    {rec.note || <span className="text-slate-400 italic">No notes added.</span>}
                                </p>
                            )}
                        </div>
                    )}

                    {/* AI Insights & Transcription */}
                    {(expandedId === rec.id || rec.transcription || rec.isTranscribing) && (
                        <div className="mt-4 border-t border-slate-100 pt-3">
                            {/* Action Items Highlight */}
                            {actionItems && (
                                <div className="mb-4 bg-amber-50 border border-amber-200 rounded-md p-3">
                                    <div className="flex items-center mb-2">
                                        <ListChecks className="w-4 h-4 text-amber-600 mr-2" />
                                        <h4 className="text-xs font-bold text-amber-800 uppercase tracking-wide">Action Items</h4>
                                    </div>
                                    <div className="text-amber-900 text-sm whitespace-pre-wrap pl-6">
                                        {actionItems}
                                    </div>
                                </div>
                            )}

                            {/* Transcript Header & Toggle */}
                            <div 
                                className="flex items-center justify-between cursor-pointer py-2 hover:bg-slate-50 rounded transition-colors"
                                onClick={() => toggleTranscript(rec.id)}
                            >
                                <div className="flex items-center">
                                <Sparkles className="w-3 h-3 text-purple-500 mr-2" />
                                <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide">Transcript</h4>
                                {matchInTranscript && !isTranscriptExpanded && (
                                    <span className="ml-2 px-1.5 py-0.5 bg-yellow-100 text-yellow-800 text-[10px] font-bold uppercase rounded-full">
                                        Match
                                    </span>
                                )}
                                </div>
                                <div className="flex items-center space-x-2">
                                    {rec.transcription && !rec.isTranscribing && isTranscriptExpanded && (
                                        <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleCopyTranscript(rec.transcription!, rec.id);
                                                }}
                                                className="flex items-center text-xs text-slate-400 hover:text-fs-primary transition-colors mr-2"
                                                title="Copy transcript"
                                        >
                                            {copiedId === rec.id ? <Check className="w-3 h-3 mr-1" /> : <Copy className="w-3 h-3 mr-1" />}
                                            {copiedId === rec.id ? 'Copied' : 'Copy'}
                                        </button>
                                    )}
                                    {isTranscriptExpanded ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
                                </div>
                            </div>

                            {/* Collapsible Transcript Body */}
                            {rec.isTranscribing ? (
                                <div className="flex items-center space-x-2 text-slate-500 py-3 px-2 bg-slate-50/50 rounded animate-pulse">
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                    <span className="text-sm italic">Generating transcript...</span>
                                </div>
                            ) : (
                                isTranscriptExpanded && (
                                    <div className="mt-2 bg-white p-3 sm:p-4 rounded-lg border border-slate-100 shadow-inner bg-slate-50/30">
                                        {renderFormattedTranscript(mainTranscript)}
                                    </div>
                                )
                            )}
                        </div>
                    )}

                    {/* Expanded Controls for non-editing state */}
                    {editingId !== rec.id && (
                        <div className="mt-4 flex items-center justify-between border-t border-slate-100 pt-3">
                            <button 
                                onClick={() => handlePlay(rec)}
                                className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                    playingId === rec.id 
                                    ? 'bg-slate-900 text-white' 
                                    : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                                }`}
                            >
                                {playingId === rec.id ? <Pause className="w-4 h-4 mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                                {playingId === rec.id ? 'Pause' : 'Play'}
                            </button>

                            <div className="flex space-x-2">
                                <button 
                                    onClick={() => handleDownload(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                                    title="Download MP3"
                                >
                                    <Download className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => handleExportReport(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                                    title="Export Transcript & Notes"
                                >
                                    <FileDown className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => onShare(rec)}
                                    disabled={rec.status === 'shared'}
                                    className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                        rec.status === 'shared'
                                        ? 'bg-green-100 text-green-700 cursor-default'
                                        : 'bg-fs-primary text-white hover:bg-emerald-600 shadow-sm'
                                    }`}
                                >
                                    {rec.status === 'shared' ? (
                                        <>
                                            <Check className="w-4 h-4 mr-2" />
                                            Shared to ALLi
                                        </>
                                    ) : (
                                        <>
                                            <Share2 className="w-4 h-4 mr-2" />
                                            Share to ALLi
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>
                    )}

                </div>
                </div>
                );
            })}
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Play, Pause, Share2, FileText, Clock, Edit2, Check, Download, Loader2, Sparkles, Copy, ChevronDown, ChevronUp, ListChecks, Search, X, FileDown } from 'lucide-react';
import { Recording, User } from '../types';
import { getAudioBlob } from '../services/dbService';

interface RecordingListProps {
  recordings: Recording[];
  currentUser: User | null;
  onUpdateRecording: (updated: Recording) => void;
  onShare: (recording: Recording) => void;
}

// Helper: Generate consistent colors for speakers based on name hash
const getSpeakerColor = (name: string) => {
  const colors = [
    'bg-blue-100 text-blue-700 border-blue-200',
    'bg-emerald-100 text-emerald-700 border-emerald-200',
    'bg-amber-100 text-amber-700 border-amber-200',
    'bg-purple-100 text-purple-700 border-purple-200',
    'bg-pink-100 text-pink-700 border-pink-200',
    'bg-indigo-100 text-indigo-700 border-indigo-200',
    'bg-cyan-100 text-cyan-700 border-cyan-200',
    'bg-rose-100 text-rose-700 border-rose-200',
  ];
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return colors[Math.abs(hash) % colors.length];
};

// Helper: Simple Markdown Parser for Bold and Italics
const parseMarkdown = (text: string) => {
  // Split by bold (**...**)
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return parts.map((part, i) => {
    if (part.startsWith('**') && part.endsWith('**')) {
      return <strong key={i} className="font-bold text-slate-900">{part.slice(2, -2)}</strong>;
    }
    // Split by italic (*...*) inside non-bold parts
    const subParts = part.split(/(\*.*?\*)/g);
    return subParts.map((subPart, j) => {
       if (subPart.startsWith('*') && subPart.endsWith('*') && subPart.length > 2) {
         return <em key={`${i}-${j}`} className="italic text-slate-800">{subPart.slice(1, -1)}</em>;
       }
       return subPart;
    });
  });
};

export const RecordingList: React.FC<RecordingListProps> = ({ 
  recordings, 
  currentUser,
  onUpdateRecording,
  onShare
}) => {
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNote, setEditNote] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Track which transcripts are fully expanded
  const [transcriptExpandedIds, setTranscriptExpandedIds] = useState<Set<string>>(new Set());

  // Clean up audio on unmount
  useEffect(() => {
    return () => {
      if (audioEl) {
        audioEl.pause();
        audioEl.src = '';
      }
    };
  }, [audioEl]);

  const handlePlay = async (recording: Recording) => {
    if (playingId === recording.id && audioEl) {
      audioEl.pause();
      setPlayingId(null);
      return;
    }

    if (audioEl) {
      audioEl.pause();
    }

    try {
      const blob = await getAudioBlob(recording.blobId);
      if (!blob) {
        alert("Audio file not found.");
        return;
      }

      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);

      audio.onended = () => setPlayingId(null);
      audio.play();

      setAudioEl(audio);
      setPlayingId(recording.id);
    } catch (e) {
      console.error("Error playing audio", e);
    }
  };

  const handleStartEdit = (rec: Recording) => {
    setEditingId(rec.id);
    setEditTitle(rec.title);
    setEditNote(rec.note);
    setExpandedId(rec.id);
  };

  const handleSaveEdit = (rec: Recording) => {
    onUpdateRecording({
      ...rec,
      title: editTitle,
      note: editNote
    });
    setEditingId(null);
  };

  const handleDownload = async (rec: Recording) => {
      try {
        const blob = await getAudioBlob(rec.blobId);
        if (blob) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.mp3`; 
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
      } catch (e) {
          console.error(e);
      }
  };

  const handleExportReport = (rec: Recording) => {
    const date = new Date(rec.timestamp).toLocaleDateString();
    const time = new Date(rec.timestamp).toLocaleTimeString();
    const duration = `${Math.floor(rec.duration / 60)} minutes ${rec.duration % 60} seconds`;

    let content = `FRONTSTEPS NOTE TAKER REPORT\n`;
    content += `==================================================\n`;
    content += `Title:    ${rec.title}\n`;
    content += `Date:     ${date} at ${time}\n`;
    content += `Duration: ${duration}\n`;
    content += `==================================================\n\n`;

    if (rec.note) {
        content += `NOTES\n`;
        content += `-----\n`;
        content += `${rec.note}\n\n`;
    }

    if (rec.transcription) {
        content += `TRANSCRIPT & AI INSIGHTS\n`;
        content += `------------------------\n`;
        content += `${rec.transcription}\n`;
    } else {
         content += `(No transcript available)\n`;
    }

    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_report.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCopyTranscript = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
        setCopiedId(id);
        setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const toggleTranscript = (id: string) => {
    setTranscriptExpandedIds(prev => {
        const next = new Set(prev);
        if (next.has(id)) {
            next.delete(id);
        } else {
            next.add(id);
        }
        return next;
    });
  };

  // Helper to render transcript with speaker labels and markdown
  const renderFormattedTranscript = (text: string) => {
      if (!text) return <span className="text-slate-400 italic">Transcript not available.</span>;

      // Split by newlines to handle paragraphs/lines
      const lines = text.split('\n');

      return (
          <div className="space-y-6">
              {lines.map((line, idx) => {
                  const trimmed = line.trim();
                  if (!trimmed) return null;

                  // Detect "Speaker Name:" pattern
                  // Matches "**Speaker Name:** Content" or "Speaker Name: Content"
                  // We look for a colon in the first 40 chars as a heuristic
                  const colonIndex = trimmed.indexOf(':');

                  if (colonIndex > 0 && colonIndex < 40) {
                      const rawSpeaker = trimmed.substring(0, colonIndex);
                      // Clean up markdown chars from speaker name (e.g. **Speaker**)
                      const speakerName = rawSpeaker.replace(/[\*\_]/g, '').trim();
                      const content = trimmed.substring(colonIndex + 1).trim();

                      // Generate initials
                      const initials = speakerName.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
                      const colorClass = getSpeakerColor(speakerName);

                      return (
                          <div key={idx} className="flex flex-row items-start gap-3 group">
                              <div className={`flex-shrink-0 mt-1 w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold border ${colorClass} shadow-sm select-none`}>
                                  {initials}
                              </div>
                              <div className="flex-1 min-w-0">
                                  <span className={`inline-block mb-1.5 px-2.5 py-0.5 rounded-md text-[11px] font-bold uppercase tracking-wider border ${colorClass}`}>
                                      {speakerName}
                                  </span>
                                  <p className="text-slate-700 leading-relaxed text-sm">
                                      {parseMarkdown(content)}
                                  </p>
                              </div>
                          </div>
                      );
                  }

                  // Default paragraph if no speaker detected
                  // Indent slightly to align better with text in speaker blocks
                  return (
                      <p key={idx} className="text-slate-700 leading-relaxed text-sm pl-0 sm:pl-12">
                          {parseMarkdown(trimmed)}
                      </p>
                  );
