                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="flex flex-col items-center mb-8">
                            <div className={`text-6xl font-mono font-bold tracking-wider tabular-nums transition-colors duration-300 ${isRecording ? 'text-slate-800' : 'text-slate-300'}`}>
                                {formatTime(duration)}
                            </div>
                            {isRecording && (
                                <div className="flex items-center mt-3 text-red-500 font-medium text-sm animate-pulse">
                                    <div className="w-2 h-2 bg-red-500 rounded-full mr-2" />
                                    Recording in progress
                                </div>
                            )}
                        </div>

                        <div className="relative">
                            {isRecording && (
                                <div className="absolute inset-0 rounded-full border border-red-200 animate-ping opacity-75 scale-150 pointer-events-none" />
                            )}

                            {!isRecording ? (
                                <button 
                                    onClick={startRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-fs-primary hover:bg-emerald-600 text-white shadow-lg hover:shadow-xl hover:shadow-emerald-500/30 transition-all duration-300 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-emerald-100"
                                >
                                    <Mic className="w-10 h-10" />
                                </button>
                            ) : (
                                <button 
                                    onClick={stopRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-white border-4 border-red-500 hover:bg-red-50 text-red-500 shadow-lg transition-all duration-200 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-red-100"
                                >
                                    <Square className="w-8 h-8 fill-current" />
                                </button>
                            )}
                        </div>
                    </>
                ) : (
                    /* PREVIEW STATE UI */
                    <div className="w-full flex flex-col items-center animate-in fade-in duration-300">
                         <h3 className="text-lg font-semibold text-slate-700 mb-6">Preview Recording</h3>

                         {/* Playback Controls */}
                         <div className="w-full max-w-xs mb-8">
                            <div className="flex justify-between text-xs text-slate-500 font-mono mb-2 px-1">
                                <span>{formatTime(currentTime)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>
                            <input 
                                type="range"
                                min="0"
                                max={duration}
                                step="0.1"
                                value={currentTime}
                                onChange={handleSeek}
                                className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-fs-primary focus:outline-none focus:ring-2 focus:ring-fs-primary/30"
                            />
                         </div>

                         <div className="flex items-center justify-center space-x-6">
                            {/* Discard Button */}
                            <button 
                                onClick={handleDiscard} 
                                disabled={isProcessing}
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
                                title="Discard"
                            >
                                <Trash2 className="w-6 h-6 mb-1" />
                                <span className="text-[10px] font-medium uppercase tracking-wide">Discard</span>
                            </button>

                            {/* Play/Pause Button */}
                            <button 
                                onClick={togglePlay} 
                                className="w-20 h-20 bg-fs-dark text-white rounded-full flex items-center justify-center hover:bg-slate-800 shadow-xl shadow-slate-900/20 transition-transform hover:scale-105"
                            >
                                {isPlaying ? <Pause className="w-8 h-8 fill-current" /> : <Play className="w-8 h-8 fill-current ml-1" />}
                            </button>

                            {/* Save Button */}
                            <button 
                                onClick={handleSave} 
                                disabled={isProcessing} 
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-fs-primary hover:bg-emerald-50 transition-all"
                                title="Save"
                            >
                                {isProcessing ? (
                                    <Loader2 className="w-6 h-6 animate-spin mb-1" />
                                ) : (
                                    <Check className="w-6 h-6 mb-1" />
                                )}
                                <span className="text-[10px] font-medium uppercase tracking-wide">{isProcessing ? 'Saving' : 'Save'}</span>
                            </button>
                         </div>
                    </div>
                )}
            </div>

            {/* Footer Hints */}
            {!isRecording && !isProcessing && !recordedBlob && (
                 <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Ready to capture
                    </p>
                 </div>
            )}

            {recordedBlob && !isProcessing && (
                <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Review before saving
                    </p>
                 </div>
            )}
        </div>

        {/* Error Toast */}
        {error && (
            <div className="absolute -bottom-20 left-0 right-0 flex justify-center px-4 z-50">
                <div className="bg-red-50 text-red-800 px-4 py-3 rounded-xl text-sm font-medium shadow-lg border border-red-200 animate-in slide-in-from-bottom-2 fade-in duration-300 max-w-sm text-center flex items-center">
                    <span className="mr-2 text-xl">⚠️</span>
                    {error}
                </div>
            </div>
        )}
    </div>
  );
};

export const requestNotificationPermission = async (): Promise<boolean> => {
  if (!('Notification' in window)) {
    console.warn('Notifications not supported in this browser');
    return false;
  }

  if (Notification.permission === 'granted') {
    return true;
  }

  try {
    const permission = await Notification.requestPermission();
    return permission === 'granted';
  } catch (e) {
    console.error('Error requesting notification permission:', e);
    return false;
  }
};

export const sendNotification = (title: string, body: string) => {
  if (!('Notification' in window)) return;

  if (Notification.permission === 'granted') {
    try {
      new Notification(title, {
        body,
        icon: '/vite.svg', // Uses the app icon
        silent: false,
      });
    } catch (e) {
      console.error('Error sending notification:', e);
    }
  }
};

export const getNotificationPermission = (): NotificationPermission | 'unsupported' => {
  if (!('Notification' in window)) return 'unsupported';
  return Notification.permission;
};

import React, { useState, useEffect } from 'react';
import { User, Recording, UserRole } from './types';
import { getRecordingsMeta, saveRecordingsMeta, getUserSession, saveUserSession, clearUserSession } from './services/storageService';
import { AuthScreen } from './components/AuthScreen';
import { Recorder } from './components/Recorder';
import { RecordingList } from './components/RecordingList';
import { LogOut, LayoutGrid, Menu, Mic, List, History, UserCircle2, LogIn, ShieldCheck, Info, Bell } from 'lucide-react';
import { transcribeAudio } from './services/aiService';
import { getAudioBlob } from './services/dbService';
import { requestNotificationPermission, sendNotification, getNotificationPermission } from './services/notificationService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [recordings, setRecordings] = useState<Recording[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [currentView, setCurrentView] = useState<'record' | 'history'>('record');
  const [showAuth, setShowAuth] = useState(false);
  const [pendingShareRecording, setPendingShareRecording] = useState<Recording | null>(null);
  const [notificationPermission, setNotificationPermission] = useState(getNotificationPermission());

  // Initialize app
  useEffect(() => {
    const session = getUserSession();
    if (session) {
      setUser(session);
    }
    const savedRecs = getRecordingsMeta();
    setRecordings(savedRecs);
    setIsLoading(false);
  }, []);

  // Persist recordings when changed
  useEffect(() => {
    if (!isLoading) {
      saveRecordingsMeta(recordings);
    }
  }, [recordings, isLoading]);

  // Handle pending share action after successful login
  useEffect(() => {
    if (user && pendingShareRecording) {
      performShare(pendingShareRecording);
      setPendingShareRecording(null);
    }
  }, [user]);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    saveUserSession(newUser);
    setShowAuth(false);
  };

  const handleLogout = () => {
    setUser(null);
    clearUserSession();
  };

  const handleEnableNotifications = async () => {
    await requestNotificationPermission();
    setNotificationPermission(getNotificationPermission());
  };

  const handleRecordingComplete = async (blobId: string, duration: number, defaultName: string) => {
    const newRecording: Recording = {
      id: crypto.randomUUID(),
      title: defaultName,
      timestamp: new Date().toISOString(),
      duration: duration,
      note: '',
      blobId: blobId,
      status: 'ready',
      isTranscribing: true,
    };

    // Optimistically switch to history to show progress
    setRecordings(prev => [newRecording, ...prev]);
    setCurrentView('history');

    try {
      const blob = await getAudioBlob(blobId);
      if (blob) {
        const transcription = await transcribeAudio(blob);
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, transcription, isTranscribing: false } 
            : rec
        ));

        // Notify user
        sendNotification("Transcription Ready", `Processing complete for "${defaultName}"`);

      } else {
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, isTranscribing: false } 
            : rec
        ));
      }
    } catch (error) {
      console.error('Transcription failed', error);
      setRecordings(prev => prev.map(rec => 
        rec.id === newRecording.id 
          ? { ...rec, isTranscribing: false } 
          : rec
      ));
      sendNotification("Transcription Failed", `Could not generate transcript for "${defaultName}"`);
    }
  };

  const handleUpdateRecording = (updated: Recording) => {
    setRecordings(prev => prev.map(r => r.id === updated.id ? updated : r));
  };

  const performShare = (rec: Recording) => {
    // Mock API Push to ALLi
    const confirmShare = window.confirm(`Push "${rec.title}" to ALLi? This will make it available to the board.`);
    if (!confirmShare) return;

    // Optimistic update
    handleUpdateRecording({ ...rec, status: 'shared' });

    // Mock redirection based on Role
    setTimeout(() => {
      sendNotification("Shared to ALLi", `"${rec.title}" is now available to board members.`);

      if (user?.role === UserRole.BOARD_MEMBER) {
        // Deep link simulation
        alert("Redirecting to FRONTSTEPS Community App...");
      } else if (user?.role === UserRole.MANAGER) {
        window.open('https://suite.frontsteps.com/#/steps/overview', '_blank');
      } else {
        // Fallback for edge cases
        alert("Shared to ALLi successfully.");
      }
    }, 1000);
  };

  const handleShareClick = (rec: Recording) => {
    if (!user) {
      setPendingShareRecording(rec);
      setShowAuth(true);
      return;
    }
    performShare(rec);
  };

  if (isLoading) return null;

  return (
    <div className="h-screen bg-slate-50 flex flex-col md:flex-row overflow-hidden relative">

      {/* Auth Modal */}
      {showAuth && (
        <AuthScreen 
            onLogin={handleLogin} 
            onCancel={() => {
                setShowAuth(false);
                setPendingShareRecording(null);
            }} 
        />
      )}

      {/* Sidebar (Desktop) */}
      <div className="hidden md:flex md:w-64 bg-fs-dark flex-shrink-0 flex-col justify-between shadow-xl z-10">
        <div className="p-6">
           <div className="flex items-center space-x-3 mb-8 px-1">
               <div className="h-10 w-10 bg-gradient-to-br from-fs-primary to-emerald-600 rounded-lg flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-fs-primary/20">
                   <span className="font-sans">F</span>
               </div>
               <div className="flex flex-col">
                    <span className="text-lg font-bold text-white tracking-tight leading-none">
                        FRONTST<span className="text-fs-primary">Ξ</span>PS
                    </span>
                    <span className="text-[10px] text-slate-400 font-bold tracking-widest uppercase mt-0.5">Note Taker</span>
               </div>
           </div>

           <nav className="space-y-2">
              <button 
                onClick={() => setCurrentView('record')}
                className={`w-full flex items-center space-x-3 px-3 py-3 rounded-lg transition-all duration-200 ${
                    currentView === 'record' 
                    ? 'bg-slate-800 text-white shadow-md border-l-4 border-fs-primary' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                }`}
              >
                 <Mic className={`w-5 h-5 ${currentView === 'record' ? 'text-fs-primary' : ''}`} />
                 <span className="text-sm font-medium">Record</span>
              </button>

              <button 
                onClick={() => setCurrentView('history')}
                className={`w-full flex items-center space-x-3 px-3 py-3 rounded-lg transition-all duration-200 ${
                    currentView === 'history' 
                    ? 'bg-slate-800 text-white shadow-md border-l-4 border-fs-primary' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                }`}
              >
                 <History className={`w-5 h-5 ${currentView === 'history' ? 'text-fs-primary' : ''}`} />
                 <span className="text-sm font-medium">History</span>
                 {recordings.length > 0 && (
                    <span className="ml-auto text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded-full">
                        {recordings.length}
                    </span>
                 )}
              </button>

              {notificationPermission === 'default' && (
                  <button 
                    onClick={handleEnableNotifications}
                    className="w-full flex items-center space-x-3 px-3 py-3 rounded-lg text-slate-400 hover:text-white hover:bg-slate-800/50 transition-all duration-200"
                  >
                     <Bell className="w-5 h-5" />
                     <span className="text-sm font-medium">Enable Alerts</span>
                  </button>
              )}
           </nav>
        </div>

        {/* User Profile Snippet */}
        <div className="p-4 bg-fs-darker border-t border-slate-800">
          <div className="flex items-center justify-between">
            {user ? (
                <>
                    <div className="flex items-center space-x-3 overflow-hidden">
                    <div className="w-8 h-8 rounded-full bg-slate-600 flex items-center justify-center text-white text-xs ring-2 ring-slate-700">
                        {user.email.substring(0,2).toUpperCase()}
                    </div>
                    <div className="flex flex-col min-w-0">
                        <span className="text-sm text-white truncate font-medium">{user.email.split('@')[0]}</span>
                        <span className="text-xs text-slate-400 capitalize">{user.role.replace('_', ' ')}</span>
                    </div>
                    </div>
                    <button onClick={handleLogout} className="text-slate-400 hover:text-white p-2 hover:bg-slate-800 rounded-full transition-colors" title="Logout">
                    <LogOut className="w-4 h-4" />
                    </button>
                </>
            ) : (
                <div className="flex items-center justify-between w-full">
                    <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-slate-400 border border-slate-600">
                            <UserCircle2 className="w-5 h-5" />
                        </div>
                        <div className="flex flex-col">
                            <span className="text-sm text-slate-300 font-medium">Guest User</span>
                            <span className="text-[10px] text-slate-500 uppercase tracking-wide">Local Mode</span>
                        </div>
                    </div>
                    <button 
                        onClick={() => setShowAuth(true)}
                        className="text-fs-primary hover:text-white p-2 hover:bg-slate-800 rounded-full transition-colors"
                        title="Log In"
                    >
                        <LogIn className="w-4 h-4" />
                    </button>
                </div>
            )}
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">

        {/* Mobile Header / Navigation Tabs */}
        <div className="md:hidden bg-white border-b border-slate-200 shadow-sm z-20">
            <div className="p-4 flex items-center justify-between border-b border-slate-100">
                <div className="flex items-center space-x-2">
                    <div className="h-6 w-6 bg-gradient-to-br from-fs-primary to-emerald-600 rounded flex items-center justify-center text-white font-bold text-sm">
                       F
                    </div>
                    <span className="font-bold text-slate-800 text-lg tracking-tight">
                        FRONTST<span className="text-fs-primary">Ξ</span>PS <span className="text-slate-400 font-normal text-base ml-1">Note Taker</span>
                    </span>
                </div>
                {user ? (
                    <button onClick={handleLogout} className="text-slate-500">
                        <LogOut className="w-5 h-5" />
                    </button>
                ) : (
                    <button onClick={() => setShowAuth(true)} className="text-fs-primary font-medium text-sm flex items-center">
                        Login
                    </button>
                )}
            </div>
            <div className="flex">
                <button 
                    onClick={() => setCurrentView('record')}
                    className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${
                        currentView === 'record' 
                        ? 'border-fs-primary text-fs-primary' 
                        : 'border-transparent text-slate-500'
                    }`}
                >
                    Record
                </button>
                <button 
                    onClick={() => setCurrentView('history')}
                    className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${
                        currentView === 'history' 
                        ? 'border-fs-primary text-fs-primary' 
                        : 'border-transparent text-slate-500'
                    }`}
                >
                    History
                </button>
            </div>
        </div>

        {/* View Content */}
        <main className="flex-1 overflow-y-auto bg-slate-50">
            {currentView === 'record' ? (
                <div className="h-full flex flex-col items-center p-6 md:p-12 pt-12 md:pt-20">
                     <div className="max-w-2xl w-full flex flex-col items-center">
                        <div className="mb-8 text-center">
                            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Meeting Recorder</h1>
                            <p className="text-slate-500 mt-2 text-lg">Capture audio, get transcripts, and push to ALLi.</p>
                        </div>
                        <Recorder onRecordingComplete={handleRecordingComplete} />

                        {/* Enhanced Privacy Section */}
                        <div className="mt-10 flex flex-col items-center">
                            <div className="group relative inline-flex items-center justify-center cursor-help transition-opacity hover:opacity-100 opacity-80">
                                <ShieldCheck className="w-4 h-4 text-emerald-600 mr-2" />
                                <span className="text-sm font-medium text-slate-600 border-b border-dashed border-slate-300 pb-0.5">
                                    Privacy & Data Protection
                                </span>

                                {/* Tooltip */}
                                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 w-72 p-4 bg-slate-900 text-slate-50 text-xs rounded-xl shadow-xl opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50 pointer-events-none text-left leading-relaxed border border-slate-700">
                                    <div className="absolute bottom-[-6px] left-1/2 -translate-x-1/2 w-3 h-3 bg-slate-900 border-r border-b border-slate-700 rotate-45"></div>
                                    <h4 className="font-bold text-white mb-2 flex items-center">
                                        <ShieldCheck className="w-3 h-3 mr-1.5 text-emerald-500" />
                                        Your Data Privacy
                                    </h4>
                                    <ul className="space-y-2 text-slate-300">
                                        <li className="flex items-start">
                                            <span className="mr-2 text-emerald-500">•</span>
                                            <span><strong>FRONTSTEPS does not store</strong> any recording data. All files stay on your device until you choose to share.</span>
                                        </li>
                                        <li className="flex items-start">
                                            <span className="mr-2 text-emerald-500">•</span>
                                            <span>Your information is <strong>never used for training</strong> AI models.</span>
                                        </li>
                                        <li className="flex items-start">
                                            <span className="mr-2 text-emerald-500">•</span>
                                            <span>Transcriptions are processed ephemerally and encrypted.</span>
                                        </li>
                                    </ul>
                                </div>
                            </div>
                            <p className="mt-3 text-xs text-slate-400 text-center max-w-xs">
                                Recordings are stored locally. You retain full ownership of your data.
                            </p>
                        </div>
                     </div>
                </div>
            ) : (
                <div className="h-full overflow-y-auto">
                    <div className="max-w-4xl mx-auto p-4 md:p-12">
                         <div className="flex items-center justify-between mb-8">
                            <div>
                                <h1 className="text-2xl font-bold text-slate-900">Recording History</h1>
                                <p className="text-slate-500 mt-1">Review transcripts and action items</p>
                            </div>
                            <span className="hidden md:inline-flex bg-white px-3 py-1 rounded-full border border-slate-200 text-xs font-medium text-slate-600 shadow-sm">
                                {recordings.length} items
                            </span>
                         </div>

                        <RecordingList 
                            recordings={recordings}
                            currentUser={user}
                            onUpdateRecording={handleUpdateRecording}
                            onShare={handleShareClick}
                        />
                    </div>
                </div>
            )}
        </main>
      </div>

    </div>
  );
};

