  const [gameState, setGameState] = useState<'start' | 'playing' | 'gameover'>('start');
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);

  // Game Refs to avoid stale state in loop
  const requestRef = useRef<number>(0);
  const gameStateRef = useRef<'start' | 'playing' | 'gameover'>('start');
  const scoreRef = useRef(0);

  // Game Constants
  const GRAVITY = 0.45; 
  const JUMP_FORCE = -8; 
  const SPEED = 3.5; 
  const GROUND_HEIGHT = 20;

  // Entities
  const playerRef = useRef({
    x: 50,
    y: 0, 
    width: 28, // Slightly wider for a house
    height: 28,
    dy: 0,
    grounded: false,
    rotation: 0
  });

  const obstaclesRef = useRef<Array<{
      x: number, 
      width: number, 
      height: number, 
      passed: boolean, 
      type: 'trash' | 'flamingo' 
  }>>([]);

  const frameCountRef = useRef(0);

  // Initialize Game
  const resetGame = () => {
    if (canvasRef.current) {
        playerRef.current = {
            x: 50,
            y: canvasRef.current.height - GROUND_HEIGHT - 28,
            width: 28,
            height: 28,
            dy: 0,
            grounded: true,
            rotation: 0
        };
        obstaclesRef.current = [];
        frameCountRef.current = 0;
        scoreRef.current = 0;
        setScore(0);
        setGameState('playing');
        gameStateRef.current = 'playing';
    }
  };

  const jump = () => {
    if (gameStateRef.current !== 'playing') {
        if (gameStateRef.current !== 'playing') resetGame();
        return;
    }

    if (playerRef.current.grounded) {
        playerRef.current.dy = JUMP_FORCE;
        playerRef.current.grounded = false;
    }
  };

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.code === 'Space' || e.code === 'ArrowUp') {
            e.preventDefault();
            jump();
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Main Game Loop
  const update = (time: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear Canvas with a subtle sky gradient
    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, '#f0f9ff'); // Sky blue light
    gradient.addColorStop(1, '#ffffff');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // --- LOGIC ---
    if (gameStateRef.current === 'playing') {
        frameCountRef.current++;

        // Spawn Obstacles (Violations)
        if (frameCountRef.current % Math.floor(100 + Math.random() * 60) === 0) {
             const type = Math.random() > 0.5 ? 'trash' : 'flamingo';
             const height = type === 'trash' ? 30 : 35;
             const width = type === 'trash' ? 20 : 15;

             obstaclesRef.current.push({
                 x: canvas.width,
                 width: width,
                 height: height,
                 passed: false,
                 type: type
             });
        }

        // Update Obstacles
        for (let i = obstaclesRef.current.length - 1; i >= 0; i--) {
            let obs = obstaclesRef.current[i];
            obs.x -= SPEED;

            // Remove if off screen
            if (obs.x + obs.width < 0) {
                obstaclesRef.current.splice(i, 1);
                continue;
            }

            // Score update
            if (!obs.passed && obs.x + obs.width < playerRef.current.x) {
                scoreRef.current++;
                setScore(scoreRef.current);
                obs.passed = true;
            }

            // Collision Detection
            const p = playerRef.current;
            const padding = 6;

            const playerBottom = p.y + p.height - padding;
            const playerRight = p.x + p.width - padding;
            const playerLeft = p.x + padding;
            const playerTop = p.y + padding;

            const obsLeft = obs.x + 2; // slight visual padding for obstacle
            const obsRight = obs.x + obs.width - 2;
            const obsTop = canvas.height - GROUND_HEIGHT - obs.height + 2;

            if (playerRight > obsLeft && 
                playerLeft < obsRight && 
                playerBottom > obsTop) {

                gameStateRef.current = 'gameover';
                setGameState('gameover');
                if (scoreRef.current > highScore) {
                    setHighScore(scoreRef.current);
                }
            }
        }

        // Update Player
        const p = playerRef.current;
        p.dy += GRAVITY;
        p.y += p.dy;

        // Ground collision
        if (p.y + p.height >= canvas.height - GROUND_HEIGHT) {
            p.y = canvas.height - GROUND_HEIGHT - p.height;
            p.dy = 0;
            p.grounded = true;
            p.rotation = 0; // Reset rotation on ground
        } else {
            // Slight tilt when jumping
            p.rotation = Math.min(Math.PI / 8, p.dy * 0.05);
        }
    }

    // --- DRAWING ---

    // Draw Ground (Grass)
    ctx.fillStyle = '#86efac'; // Green-300
    ctx.fillRect(0, canvas.height - GROUND_HEIGHT, canvas.width, GROUND_HEIGHT);
    // Grass top border
    ctx.beginPath();
    ctx.strokeStyle = '#22c55e'; // Green-500
    ctx.lineWidth = 2;
    ctx.moveTo(0, canvas.height - GROUND_HEIGHT);
    ctx.lineTo(canvas.width, canvas.height - GROUND_HEIGHT);
    ctx.stroke();

    // Draw Obstacles
    obstaclesRef.current.forEach(obs => {
        const y = canvas.height - GROUND_HEIGHT - obs.height;

        if (obs.type === 'trash') {
            // Draw Trash Can
            ctx.fillStyle = '#64748b'; // Slate-500
            // Can body
            ctx.fillRect(obs.x + 2, y + 4, obs.width - 4, obs.height - 4);
            // Lid
            ctx.fillStyle = '#475569'; // Slate-600
            ctx.fillRect(obs.x, y, obs.width, 4);
            // Lines
            ctx.fillStyle = '#94a3b8';
            ctx.fillRect(obs.x + 5, y + 8, 2, obs.height - 10);
            ctx.fillRect(obs.x + 9, y + 8, 2, obs.height - 10);
            ctx.fillRect(obs.x + 13, y + 8, 2, obs.height - 10);
        } else {
            // Draw Flamingo
            const centerX = obs.x + obs.width/2;

            // Legs
            ctx.beginPath();
            ctx.strokeStyle = '#f472b6'; // Pink-400
            ctx.lineWidth = 2;
            ctx.moveTo(centerX, y + obs.height);
            ctx.lineTo(centerX, y + obs.height/2);
            ctx.stroke();

            // Body
            ctx.fillStyle = '#ec4899'; // Pink-500
            ctx.beginPath();
            ctx.ellipse(centerX, y + obs.height/2 - 5, 8, 6, -0.2, 0, Math.PI * 2);
            ctx.fill();

            // Neck & Head
            ctx.beginPath();
            ctx.strokeStyle = '#ec4899';
            ctx.lineWidth = 3;
            ctx.moveTo(centerX + 6, y + obs.height/2 - 8);
            ctx.quadraticCurveTo(centerX + 12, y + obs.height/2 - 15, centerX + 4, y);
            ctx.stroke();

            // Beak
            ctx.fillStyle = '#1e293b';
            ctx.beginPath();
            ctx.arc(centerX + 4, y, 2, 0, Math.PI * 2);
            ctx.fill();
        }
    });

    // Draw Player (House)
    const p = playerRef.current;
    ctx.save();
    ctx.translate(p.x + p.width/2, p.y + p.height/2);
    ctx.rotate(p.rotation);

    // House Body
    ctx.fillStyle = '#3b82f6'; // Blue-500
    ctx.fillRect(-p.width/2 + 2, -p.height/2 + 10, p.width - 4, p.height - 10);

    // Door
    ctx.fillStyle = '#1e3a8a'; // Blue-900
    ctx.fillRect(-4, 2, 8, p.height/2 - 2);

    // Roof
    ctx.beginPath();
    ctx.fillStyle = '#1d4ed8'; // Blue-700
    ctx.moveTo(-p.width/2, -p.height/2 + 10);
    ctx.lineTo(0, -p.height/2 - 2);
    ctx.lineTo(p.width/2, -p.height/2 + 10);
    ctx.fill();

    ctx.restore();

    requestRef.current = requestAnimationFrame(update);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(update);
    return () => cancelAnimationFrame(requestRef.current);
  }, []);

  return (
    <div className="mt-8 w-full max-w-md mx-auto relative group select-none">

        {/* Game Canvas */}
        <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-inner relative" onClick={jump}>
            <canvas 
                ref={canvasRef}
                width={400} 
                height={160} 
                className="w-full h-auto cursor-pointer block"
            />

