import React, { useState, useEffect } from 'react';
import { User, Recording, UserRole } from './types';
import { getRecordingsMeta, saveRecordingsMeta, getUserSession, saveUserSession, clearUserSession } from './services/storageService';
import { AuthScreen } from './components/AuthScreen';
import { Recorder } from './components/Recorder';
import { RecordingList } from './components/RecordingList';
import { LogOut, LayoutGrid, Menu, Mic, List, History, UserCircle2, LogIn, ShieldCheck, Info, Bell } from 'lucide-react';
import { transcribeAudio } from './services/aiService';
import { getAudioBlob } from './services/dbService';
import { requestNotificationPermission, sendNotification, getNotificationPermission } from './services/notificationService';
import { logGuestActivity } from './services/loggingService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [recordings, setRecordings] = useState<Recording[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [currentView, setCurrentView] = useState<'record' | 'history'>('record');
  const [showAuth, setShowAuth] = useState(false);
  const [pendingShareRecording, setPendingShareRecording] = useState<Recording | null>(null);
  const [notificationPermission, setNotificationPermission] = useState(getNotificationPermission());

  // Initialize app
  useEffect(() => {
    const session = getUserSession();
    if (session) {
      setUser(session);
    }
    const savedRecs = getRecordingsMeta();
    setRecordings(savedRecs);
    setIsLoading(false);
  }, []);

  // Persist recordings when changed
  useEffect(() => {
    if (!isLoading) {
      saveRecordingsMeta(recordings);
    }
  }, [recordings, isLoading]);

  // Handle pending share action after successful login
  useEffect(() => {
    if (user && pendingShareRecording) {
      performShare(pendingShareRecording);
      setPendingShareRecording(null);
    }
  }, [user]);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    saveUserSession(newUser);
    setShowAuth(false);
  };

  const handleLogout = () => {
    setUser(null);
    clearUserSession();
  };

  const handleEnableNotifications = async () => {
    await requestNotificationPermission();
    setNotificationPermission(getNotificationPermission());
  };

  const handleRecordingComplete = async (blobId: string, duration: number, defaultName: string, note: string) => {
    const newRecording: Recording = {
      id: crypto.randomUUID(),
      title: defaultName,
      timestamp: new Date().toISOString(),
      duration: duration,
      note: note,
      blobId: blobId,
      status: 'ready',
      isTranscribing: true,
    };

    // Log metadata if user is not logged in (Guest Mode)
    if (!user) {
        logGuestActivity('RECORDING_COMPLETED', {
            recordingId: newRecording.id,
            durationSeconds: duration,
            hasNotes: !!note,
            timestamp: newRecording.timestamp,
            deviceType: /Mobi|Android/i.test(navigator.userAgent) ? 'mobile' : 'desktop'
        });
    }

    // Optimistically switch to history to show progress
    setRecordings(prev => [newRecording, ...prev]);
    setCurrentView('history');

    try {
      const blob = await getAudioBlob(blobId);
      if (blob) {
        const transcription = await transcribeAudio(blob);
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, transcription, isTranscribing: false } 
            : rec
        ));

        // Notify user
        sendNotification("Transcription Ready", `Processing complete for "${defaultName}"`);

      } else {
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, isTranscribing: false } 
            : rec
        ));
      }
    } catch (error) {
      console.error('Transcription failed', error);
      setRecordings(prev => prev.map(rec => 
        rec.id === newRecording.id 
          ? { ...rec, isTranscribing: false } 
          : rec
      ));
      sendNotification("Transcription Failed", `Could not generate transcript for "${defaultName}"`);
    }
  };

  const handleUpdateRecording = (updated: Recording) => {
    setRecordings(prev => prev.map(r => r.id === updated.id ? updated : r));
  };

  const performShare = (rec: Recording) => {
    // Mock API Push to ALLi
    const confirmShare = window.confirm(`Push "${rec.title}" to ALLi? This will make it available to the board.`);
    if (!confirmShare) return;

    // Optimistic update
    handleUpdateRecording({ ...rec, status: 'shared' });

    // Mock redirection based on Role
    setTimeout(() => {
      sendNotification("Shared to ALLi", `"${rec.title}" is now available to board members.`);

      if (user?.role === UserRole.BOARD_MEMBER) {
        // Deep link simulation
        alert("Redirecting to FRONTSTEPS Community App...");
      } else if (user?.role === UserRole.MANAGER) {
        window.open('https://suite.frontsteps.com/#/steps/overview', '_blank');
      } else {
        // Fallback for edge cases
        alert("Shared to ALLi successfully.");
      }
    }, 1000);
  };

  const handleShareClick = (rec: Recording) => {
    if (!user) {
      setPendingShareRecording(rec);
      setShowAuth(true);
      return;
    }
    performShare(rec);
  };

  if (isLoading) return null;

  return (
    <div className="h-screen bg-slate-50 flex flex-col md:flex-row overflow-hidden relative">

      {/* Auth Modal */}
      {showAuth && (
        <AuthScreen 
            onLogin={handleLogin} 
            onCancel={() => {
                setShowAuth(false);
                setPendingShareRecording(null);
            }} 
        />
      )}

      {/* Sidebar (Desktop) */}
      <div className="hidden md:flex md:w-64 bg-fs-dark flex-shrink-0 flex-col justify-between shadow-xl z-10">
        <div className="p-6">
           <div className="flex items-center space-x-3 mb-8 px-1">
               <div className="h-10 w-10 bg-gradient-to-br from-fs-primary to-emerald-600 rounded-lg flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-fs-primary/20">
                   <span className="font-sans">F</span>
               </div>
               <div className="flex flex-col">
                    <span className="text-lg font-bold text-white tracking-tight leading-none">
                        FRONTST<span className="text-fs-primary">Ξ</span>PS
                    </span>
                    <span className="text-[10px] text-slate-400 font-bold tracking-widest uppercase mt-0.5">Note Taker</span>
               </div>
           </div>

           <nav className="space-y-2">
              <button 
                onClick={() => setCurrentView('record')}
                className={`w-full flex items-center space-x-3 px-3 py-3 rounded-lg transition-all duration-200 ${
                    currentView === 'record' 
                    ? 'bg-slate-800 text-white shadow-md border-l-4 border-fs-primary' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                }`}
              >
                 <Mic className={`w-5 h-5 ${currentView === 'record' ? 'text-fs-primary' : ''}`} />
                 <span className="text-sm font-medium">Record</span>
              </button>

              <button 
                onClick={() => setCurrentView('history')}
                className={`w-full flex items-center space-x-3 px-3 py-3 rounded-lg transition-all duration-200 ${
                    currentView === 'history' 
                    ? 'bg-slate-800 text-white shadow-md border-l-4 border-fs-primary' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                }`}
              >
                 <History className={`w-5 h-5 ${currentView === 'history' ? 'text-fs-primary' : ''}`} />
                 <span className="text-sm font-medium">History</span>
                 {recordings.length > 0 && (
                    <span className="ml-auto text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded-full">
                        {recordings.length}
                    </span>
                 )}
              </button>

              {notificationPermission === 'default' && (
                  <button 
                    onClick={handleEnableNotifications}
                    className="w-full flex items-center space-x-3 px-3 py-3 rounded-lg text-slate-400 hover:text-white hover:bg-slate-800/50 transition-all duration-200"
                  >
                     <Bell className="w-5 h-5" />
                     <span className="text-sm font-medium">Enable Alerts</span>
                  </button>
              )}
           </nav>
        </div>

        {/* User Profile Snippet */}
        <div className="p-4 bg-fs-darker border-t border-slate-800">
          <div className="flex items-center justify-between">
            {user ? (
                <>
                    <div className="flex items-center space-x-3 overflow-hidden">
                    <div className="w-8 h-8 rounded-full bg-slate-600 flex items-center justify-center text-white text-xs ring-2 ring-slate-700">
                        {user.email.substring(0,2).toUpperCase()}
                    </div>
                    <div className="flex flex-col min-w-0">
                        <span className="text-sm text-white truncate font-medium">{user.email.split('@')[0]}</span>
