/**
 * Helper: Generate consistent colors for speakers based on name hash.
 * This ensures that 'Speaker 1' always gets the same color across renders.
 */
const getSpeakerColor = (name: string) => {
  const colors = [
    'bg-blue-100 text-blue-700 border-blue-200',
    'bg-emerald-100 text-emerald-700 border-emerald-200',
    'bg-amber-100 text-amber-700 border-amber-200',
    'bg-purple-100 text-purple-700 border-purple-200',
    'bg-pink-100 text-pink-700 border-pink-200',
    'bg-indigo-100 text-indigo-700 border-indigo-200',
    'bg-cyan-100 text-cyan-700 border-cyan-200',
    'bg-rose-100 text-rose-700 border-rose-200',
  ];
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return colors[Math.abs(hash) % colors.length];
};

/**
 * Helper: Simple Markdown Parser for Bold and Italics.
 * Parses strings like "**Bold**" and "*Italic*" into React elements.
 */
const parseMarkdown = (text: string) => {
  // Split by bold (**...**)
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return parts.map((part, i) => {
    if (part.startsWith('**') && part.endsWith('**')) {
      return <strong key={i} className="font-bold text-slate-900">{part.slice(2, -2)}</strong>;
    }
    // Split by italic (*...*) inside non-bold parts
    const subParts = part.split(/(\*.*?\*)/g);
    return subParts.map((subPart, j) => {
       if (subPart.startsWith('*') && subPart.endsWith('*') && subPart.length > 2) {
         return <em key={`${i}-${j}`} className="italic text-slate-800">{subPart.slice(1, -1)}</em>;
       }
       return subPart;
    });
  });
};

export const RecordingList: React.FC<RecordingListProps> = ({ 
  recordings, 
  currentUser,
  onUpdateRecording,
  onShare
}) => {
  // State for playback
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);

  // State for editing title/notes
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNote, setEditNote] = useState('');

  // State for UI interactions
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Track which transcripts are fully expanded
  const [transcriptExpandedIds, setTranscriptExpandedIds] = useState<Set<string>>(new Set());

  // Clean up audio on unmount
  useEffect(() => {
    return () => {
      if (audioEl) {
        audioEl.pause();
        audioEl.src = '';
      }
    };
  }, [audioEl]);

  const handlePlay = async (recording: Recording) => {
    if (playingId === recording.id && audioEl) {
      audioEl.pause();
      setPlayingId(null);
      return;
    }

    if (audioEl) {
      audioEl.pause();
    }

    try {
      const blob = await getAudioBlob(recording.blobId);
      if (!blob) {
        alert("Audio file not found.");
        return;
      }

      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);

      audio.onended = () => setPlayingId(null);
      audio.play();

      setAudioEl(audio);
      setPlayingId(recording.id);
    } catch (e) {
      console.error("Error playing audio", e);
    }
  };

  const handleStartEdit = (rec: Recording) => {
    setEditingId(rec.id);
    setEditTitle(rec.title);
    setEditNote(rec.note);
    setExpandedId(rec.id);
  };

  const handleSaveEdit = (rec: Recording) => {
    onUpdateRecording({
      ...rec,
      title: editTitle,
      note: editNote
    });
    setEditingId(null);
  };

  const handleDownload = async (rec: Recording) => {
      try {
        const blob = await getAudioBlob(rec.blobId);
        if (blob) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.mp3`; 
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
      } catch (e) {
          console.error(e);
      }
  };

  const handleExportReport = (rec: Recording) => {
    const date = new Date(rec.timestamp).toLocaleDateString();
    const time = new Date(rec.timestamp).toLocaleTimeString();
    const duration = `${Math.floor(rec.duration / 60)} minutes ${rec.duration % 60} seconds`;

    let content = `FRONTSTEPS NOTE TAKER REPORT\n`;
    content += `==================================================\n`;
    content += `Title:    ${rec.title}\n`;
    content += `Date:     ${date} at ${time}\n`;
    content += `Duration: ${duration}\n`;
    content += `==================================================\n\n`;

    if (rec.note) {
        content += `NOTES\n`;
        content += `-----\n`;
        content += `${rec.note}\n\n`;
    }

    if (rec.transcription) {
        content += `TRANSCRIPT & AI INSIGHTS\n`;
        content += `------------------------\n`;
        content += `${rec.transcription}\n`;
    } else {
         content += `(No transcript available)\n`;
    }

    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_report.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCopyTranscript = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
        setCopiedId(id);
        setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const toggleTranscript = (id: string) => {
    setTranscriptExpandedIds(prev => {
        const next = new Set(prev);
        if (next.has(id)) {
            next.delete(id);
        } else {
            next.add(id);
        }
        return next;
    });
  };

  // Helper to render transcript with speaker labels and markdown
  const renderFormattedTranscript = (text: string) => {
      if (!text) return <span className="text-slate-400 italic">Transcript not available.</span>;

      // Split by newlines to handle paragraphs/lines
      const lines = text.split('\n');

      return (
          <div className="space-y-6">
              {lines.map((line, idx) => {
                  const trimmed = line.trim();
                  if (!trimmed) return null;

                  // Detect "Speaker Name:" pattern
                  // Matches "**Speaker Name:** Content" or "Speaker Name: Content"
                  // We look for a colon in the first 40 chars as a heuristic
                  const colonIndex = trimmed.indexOf(':');

                  if (colonIndex > 0 && colonIndex < 40) {
                      const rawSpeaker = trimmed.substring(0, colonIndex);
                      // Clean up markdown chars from speaker name (e.g. **Speaker**)
                      const speakerName = rawSpeaker.replace(/[\*\_]/g, '').trim();
                      const content = trimmed.substring(colonIndex + 1).trim();

                      // Generate initials
                      const initials = speakerName.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
                      const colorClass = getSpeakerColor(speakerName);

                      return (
                          <div key={idx} className="flex flex-row items-start gap-3 group">
                              <div className={`flex-shrink-0 mt-1 w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold border ${colorClass} shadow-sm select-none`}>
                                  {initials}
                              </div>
                              <div className="flex-1 min-w-0">
                                  <span className={`inline-block mb-1.5 px-2.5 py-0.5 rounded-md text-[11px] font-bold uppercase tracking-wider border ${colorClass}`}>
                                      {speakerName}
                                  </span>
                                  <p className="text-slate-700 leading-relaxed text-sm">
                                      {parseMarkdown(content)}
                                  </p>
                              </div>
                          </div>
                      );
                  }

                  // Default paragraph if no speaker detected
                  // Indent slightly to align better with text in speaker blocks
                  return (
                      <p key={idx} className="text-slate-700 leading-relaxed text-sm pl-0 sm:pl-12">
                          {parseMarkdown(trimmed)}
                      </p>
                  );
              })}
          </div>
      );
  };

  if (recordings.length === 0) {
    return (
        <div className="text-center py-12 px-4">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileText className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-medium text-slate-900">No recordings yet</h3>
            <p className="text-slate-500 max-w-sm mx-auto mt-2 mb-8">
                Tap the microphone button above to start recording your board meeting.
            </p>

            {/* Creative Microgame when list is empty */}
            <MusicalNotesGame />
        </div>
    );
  }

  const filteredRecordings = recordings.filter(rec => {
      const query = searchQuery.toLowerCase();
      const matchTitle = rec.title.toLowerCase().includes(query);
      const matchNote = rec.note && rec.note.toLowerCase().includes(query);
      const matchTranscript = rec.transcription && rec.transcription.toLowerCase().includes(query);

      return matchTitle || matchNote || matchTranscript;
  });

  return (
    <div className="space-y-6">
      {/* Search Bar */}
      <div className="relative max-w-md">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-slate-400" />
        </div>
        <input 
            type="text"
            placeholder="Search by title, notes, or transcript..."
            className="block w-full pl-10 pr-10 py-2.5 border border-slate-300 rounded-lg leading-5 bg-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-fs-primary/50 focus:border-fs-primary sm:text-sm transition-shadow shadow-sm"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
        />
        {searchQuery && (
            <button 
                onClick={() => setSearchQuery('')}
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600"
            >
                <X className="h-4 w-4" />
            </button>
        )}
      </div>

      {filteredRecordings.length === 0 ? (
          <div className="text-center py-12 bg-white rounded-lg border border-dashed border-slate-300">
              <Search className="w-8 h-8 mx-auto mb-2 text-slate-300" />
              <p className="text-slate-500 text-sm">No recordings found for "{searchQuery}"</p>
              <button 
                onClick={() => setSearchQuery('')}
                className="mt-2 text-fs-primary text-sm font-medium hover:underline"
              >
                  Clear search
              </button>
          </div>
      ) : (
          <div className="space-y-4">
            {filteredRecordings.map((rec) => {
                // Parse Action Items if present
                const parts = rec.transcription ? rec.transcription.split('### ACTION ITEMS') : [];
                const mainTranscript = parts[0] ? parts[0].trim() : '';
                const actionItems = parts[1] ? parts[1].trim() : null;
                const isTranscriptExpanded = transcriptExpandedIds.has(rec.id);

                // Determine if there is a match in the transcript for the current search query
                const query = searchQuery.toLowerCase();
                const matchInTranscript = query && rec.transcription && rec.transcription.toLowerCase().includes(query);

                return (
                <div key={rec.id} className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden transition-all duration-200 hover:shadow-lg hover:bg-slate-50 hover:border-slate-300">
                <div className="p-4">

                    {/* Header / Title */}
                    <div className="flex items-start justify-between mb-2">
                    <div className="flex-1 mr-4">
                        {editingId === rec.id ? (
                            <input 
                                type="text" 
                                value={editTitle}
                                onChange={(e) => setEditTitle(e.target.value)}
                                className="w-full text-lg font-semibold text-slate-900 border-b-2 border-fs-primary focus:outline-none bg-transparent"
                                autoFocus
                            />
                        ) : (
                            <h3 className="text-lg font-semibold text-slate-900 leading-tight">
                                {rec.title}
                            </h3>
                        )}
                        <div className="flex items-center text-xs text-slate-500 mt-1 space-x-3">
                            {/* Timestamp Formatting */}
                            <span className="flex items-center">
                                <Clock className="w-3 h-3 mr-1" />
                                {/* Display Date (e.g. Oct 24, 2023) */}
                                {new Date(rec.timestamp).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                                <span className="mx-1.5 opacity-50">|</span>
                                {/* Display Time (e.g. 2:30 PM) using local locale */}
                                {new Date(rec.timestamp).toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' })}
                            </span>
                            <span className="font-mono bg-slate-100 px-1.5 py-0.5 rounded">
                                {Math.floor(rec.duration / 60)}:{String(rec.duration % 60).padStart(2, '0')}
                            </span>
                        </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex items-center space-x-1">
                        {editingId === rec.id ? (
                            <button 
                                onClick={() => handleSaveEdit(rec)}
                                className="p-2 text-fs-primary hover:bg-emerald-50 rounded-full"
                            >
                                <Check className="w-5 h-5" />
                            </button>
                        ) : (
                            <button 
                                onClick={() => handleStartEdit(rec)}
                                className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full"
                            >
                                <Edit2 className="w-4 h-4" />
                            </button>
                        )}
                    </div>
                    </div>

                    {/* Notes Section */}
                    {(expandedId === rec.id || rec.note) && (
                        <div className="mt-3 bg-slate-50 rounded p-3 text-sm">
                            <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide mb-1">Notes</h4>
                            {editingId === rec.id ? (
                                <textarea 
                                    value={editNote}
                                    onChange={(e) => setEditNote(e.target.value)}
                                    placeholder="Add meeting notes, agenda items, or action points..."
                                    className="w-full bg-transparent focus:outline-none min-h-[60px] text-slate-700 resize-none"
                                />
                            ) : (
                                <p className="text-slate-600 whitespace-pre-wrap">
                                    {rec.note || <span className="text-slate-400 italic">No notes added.</span>}
                                </p>
                            )}
                        </div>
                    )}

                    {/* AI Insights & Transcription */}
                    {(expandedId === rec.id || rec.transcription || rec.isTranscribing) && (
                        <div className="mt-4 border-t border-slate-100 pt-3">
                            {/* Action Items Highlight */}
                            {actionItems && (
                                <div className="mb-4 bg-amber-50 border border-amber-200 rounded-md p-3">
                                    <div className="flex items-center mb-2">
                                        <ListChecks className="w-4 h-4 text-amber-600 mr-2" />
                                        <h4 className="text-xs font-bold text-amber-800 uppercase tracking-wide">Action Items</h4>
                                    </div>
                                    <div className="text-amber-900 text-sm whitespace-pre-wrap pl-6">
                                        {actionItems}
                                    </div>
                                </div>
                            )}

                            {/* Transcript Header & Toggle */}
                            <div 
                                className="flex items-center justify-between cursor-pointer py-2 hover:bg-slate-50 rounded transition-colors"
                                onClick={() => toggleTranscript(rec.id)}
                            >
                                <div className="flex items-center">
                                <Sparkles className="w-3 h-3 text-purple-500 mr-2" />
                                <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wide">Transcript</h4>
                                {matchInTranscript && !isTranscriptExpanded && (
                                    <span className="ml-2 px-1.5 py-0.5 bg-yellow-100 text-yellow-800 text-[10px] font-bold uppercase rounded-full">
                                        Match
                                    </span>
                                )}
                                </div>
                                <div className="flex items-center space-x-2">
                                    {rec.transcription && !rec.isTranscribing && isTranscriptExpanded && (
                                        <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleCopyTranscript(rec.transcription!, rec.id);
                                                }}
                                                className="flex items-center text-xs text-slate-400 hover:text-fs-primary transition-colors mr-2"
                                                title="Copy transcript"
                                        >
                                            {copiedId === rec.id ? <Check className="w-3 h-3 mr-1" /> : <Copy className="w-3 h-3 mr-1" />}
                                            {copiedId === rec.id ? 'Copied' : 'Copy'}
                                        </button>
                                    )}
                                    {isTranscriptExpanded ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
                                </div>
                            </div>

                            {/* Collapsible Transcript Body */}
                            {rec.isTranscribing ? (
                                <div className="flex items-center space-x-2 text-slate-500 py-3 px-2 bg-slate-50/50 rounded animate-pulse">
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                    <span className="text-sm italic">Generating transcript...</span>
                                </div>
                            ) : (
                                isTranscriptExpanded && (
                                    <div className="mt-2 bg-white p-3 sm:p-4 rounded-lg border border-slate-100 shadow-inner bg-slate-50/30">
                                        {renderFormattedTranscript(mainTranscript)}
                                    </div>
                                )
                            )}
                        </div>
                    )}

                    {/* Expanded Controls for non-editing state */}
                    {editingId !== rec.id && (
                        <div className="mt-4 flex items-center justify-between border-t border-slate-100 pt-3">
                            <button 
                                onClick={() => handlePlay(rec)}
                                className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                    playingId === rec.id 
                                    ? 'bg-slate-900 text-white' 
                                    : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                                }`}
                            >
                                {playingId === rec.id ? <Pause className="w-4 h-4 mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                                {playingId === rec.id ? 'Pause' : 'Play'}
                            </button>

                            <div className="flex space-x-2">
                                <button 
                                    onClick={() => handleDownload(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                                    title="Download MP3"
                                >
                                    <Download className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => handleExportReport(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md"
                                    title="Export Transcript & Notes"
                                >
                                    <FileDown className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => onShare(rec)}
                                    disabled={rec.status === 'shared'}
                                    className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                        rec.status === 'shared'
                                        ? 'bg-green-100 text-green-700 cursor-default'
                                        : 'bg-fs-primary text-white hover:bg-emerald-600 shadow-sm'
                                    }`}
                                >
                                    {rec.status === 'shared' ? (
                                        <>
                                            <Check className="w-4 h-4 mr-2" />
                                            Shared to ALLi
                                        </>
                                    ) : (
                                        <>
                                            <Share2 className="w-4 h-4 mr-2" />
                                            Share to ALLi
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>
                    )}

                </div>
                </div>
                );
            })}
          </div>
      )}
    </div>
  );
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

/**
 * Entry Point
 * 
 * Mounts the React application to the DOM.
 * Utilizes React.StrictMode to highlight potential problems in the application.
 */

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

/**
 * Application Type Definitions
 * 
 * Contains shared interfaces and enums for the domain model.
 */

// User Roles determine access levels within the app and the mocked downstream systems (ALLi)
export enum UserRole {
  BOARD_MEMBER = 'board_member', // Can record and vote
  MANAGER = 'manager'            // Admin oversight
}

// Represents the currently authenticated user session
export interface User {
  email: string;
  role: UserRole;
  isAuthenticated: boolean;
}

// Core Recording Entity
// Note: The actual audio binary is stored in IndexedDB (blobId), 
// while this metadata object is stored in LocalStorage.
export interface Recording {
  id: string;             // Unique UUID
  title: string;          // User-editable title
  timestamp: string;      // ISO String creation date
  duration: number;       // Length in seconds
  note: string;           // User annotations
  blobId: string;         // Reference key for IndexedDB storage
  status: 'ready' | 'uploading' | 'shared'; // Workflow state
  transcription?: string; // AI-generated text
  isTranscribing?: boolean; // UI loading state for AI processing
}

// State interface for the Authentication UI flow
export interface AuthState {
  step: 'email' | 'code' | 'authenticated';
  email: string;
  loading: boolean;
  error?: string;
}

// Web Audio API context wrapper types
export interface AudioContextType {
  isRecording: boolean;
  recordingTime: number;
  analyserData: Uint8Array | null;
}

/**
 * IndexedDB Service
 * 
 * We use IndexedDB to store audio Blobs because LocalStorage has a strict quota (usually 5-10MB),
 * which is insufficient for audio recordings. IndexedDB allows storing large binary objects asynchronously.
 */

const DB_NAME = 'frontsteps_notes_db';
const STORE_NAME = 'audio_blobs';
const DB_VERSION = 1;

/**
 * Opens a connection to the browser's IndexedDB.
 * Handles schema upgrades (creating object stores) if the version changes.
 */
export const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME);
      }
    };

    request.onsuccess = (event) => {
      resolve((event.target as IDBOpenDBRequest).result);
    };

    request.onerror = (event) => {
      reject((event.target as IDBOpenDBRequest).error);
    };
  });
};

/**
 * Saves an audio Blob to the database.
 * @param id - Unique identifier for the blob (referenced in Recording metadata).
 * @param blob - The audio file data.
 */
export const saveAudioBlob = async (id: string, blob: Blob): Promise<void> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_NAME], 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.put(blob, id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

/**
 * Retrieves an audio Blob by its ID.
 */
export const getAudioBlob = async (id: string): Promise<Blob | undefined> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_NAME], 'readonly');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.get(id);

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

/**
 * Deletes an audio Blob.
 * Should be called when a recording is deleted from the UI to clean up storage.
 */
export const deleteAudioBlob = async (id: string): Promise<void> => {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_NAME], 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.delete(id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

import { Recording, User } from '../types';

/**
 * Storage Service (LocalStorage)
 * 
 * Handles persistence of lightweight metadata (JSON) such as:
 * - List of recordings (titles, timestamps, notes, blob IDs).
 * - User session information.
 * 
 * Note: Actual audio data is NOT stored here; it lives in IndexedDB via dbService.ts.
 */

const RECORDINGS_KEY = 'frontsteps_recordings_meta';
const USER_KEY = 'frontsteps_user_session';

/**
 * Retrieves the list of recording metadata.
 */
export const getRecordingsMeta = (): Recording[] => {
  try {
    const data = localStorage.getItem(RECORDINGS_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    console.error("Failed to load recordings", e);
    return [];
  }
};

/**
 * Saves the list of recording metadata.
 */
export const saveRecordingsMeta = (recordings: Recording[]): void => {
  localStorage.setItem(RECORDINGS_KEY, JSON.stringify(recordings));
};

/**
 * Retrieves the active user session if one exists.
 */
export const getUserSession = (): User | null => {
  try {
    const data = localStorage.getItem(USER_KEY);
    return data ? JSON.parse(data) : null;
  } catch (e) {
    return null;
  }
};

/**
 * Persists the user session.
 */
export const saveUserSession = (user: User): void => {
  localStorage.setItem(USER_KEY, JSON.stringify(user));
};

/**
 * Clears the user session (Logout).
 */
export const clearUserSession = (): void => {
  localStorage.removeItem(USER_KEY);
};

import { GoogleGenAI } from "@google/genai";

/**
 * AI Service
 * 
 * Integrates with Google's Gemini API to provide transcription and summarization features.
 * This service handles converting browser Blobs to Base64 (required by the API) and
 * constructing the prompt context.
 */

// Helper: Converts a binary Blob to a Base64 string for API consumption.
const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') {
        // Remove data URL prefix (e.g., "data:audio/webm;base64,") to get raw base64
        const base64 = reader.result.split(',')[1];
        resolve(base64);
      } else {
        reject(new Error('Failed to convert blob to base64'));
      }
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

/**
 * Sends audio to Gemini for transcription.
 * 
 * Uses 'gemini-2.5-flash' which is optimized for speed and cost, making it ideal
 * for near-real-time feedback on mobile devices.
 * 
 * @param audioBlob - The recorded audio file
 * @returns The generated transcript text
 */
export const transcribeAudio = async (audioBlob: Blob): Promise<string> => {
  try {
    // API Key is injected via environment variables at build time
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const base64Data = await blobToBase64(audioBlob);

    // Determine mime type from blob if possible, default to webm (common for MediaRecorder)
    const mimeType = audioBlob.type || 'audio/webm';

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          {
            text: "Transcribe this board meeting audio."
          }
        ]
      },
      // System instructions guide the model's persona and formatting rules.
      config: {
        systemInstruction: "You are an expert transcriber and minute-taker for HOA board meetings. Your goal is to provide a highly accurate, speaker-diarized transcript.\n\nRules:\n1. Identify different speakers based on voice, tone, and context. Label them clearly (e.g., 'Speaker 1:', 'Speaker 2:', or by name if mentioned).\n2. Format the output as a script with clear line breaks between speakers.\n3. Remove non-essential filler words (um, uh) to keep it professional.\n4. CRITICAL: At the very end, analyze the content for tasks, votes, and decisions. Add a section titled '### ACTION ITEMS' and list them as bullet points. If none, omit this section.",
      }
    });

    return response.text || "No transcription generated.";
  } catch (error) {
    console.error("Transcription failed:", error);
    return "Transcription failed. Please try again later.";
  }
};

/**
 * Notification Service
 * 
 * Encapsulates the logic for requesting permissions and sending system-level notifications.
 * This is used to alert the user when long-running tasks (like transcription) complete,
 * even if the user has switched tabs.
 */

export const requestNotificationPermission = async (): Promise<boolean> => {
  // Check if browser supports notifications
  if (!('Notification' in window)) {
    console.warn('Notifications not supported in this browser');
    return false;
  }

  if (Notification.permission === 'granted') {
    return true;
  }

  try {
    const permission = await Notification.requestPermission();
    return permission === 'granted';
  } catch (e) {
    console.error('Error requesting notification permission:', e);
    return false;
  }
};

export const sendNotification = (title: string, body: string) => {
  if (!('Notification' in window)) return;

  if (Notification.permission === 'granted') {
    try {
      new Notification(title, {
        body,
        icon: '/vite.svg', // Uses the app icon
        silent: false,
      });
    } catch (e) {
      console.error('Error sending notification:', e);
    }
  }
};

export const getNotificationPermission = (): NotificationPermission | 'unsupported' => {
  if (!('Notification' in window)) return 'unsupported';
  return Notification.permission;
};

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SignalHigh, Play, Pause, Trash2, Check, RotateCcw, X, Upload } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string, note: string) => void;
}

/**
 * Recorder Component
 * 
 * Handles the core recording functionality using the MediaRecorder API.
 * 
 * Key features:
 * 1. Audio Capture: Captures microphone input.
 * 2. Visualization: Uses Web Audio API (AnalyserNode) to draw a frequency bar graph on a canvas.
 * 3. File Upload: Allows users to upload pre-recorded files if they don't want to record live.
 * 4. State Management: Manages transitions between 'recording', 'preview', and 'processing' states.
 */
export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete }) => {
  // --- State: Recording ---
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0); // Tracks seconds elapsed

  // --- State: Preview/Playback ---
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0); // For seek bar
  const [note, setNote] = useState(''); 
  const [uploadedFileName, setUploadedFileName] = useState<string | null>(null);

  // --- State: Processing ---
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Refs: Audio Infrastructure ---
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]); // Accumulates audio data chunks
  const audioRef = useRef<HTMLAudioElement | null>(null); // For preview playback
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Refs: Visualizer ---
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  /**
   * Initializes the MediaStream and MediaRecorder.
   * Handles browser permission errors gracefully.
   */
  const startRecording = async () => {
    setError(null);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setCurrentTime(0);
    setDuration(0);
    setNote('');

    // Feature detection
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Audio recording is not supported in this browser. Please use a modern browser.");
        return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Prefer webm, fallback to mp4
      const mimeType = MediaRecorder.isTypeSupported('audio/webm')
        ? 'audio/webm'
        : 'audio/mp4';

      let recorder;
      try {
         recorder = new MediaRecorder(stream, { mimeType });
      } catch (e) {
         stream.getTracks().forEach(t => t.stop());
         streamRef.current = null;
         setError("Failed to create MediaRecorder. Your browser might not support the selected audio format.");
         return;
      }

      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      // Collect data chunks as they become available
      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      // Finalize recording on stop
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const url = URL.createObjectURL(blob);
        setRecordedBlob(blob);
        setAudioUrl(url);
        setIsRecording(false);

        // Release hardware resources
        streamRef.current?.getTracks().forEach(track => track.stop());
        streamRef.current = null;

        if (timerIntervalRef.current) {
            clearInterval(timerIntervalRef.current);
            timerIntervalRef.current = null;
        }
      };

      recorder.start();
      setIsRecording(true);

      // Start duration timer
      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => {
        setDuration(Math.floor((Date.now() - startTime) / 1000));
      }, 1000);

    } catch (err: any) {
      console.error("Microphone access error:", err);

      // Cleanup if stream was opened but error occurred later
      if (streamRef.current) {
         streamRef.current.getTracks().forEach(t => t.stop());
         streamRef.current = null;
      }

      // Provide user-friendly error messages
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setError("Access denied. Please enable microphone permissions in your browser settings.");
      } else if (err.name === 'NotFoundError') {
        setError("No microphone found.");
      } else {
        setError(`Could not start recording: ${err.message || "Unknown error"}.`);
      }
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      // Logic continues in onstop event handler above
    }
  };

  const cancelRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      // Prevent onstop from triggering a save flow
      mediaRecorderRef.current.onstop = null;
      mediaRecorderRef.current.stop();

      if (streamRef.current) {
         streamRef.current.getTracks().forEach(track => track.stop());
         streamRef.current = null;
      }

      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
      }

      setIsRecording(false);
      setDuration(0);
      setNote('');
      setError(null);
    }
  };

  const handleUploadClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
        setError(null);
        setRecordedBlob(file);
        const url = URL.createObjectURL(file);
        setAudioUrl(url);
        setUploadedFileName(file.name);
        setCurrentTime(0);
        setDuration(0); // Will be updated by audio.onloadedmetadata
        setNote('');
        setIsRecording(false);
    }
  };

  const handleDiscard = () => {
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setDuration(0);
    setCurrentTime(0);
    setIsPlaying(false);
    setNote('');
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  /**
   * Saves the recording to IndexedDB and triggers the parent completion handler.
   */
  const handleSave = async () => {
    if (!recordedBlob) return;

    setIsProcessing(true);
    const blobId = `rec_${Date.now()}`;

    try {
        // Persist blob to IndexedDB
        await saveAudioBlob(blobId, recordedBlob);

        const now = new Date();
        let defaultName = `Board Meeting ${now.toLocaleDateString()}`;

        if (uploadedFileName) {
            defaultName = uploadedFileName.replace(/\.[^/.]+$/, "");
        }

        // Cleanup URL
        if (audioUrl) URL.revokeObjectURL(audioUrl);
        setRecordedBlob(null);
        setAudioUrl(null);
        setUploadedFileName(null);

        onRecordingComplete(blobId, duration, defaultName, note);
    } catch (err) {
        setError("Failed to save recording. Storage might be full.");
        console.error(err);
    } finally {
        setIsProcessing(false);
        setDuration(0);
        setNote('');
    }
  };

  // --- Visualizer Effect ---
  // Connects the audio stream to a canvas analyser when recording starts
  useEffect(() => {
    if (isRecording && streamRef.current && canvasRef.current) {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const audioCtx = new AudioContextClass();
        const analyser = audioCtx.createAnalyser();
        const source = audioCtx.createMediaStreamSource(streamRef.current);

        source.connect(analyser);
        analyser.fftSize = 256; 
        analyser.smoothingTimeConstant = 0.5;

        audioContextRef.current = audioCtx;
        analyserRef.current = analyser;

        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Retina display scaling
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
        ctx.scale(dpr, dpr);

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        // Animation Loop
        const draw = () => {
            animationFrameRef.current = requestAnimationFrame(draw);
            analyser.getByteFrequencyData(dataArray);

            ctx.clearRect(0, 0, rect.width, rect.height);

            // Draw configuration
            const bars = 24; 
            const gap = 4;
            const totalGapSpace = (bars - 1) * gap;
            const availableWidth = rect.width * 0.8;
            const barWidth = (availableWidth - totalGapSpace) / bars;
            const startX = (rect.width - availableWidth) / 2;

            // Downsample the frequency data to fit the number of bars
            const step = Math.floor((bufferLength / 2) / bars);

            for (let i = 0; i < bars; i++) {
                let sum = 0;
                for (let j = 0; j < step; j++) {
                    sum += dataArray[(i * step) + j];
                }
                const avg = sum / step;

                const barHeight = Math.max(4, (avg / 255) * rect.height * 0.9);
                const x = startX + (i * (barWidth + gap));
                const y = (rect.height - barHeight) / 2;

                ctx.fillStyle = '#ef4444'; // Red-500

                ctx.beginPath();
                if (typeof ctx.roundRect === 'function') {
                    ctx.roundRect(x, y, barWidth, barHeight, 4);
                } else {
                    ctx.rect(x, y, barWidth, barHeight);
                }
                ctx.fill();
            }
        };

        draw();

        return () => {
            if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
            if (audioCtx.state !== 'closed') audioCtx.close();
        };
    }
  }, [isRecording]);

  // --- Audio Preview Playback Logic ---
  useEffect(() => {
    if (audioUrl) {
        const audio = new Audio(audioUrl);
        audioRef.current = audio;

        audio.onloadedmetadata = () => {
            if (audio.duration && !isNaN(audio.duration) && audio.duration !== Infinity) {
                setDuration(audio.duration);
            }
        };

        audio.ontimeupdate = () => {
            setCurrentTime(audio.currentTime);
        };

        audio.onended = () => {
            setIsPlaying(false);
            setCurrentTime(0);
        };

        return () => {
            audio.pause();
            audioRef.current = null;
        };
    }
  }, [audioUrl]);

  const togglePlay = () => {
    if (audioRef.current) {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
      const time = parseFloat(e.target.value);
      if (audioRef.current) {
          audioRef.current.currentTime = time;
          setCurrentTime(time);
      }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Global Cleanup
  useEffect(() => {
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (audioUrl) URL.revokeObjectURL(audioUrl);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
    };
  }, []);

  return (
    <div className="w-full relative group">
        <input 
            type="file" 
            accept="audio/*" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            className="hidden" 
        />

        {/* Main Card */}
        <div className={`relative w-full max-w-lg mx-auto bg-white rounded-3xl shadow-2xl transition-all duration-500 overflow-hidden border border-slate-100 ${isRecording ? 'shadow-fs-primary/20 scale-[1.02]' : 'shadow-slate-200/50'}`}>

            {/* Header Status Bar Indicator */}
            <div className={`absolute top-0 left-0 right-0 h-1.5 transition-colors duration-500 ${isRecording ? 'bg-red-500' : (recordedBlob ? 'bg-fs-primary' : 'bg-transparent')}`} />

            {/* Content Area */}
            <div className="p-8 md:p-12 flex flex-col items-center justify-center min-h-[360px]">

                {!recordedBlob ? (
                    /* RECORDING STATE UI */
                    <>
                        <div className="h-24 w-full flex items-center justify-center mb-6">
                            {isRecording ? (
                                <canvas ref={canvasRef} className="w-full h-full max-w-[300px]" />
                            ) : (
                                <div className="flex flex-col items-center justify-center text-slate-300">
                                    <div className="w-20 h-20 rounded-full border-4 border-slate-100 flex items-center justify-center mb-2">
                                        <SignalHigh className="w-10 h-10" />
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="flex flex-col items-center mb-8">
                            <div className={`text-6xl font-mono font-bold tracking-wider tabular-nums transition-colors duration-300 ${isRecording ? 'text-slate-800' : 'text-slate-300'}`}>
                                {formatTime(duration)}
                            </div>
                            {isRecording && (
                                <div className="flex items-center mt-3 text-red-500 font-medium text-sm animate-pulse">
                                    <div className="w-2 h-2 bg-red-500 rounded-full mr-2" />
                                    Recording in progress
                                </div>
                            )}
                        </div>

                        <div className="relative">
                            {isRecording && (
                                <div className="absolute inset-0 rounded-full border border-red-200 animate-ping opacity-75 scale-150 pointer-events-none" />
                            )}

                            {!isRecording ? (
                                <button 
                                    onClick={startRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-fs-primary hover:bg-emerald-600 text-white shadow-lg hover:shadow-xl hover:shadow-emerald-500/30 transition-all duration-300 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-emerald-100"
                                >
                                    <Mic className="w-10 h-10" />
                                </button>
                            ) : (
                                <button 
                                    onClick={stopRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-white border-4 border-red-500 hover:bg-red-50 text-red-500 shadow-lg transition-all duration-200 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-red-100"
                                >
                                    <Square className="w-8 h-8 fill-current" />
                                </button>
                            )}
                        </div>

                        {/* Upload Button */}
                        {!isRecording && (
                             <div className="mt-8 flex flex-col items-center">
                                <span className="text-slate-400 text-xs mb-2">- OR -</span>
                                <button 
                                    onClick={handleUploadClick}
                                    className="flex items-center text-slate-600 hover:text-fs-primary transition-colors text-sm font-medium bg-white hover:bg-slate-50 px-5 py-2.5 rounded-full border border-slate-200 shadow-sm"
                                >
                                    <Upload className="w-4 h-4 mr-2" />
                                    Upload Audio File
                                </button>
                             </div>
                        )}

                        {/* Cancel Button */}
                        {isRecording && (
                             <button 
                                onClick={cancelRecording}
                                className="mt-8 flex items-center text-slate-400 hover:text-slate-600 px-4 py-2 rounded-full hover:bg-slate-100 transition-all duration-200 text-sm font-medium animate-in fade-in slide-in-from-top-2"
                             >
                                <X className="w-4 h-4 mr-2" />
                                Cancel
                             </button>
                        )}
                    </>
                ) : (
                    /* PREVIEW STATE UI */
                    <div className="w-full flex flex-col items-center animate-in fade-in duration-300">
                         <h3 className="text-lg font-semibold text-slate-700 mb-6">Preview Recording</h3>

                         {/* Playback Controls */}
                         <div className="w-full max-w-xs mb-6">
                            <div className="flex justify-between text-xs text-slate-500 font-mono mb-2 px-1">
                                <span>{formatTime(currentTime)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>
                            <input 
                                type="range"
                                min="0"
                                max={duration}
                                step="0.1"
                                value={currentTime}
                                onChange={handleSeek}
                                className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-fs-primary focus:outline-none focus:ring-2 focus:ring-fs-primary/30"
                            />
                         </div>

                         {/* Notes Input */}
                         <div className="w-full max-w-xs mb-8">
                             <label className="block text-xs font-medium text-slate-500 mb-1 uppercase tracking-wide">
                                 Meeting Notes (Optional)
                             </label>
                             <textarea
                                 value={note}
                                 onChange={(e) => setNote(e.target.value)}
                                 placeholder="Add context, agenda items, or quick notes..."
                                 className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-fs-primary/50 resize-none h-24 transition-all"
                             />
                         </div>

                         <div className="flex items-center justify-center space-x-6">
                            {/* Discard Button */}
                            <button 
                                onClick={handleDiscard} 
                                disabled={isProcessing}
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
                                title="Discard"
                            >
                                <Trash2 className="w-6 h-6 mb-1" />
                                <span className="text-[10px] font-medium uppercase tracking-wide">Discard</span>
                            </button>

                            {/* Play/Pause Button */}
                            <button 
                                onClick={togglePlay} 
                                className="w-20 h-20 bg-fs-dark text-white rounded-full flex items-center justify-center hover:bg-slate-800 shadow-xl shadow-slate-900/20 transition-transform hover:scale-105"
                            >
                                {isPlaying ? <Pause className="w-8 h-8 fill-current" /> : <Play className="w-8 h-8 fill-current ml-1" />}
                            </button>

                            {/* Save Button */}
                            <button 
                                onClick={handleSave} 
                                disabled={isProcessing} 
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-fs-primary hover:bg-emerald-50 transition-all"
                                title="Save"
                            >
                                {isProcessing ? (
                                    <Loader2 className="w-6 h-6 animate-spin mb-1" />
                                ) : (
                                    <Check className="w-6 h-6 mb-1" />
                                )}
                                <span className="text-[10px] font-medium uppercase tracking-wide">{isProcessing ? 'Saving' : 'Save'}</span>
                            </button>
                         </div>
                    </div>
                )}
            </div>

            {/* Footer Hints */}
            {!isRecording && !isProcessing && !recordedBlob && (
                 <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Ready to capture
                    </p>
                 </div>
            )}

            {recordedBlob && !isProcessing && (
                <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Review before saving
                    </p>
                 </div>
            )}
        </div>

        {/* Error Toast */}
        {error && (
            <div className="absolute -bottom-20 left-0 right-0 flex justify-center px-4 z-50">
                <div className="bg-red-50 text-red-800 px-4 py-3 rounded-xl text-sm font-medium shadow-lg border border-red-200 animate-in slide-in-from-bottom-2 fade-in duration-300 max-w-sm text-center flex items-center">
                    <span className="mr-2 text-xl">⚠️</span>
                    {error}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState } from 'react';
import { User, UserRole } from '../types';
