interface AuthScreenProps {
  onLogin: (user: User) => void;
  onCancel: () => void;
}

/**
 * Auth Screen Component
 * 
 * Provides a mock "Passwordless" login flow (Email -> OTP).
 * In a production app, this would integrate with an Identity Provider (IdP) like WorkOS or Auth0.
 * 
 * Flow:
 * 1. User enters email.
 * 2. System simulates sending an OTP (Loading state).
 * 3. User enters mock OTP (any code works in this demo).
 * 4. User is authenticated and assigned a role based on email pattern.
 */
export const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin, onCancel }) => {
  const [step, setStep] = useState<'email' | 'code'>('email');
  const [email, setEmail] = useState('');
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSendCode = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;
    setLoading(true);
    // Simulate API network delay
    await new Promise(resolve => setTimeout(resolve, 1500));
    setLoading(false);
    setStep('code');
  };

  const handleVerifyCode = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!code) return;
    setLoading(true);
    // Simulate API network delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Simulate backend role assignment logic
    // For demo purposes: containing 'manager' makes you a manager
    const determinedRole = email.toLowerCase().includes('manager') 
        ? UserRole.MANAGER 
        : UserRole.BOARD_MEMBER;

    // Create the session object
    const user: User = {
        email,
        role: determinedRole,
        isAuthenticated: true
    };

    setLoading(false);
    onLogin(user);
  };

  return (
    <div className="fixed inset-0 z-50 min-h-screen bg-fs-dark/95 backdrop-blur-sm flex flex-col items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-2xl overflow-hidden relative">

        {/* Close Button */}
        <button 
          onClick={onCancel}
          className="absolute top-4 right-4 p-2 text-slate-400 hover:text-white hover:bg-slate-800/50 rounded-full transition-colors z-10"
          title="Cancel login"
        >
          <X className="w-5 h-5" />
        </button>

        {/* Branding Header */}
        <div className="bg-fs-darker p-8 text-center border-b border-slate-800">
             <div className="flex justify-center mb-4">
                 <div className="h-12 w-12 bg-gradient-to-br from-fs-primary to-emerald-600 rounded-xl flex items-center justify-center text-white font-bold text-3xl shadow-lg shadow-fs-primary/20 mb-2">
                   <span className="font-sans">F</span>
                 </div>
             </div>
             <div className="flex flex-col items-center justify-center">
                <span className="text-2xl font-bold text-white tracking-tight">FRONTST<span className="text-fs-primary">Ξ</span>PS</span>
