import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SignalHigh, Play, Pause, Trash2, Check, RotateCcw, X, Upload, Globe, ChevronDown } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string, note: string, language: string) => void;
}

const LANGUAGES = [
    { code: 'English', label: 'English' },
    { code: 'Spanish', label: 'Spanish' },
    { code: 'French', label: 'French' },
    { code: 'German', label: 'German' },
    { code: 'Portuguese', label: 'Portuguese' },
    { code: 'Chinese', label: 'Chinese' },
];

/**
 * Recorder Component
 * 
 * Handles the core recording functionality using the MediaRecorder API.
 * 
 * Key features:
 * 1. Audio Capture: Captures microphone input.
 * 2. Visualization: Uses Web Audio API (AnalyserNode) to draw a frequency bar graph on a canvas.
 * 3. File Upload: Allows users to upload pre-recorded files if they don't want to record live.
 * 4. State Management: Manages transitions between 'recording', 'preview', and 'processing' states.
 */
export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete }) => {
  // --- State: Recording ---
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0); // Tracks seconds elapsed

  // --- State: Preview/Playback ---
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0); // For seek bar
  const [note, setNote] = useState(''); 
  const [uploadedFileName, setUploadedFileName] = useState<string | null>(null);
  const [language, setLanguage] = useState('English');

  // --- State: Processing ---
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Refs: Audio Infrastructure ---
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]); // Accumulates audio data chunks
  const audioRef = useRef<HTMLAudioElement | null>(null); // For preview playback
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Refs: Visualizer ---
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  /**
   * Initializes the MediaStream and MediaRecorder.
   * Handles browser permission errors gracefully.
   */
  const startRecording = async () => {
    setError(null);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setCurrentTime(0);
    setDuration(0);
    setNote('');

    // Feature detection
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Audio recording is not supported in this browser. Please use a modern browser.");
        return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Prefer webm, fallback to mp4
      const mimeType = MediaRecorder.isTypeSupported('audio/webm')
        ? 'audio/webm'
        : 'audio/mp4';

      let recorder;
      try {
         recorder = new MediaRecorder(stream, { mimeType });
      } catch (e) {
         stream.getTracks().forEach(t => t.stop());
         streamRef.current = null;
         setError("Failed to create MediaRecorder. Your browser might not support the selected audio format.");
         return;
      }

      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      // Collect data chunks as they become available
      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      // Finalize recording on stop
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const url = URL.createObjectURL(blob);
        setRecordedBlob(blob);
        setAudioUrl(url);
        setIsRecording(false);

        // Release hardware resources
        streamRef.current?.getTracks().forEach(track => track.stop());
        streamRef.current = null;

        if (timerIntervalRef.current) {
            clearInterval(timerIntervalRef.current);
            timerIntervalRef.current = null;
        }
      };

      recorder.start();
      setIsRecording(true);

      // Start duration timer
      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => {
        setDuration(Math.floor((Date.now() - startTime) / 1000));
      }, 1000);

    } catch (err: any) {
      console.error("Microphone access error:", err);

      // Cleanup if stream was opened but error occurred later
      if (streamRef.current) {
         streamRef.current.getTracks().forEach(t => t.stop());
         streamRef.current = null;
      }

      // Provide user-friendly error messages
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setError("Access denied. Please enable microphone permissions in your browser settings.");
      } else if (err.name === 'NotFoundError') {
        setError("No microphone found.");
      } else {
        setError(`Could not start recording: ${err.message || "Unknown error"}.`);
      }
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      // Logic continues in onstop event handler above
    }
  };

  const cancelRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      // Prevent onstop from triggering a save flow
      mediaRecorderRef.current.onstop = null;
      mediaRecorderRef.current.stop();

      if (streamRef.current) {
         streamRef.current.getTracks().forEach(track => track.stop());
         streamRef.current = null;
      }

      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
      }

      setIsRecording(false);
      setDuration(0);
      setNote('');
      setError(null);
    }
  };

  const handleUploadClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
        setError(null);
        setRecordedBlob(file);
        const url = URL.createObjectURL(file);
        setAudioUrl(url);
        setUploadedFileName(file.name);
        setCurrentTime(0);
        setDuration(0); // Will be updated by audio.onloadedmetadata
        setNote('');
        setIsRecording(false);
    }
  };

  const handleDiscard = () => {
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setDuration(0);
    setCurrentTime(0);
    setIsPlaying(false);
    setNote('');
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  /**
   * Saves the recording to IndexedDB and triggers the parent completion handler.
   */
  const handleSave = async () => {
    if (!recordedBlob) return;

    setIsProcessing(true);
    const blobId = `rec_${Date.now()}`;

    try {
        // Persist blob to IndexedDB
        await saveAudioBlob(blobId, recordedBlob);

        const now = new Date();
        let defaultName = `Board Meeting ${now.toLocaleDateString()}`;

        if (uploadedFileName) {
            defaultName = uploadedFileName.replace(/\.[^/.]+$/, "");
        }

        // Cleanup URL
        if (audioUrl) URL.revokeObjectURL(audioUrl);
        setRecordedBlob(null);
        setAudioUrl(null);
        setUploadedFileName(null);

        onRecordingComplete(blobId, duration, defaultName, note, language);
    } catch (err) {
        setError("Failed to save recording. Storage might be full.");
        console.error(err);
    } finally {
        setIsProcessing(false);
        setDuration(0);
        setNote('');
    }
  };

  // --- Visualizer Effect ---
  // Connects the audio stream to a canvas analyser when recording starts
  useEffect(() => {
    if (isRecording && streamRef.current && canvasRef.current) {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const audioCtx = new AudioContextClass();
        const analyser = audioCtx.createAnalyser();
        const source = audioCtx.createMediaStreamSource(streamRef.current);

        source.connect(analyser);
        analyser.fftSize = 256; 
        analyser.smoothingTimeConstant = 0.5;

        audioContextRef.current = audioCtx;
        analyserRef.current = analyser;

        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Retina display scaling
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
        ctx.scale(dpr, dpr);

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        // Animation Loop
        const draw = () => {
            animationFrameRef.current = requestAnimationFrame(draw);
            analyser.getByteFrequencyData(dataArray);

            ctx.clearRect(0, 0, rect.width, rect.height);

            // Draw configuration
            const bars = 24; 
            const gap = 4;
            const totalGapSpace = (bars - 1) * gap;
            const availableWidth = rect.width * 0.8;
            const barWidth = (availableWidth - totalGapSpace) / bars;
            const startX = (rect.width - availableWidth) / 2;

            // Downsample the frequency data to fit the number of bars
            const step = Math.floor((bufferLength / 2) / bars);

            for (let i = 0; i < bars; i++) {
                let sum = 0;
                for (let j = 0; j < step; j++) {
                    sum += dataArray[(i * step) + j];
                }
                const avg = sum / step;

                const barHeight = Math.max(4, (avg / 255) * rect.height * 0.9);
                const x = startX + (i * (barWidth + gap));
                const y = (rect.height - barHeight) / 2;

                ctx.fillStyle = '#ef4444'; // Red-500

                ctx.beginPath();
                if (typeof ctx.roundRect === 'function') {
                    ctx.roundRect(x, y, barWidth, barHeight, 4);
                } else {
                    ctx.rect(x, y, barWidth, barHeight);
                }
                ctx.fill();
            }
        };

        draw();

        return () => {
            if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
            if (audioCtx.state !== 'closed') audioCtx.close();
        };
    }
  }, [isRecording]);

  // --- Audio Preview Playback Logic ---
  useEffect(() => {
    if (audioUrl) {
        const audio = new Audio(audioUrl);
        audioRef.current = audio;

        audio.onloadedmetadata = () => {
            if (audio.duration && !isNaN(audio.duration) && audio.duration !== Infinity) {
                setDuration(audio.duration);
            }
        };

        audio.ontimeupdate = () => {
            setCurrentTime(audio.currentTime);
        };

        audio.onended = () => {
            setIsPlaying(false);
            setCurrentTime(0);
        };

        return () => {
            audio.pause();
            audioRef.current = null;
        };
    }
  }, [audioUrl]);

  const togglePlay = () => {
    if (audioRef.current) {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
      const time = parseFloat(e.target.value);
      if (audioRef.current) {
          audioRef.current.currentTime = time;
          setCurrentTime(time);
      }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Global Cleanup
  useEffect(() => {
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (audioUrl) URL.revokeObjectURL(audioUrl);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
    };
  }, []);

  return (
    <div className="w-full relative group">
        <input 
            type="file" 
            accept="audio/*" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            className="hidden" 
        />

        {/* Main Card */}
        <div className={`relative w-full max-w-lg mx-auto bg-white rounded-3xl shadow-2xl transition-all duration-500 overflow-hidden border border-slate-100 ${isRecording ? 'shadow-fs-primary/20 scale-[1.02]' : 'shadow-slate-200/50'}`}>

            {/* Header Status Bar Indicator */}
            <div className={`absolute top-0 left-0 right-0 h-1.5 transition-colors duration-500 ${isRecording ? 'bg-red-500' : (recordedBlob ? 'bg-fs-primary' : 'bg-transparent')}`} />

            {/* Content Area */}
            <div className="p-8 md:p-12 flex flex-col items-center justify-center min-h-[360px]">

                {!recordedBlob ? (
                    /* RECORDING STATE UI */
                    <>
                        <div className="h-24 w-full flex items-center justify-center mb-6">
                            {isRecording ? (
                                <canvas ref={canvasRef} className="w-full h-full max-w-[300px]" />
                            ) : (
                                <div className="flex flex-col items-center justify-center text-slate-300">
                                    <div className="w-20 h-20 rounded-full border-4 border-slate-100 flex items-center justify-center mb-2">
                                        <SignalHigh className="w-10 h-10" />
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="flex flex-col items-center mb-6">
                            <div className={`text-6xl font-mono font-bold tracking-wider tabular-nums transition-colors duration-300 ${isRecording ? 'text-slate-800' : 'text-slate-300'}`}>
                                {formatTime(duration)}
                            </div>
                            {isRecording && (
                                <div className="flex items-center mt-3 text-red-500 font-medium text-sm animate-pulse">
                                    <div className="w-2 h-2 bg-red-500 rounded-full mr-2" />
                                    Recording in progress
                                </div>
                            )}
                        </div>

                        {/* Language Selector (Only visible when not recording) */}
                        {!isRecording && (
                            <div className="relative mb-6">
                                <div className="flex items-center space-x-2 bg-slate-50 border border-slate-200 rounded-full px-4 py-1.5 hover:border-fs-primary/50 transition-colors group/lang">
                                    <Globe className="w-3.5 h-3.5 text-slate-400 group-hover/lang:text-fs-primary" />
                                    <select 
                                        value={language}
                                        onChange={(e) => setLanguage(e.target.value)}
                                        className="bg-transparent text-sm font-medium text-slate-600 focus:outline-none cursor-pointer appearance-none pr-6"
                                        style={{ backgroundImage: 'none' }}
                                    >
                                        {LANGUAGES.map(lang => (
                                            <option key={lang.code} value={lang.code}>{lang.label}</option>
                                        ))}
                                    </select>
                                    <ChevronDown className="w-3.5 h-3.5 text-slate-400 absolute right-3 pointer-events-none" />
                                </div>
                            </div>
                        )}

                        <div className="relative">
                            {isRecording && (
                                <div className="absolute inset-0 rounded-full border border-red-200 animate-ping opacity-75 scale-150 pointer-events-none" />
                            )}

                            {!isRecording ? (
                                <button 
                                    onClick={startRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-fs-primary hover:bg-emerald-600 text-white shadow-lg hover:shadow-xl hover:shadow-emerald-500/30 transition-all duration-300 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-emerald-100"
                                >
                                    <Mic className="w-10 h-10" />
                                </button>
                            ) : (
                                <button 
                                    onClick={stopRecording}
                                    className="group/btn relative w-24 h-24 rounded-full bg-white border-4 border-red-500 hover:bg-red-50 text-red-500 shadow-lg transition-all duration-200 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-red-100"
                                >
                                    <Square className="w-8 h-8 fill-current" />
                                </button>
                            )}
                        </div>

                        {/* Upload Button */}
                        {!isRecording && (
                             <div className="mt-8 flex flex-col items-center">
                                <span className="text-slate-400 text-xs mb-2">- OR -</span>
                                <button 
                                    onClick={handleUploadClick}
                                    className="flex items-center text-slate-600 hover:text-fs-primary transition-colors text-sm font-medium bg-white hover:bg-slate-50 px-5 py-2.5 rounded-full border border-slate-200 shadow-sm"
                                >
                                    <Upload className="w-4 h-4 mr-2" />
                                    Upload Audio File
                                </button>
                             </div>
                        )}

                        {/* Cancel Button */}
                        {isRecording && (
                             <button 
                                onClick={cancelRecording}
                                className="mt-8 flex items-center text-slate-400 hover:text-slate-600 px-4 py-2 rounded-full hover:bg-slate-100 transition-all duration-200 text-sm font-medium animate-in fade-in slide-in-from-top-2"
                             >
                                <X className="w-4 h-4 mr-2" />
                                Cancel
                             </button>
                        )}
                    </>
                ) : (
                    /* PREVIEW STATE UI */
                    <div className="w-full flex flex-col items-center animate-in fade-in duration-300">
                         <h3 className="text-lg font-semibold text-slate-700 mb-6">Preview Recording</h3>

                         {/* Playback Controls */}
                         <div className="w-full max-w-xs mb-6">
                            <div className="flex justify-between text-xs text-slate-500 font-mono mb-2 px-1">
                                <span>{formatTime(currentTime)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>
                            <input 
                                type="range"
                                min="0"
                                max={duration}
                                step="0.1"
                                value={currentTime}
                                onChange={handleSeek}
                                className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-fs-primary focus:outline-none focus:ring-2 focus:ring-fs-primary/30"
                            />
                         </div>

                         {/* Notes Input */}
                         <div className="w-full max-w-xs mb-8">
                             <label className="block text-xs font-medium text-slate-500 mb-1 uppercase tracking-wide">
                                 Meeting Notes (Optional)
                             </label>
                             <textarea
                                 value={note}
                                 onChange={(e) => setNote(e.target.value)}
                                 placeholder="Add context, agenda items, or quick notes..."
                                 className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-fs-primary/50 resize-none h-12 transition-all"
                             />
                             <div className="text-[10px] text-right text-slate-400 mt-1">
                                 Language: <span className="font-medium text-slate-500">{language}</span>
                             </div>
                         </div>

                         <div className="flex items-center justify-center space-x-6">
                            {/* Discard Button */}
                            <button 
                                onClick={handleDiscard} 
                                disabled={isProcessing}
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
                                title="Discard"
                            >
                                <Trash2 className="w-6 h-6 mb-1" />
                                <span className="text-[10px] font-medium uppercase tracking-wide">Discard</span>
                            </button>

                            {/* Play/Pause Button */}
                            <button 
                                onClick={togglePlay} 
                                className="w-20 h-20 bg-fs-dark text-white rounded-full flex items-center justify-center hover:bg-slate-800 shadow-xl shadow-slate-900/20 transition-transform hover:scale-105"
                            >
                                {isPlaying ? <Pause className="w-8 h-8 fill-current" /> : <Play className="w-8 h-8 fill-current ml-1" />}
                            </button>

                            {/* Save Button */}
                            <button 
                                onClick={handleSave} 
                                disabled={isProcessing} 
                                className="flex flex-col items-center justify-center w-16 h-16 rounded-full text-fs-primary hover:bg-emerald-50 transition-all"
                                title="Save"
                            >
                                {isProcessing ? (
                                    <Loader2 className="w-6 h-6 animate-spin mb-1" />
                                ) : (
                                    <Check className="w-6 h-6 mb-1" />
                                )}
                                <span className="text-[10px] font-medium uppercase tracking-wide">{isProcessing ? 'Saving' : 'Save'}</span>
                            </button>
                         </div>
                    </div>
                )}
            </div>

            {/* Footer Hints */}
            {!isRecording && !isProcessing && !recordedBlob && (
                 <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Ready to capture
                    </p>
                 </div>
            )}

            {recordedBlob && !isProcessing && (
                <div className="bg-slate-50 py-4 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-xs font-medium uppercase tracking-wide">
                        Review before saving
                    </p>
                 </div>
            )}
        </div>

        {/* Error Toast */}
        {error && (
            <div className="absolute -bottom-20 left-0 right-0 flex justify-center px-4 z-50">
                <div className="bg-red-50 text-red-800 px-4 py-3 rounded-xl text-sm font-medium shadow-lg border border-red-200 animate-in slide-in-from-bottom-2 fade-in duration-300 max-w-sm text-center flex items-center">
                    <span className="mr-2 text-xl">⚠️</span>
                    {error}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SignalHigh, Play, Pause, Trash2, Check, RotateCcw, X, Upload, Globe, ChevronDown } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string, note: string, language: string) => void;
}

const LANGUAGES = [
    { code: 'English', label: 'English' },
    { code: 'Spanish', label: 'Spanish' },
    { code: 'French', label: 'French' },
    { code: 'German', label: 'German' },
    { code: 'Portuguese', label: 'Portuguese' },
    { code: 'Chinese', label: 'Chinese' },
];

/**
 * Recorder Component
 * 
 * Handles the core recording functionality using the MediaRecorder API.
 * 
 * Key features:
 * 1. Audio Capture: Captures microphone input.
 * 2. Visualization: Uses Web Audio API (AnalyserNode) to draw a frequency bar graph on a canvas.
 * 3. File Upload: Allows users to upload pre-recorded files if they don't want to record live.
 * 4. State Management: Manages transitions between 'recording', 'preview', and 'processing' states.
 */
export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete }) => {
  // --- State: Recording ---
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0); // Tracks seconds elapsed

  // --- State: Preview/Playback ---
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0); // For seek bar
  const [note, setNote] = useState(''); 
  const [uploadedFileName, setUploadedFileName] = useState<string | null>(null);
  const [language, setLanguage] = useState('English');

  // --- State: Processing ---
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Refs: Audio Infrastructure ---
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]); // Accumulates audio data chunks
  const audioRef = useRef<HTMLAudioElement | null>(null); // For preview playback
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Refs: Visualizer ---
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  /**
   * Initializes the MediaStream and MediaRecorder.
   * Handles browser permission errors gracefully.
   */
  const startRecording = async () => {
    setError(null);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setCurrentTime(0);
    setDuration(0);
    setNote('');

    // Feature detection
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Audio recording is not supported in this browser. Please use a modern browser.");
        return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Prefer webm, fallback to mp4
      const mimeType = MediaRecorder.isTypeSupported('audio/webm')
        ? 'audio/webm'
        : 'audio/mp4';

      let recorder;
      try {
         recorder = new MediaRecorder(stream, { mimeType });
      } catch (e) {
         stream.getTracks().forEach(t => t.stop());
         streamRef.current = null;
         setError("Failed to create MediaRecorder. Your browser might not support the selected audio format.");
         return;
      }

      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      // Collect data chunks as they become available
      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      // Finalize recording on stop
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const url = URL.createObjectURL(blob);
        setRecordedBlob(blob);
        setAudioUrl(url);
        setIsRecording(false);

        // Release hardware resources
        streamRef.current?.getTracks().forEach(track => track.stop());
        streamRef.current = null;

        if (timerIntervalRef.current) {
            clearInterval(timerIntervalRef.current);
            timerIntervalRef.current = null;
        }
      };

      recorder.start();
      setIsRecording(true);

      // Start duration timer
      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => {
        setDuration(Math.floor((Date.now() - startTime) / 1000));
      }, 1000);

    } catch (err: any) {
      console.error("Microphone access error:", err);

      // Cleanup if stream was opened but error occurred later
      if (streamRef.current) {
         streamRef.current.getTracks().forEach(t => t.stop());
         streamRef.current = null;
      }

      // Provide user-friendly error messages
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setError("Access denied. Please enable microphone permissions in your browser settings.");
      } else if (err.name === 'NotFoundError') {
        setError("No microphone found.");
      } else {
        setError(`Could not start recording: ${err.message || "Unknown error"}.`);
      }
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      // Logic continues in onstop event handler above
    }
  };

  const cancelRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      // Prevent onstop from triggering a save flow
      mediaRecorderRef.current.onstop = null;
      mediaRecorderRef.current.stop();

      if (streamRef.current) {
         streamRef.current.getTracks().forEach(track => track.stop());
         streamRef.current = null;
      }

      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
      }

      setIsRecording(false);
      setDuration(0);
      setNote('');
      setError(null);
    }
  };

  const handleUploadClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
        setError(null);
        setRecordedBlob(file);
        const url = URL.createObjectURL(file);
        setAudioUrl(url);
        setUploadedFileName(file.name);
        setCurrentTime(0);
        setDuration(0); // Will be updated by audio.onloadedmetadata
        setNote('');
        setIsRecording(false);
    }
  };

  const handleDiscard = () => {
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setDuration(0);
    setCurrentTime(0);
    setIsPlaying(false);
    setNote('');
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  /**
   * Saves the recording to IndexedDB and triggers the parent completion handler.
   */
  const handleSave = async () => {
    if (!recordedBlob) return;

    setIsProcessing(true);
    const blobId = `rec_${Date.now()}`;

    try {
        // Persist blob to IndexedDB
        await saveAudioBlob(blobId, recordedBlob);

        const now = new Date();
        let defaultName = `Board Meeting ${now.toLocaleDateString()}`;

        if (uploadedFileName) {
            defaultName = uploadedFileName.replace(/\.[^/.]+$/, "");
        }

        // Cleanup URL
        if (audioUrl) URL.revokeObjectURL(audioUrl);
        setRecordedBlob(null);
        setAudioUrl(null);
        setUploadedFileName(null);

        onRecordingComplete(blobId, duration, defaultName, note, language);
    } catch (err) {
        setError("Failed to save recording. Storage might be full.");
        console.error(err);
    } finally {
        setIsProcessing(false);
        setDuration(0);
        setNote('');
    }
  };

  // --- Visualizer Effect ---
  // Connects the audio stream to a canvas analyser when recording starts
  useEffect(() => {
    if (isRecording && streamRef.current && canvasRef.current) {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const audioCtx = new AudioContextClass();
        const analyser = audioCtx.createAnalyser();
        const source = audioCtx.createMediaStreamSource(streamRef.current);

        source.connect(analyser);
        analyser.fftSize = 256; 
        analyser.smoothingTimeConstant = 0.5;

        audioContextRef.current = audioCtx;
        analyserRef.current = analyser;

        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Retina display scaling
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
        ctx.scale(dpr, dpr);

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        // Animation Loop
        const draw = () => {
            animationFrameRef.current = requestAnimationFrame(draw);
            analyser.getByteFrequencyData(dataArray);

            ctx.clearRect(0, 0, rect.width, rect.height);

            // Draw configuration
            const bars = 24; 
            const gap = 4;
            const totalGapSpace = (bars - 1) * gap;
            const availableWidth = rect.width * 0.8;
            const barWidth = (availableWidth - totalGapSpace) / bars;
            const startX = (rect.width - availableWidth) / 2;

            // Downsample the frequency data to fit the number of bars
            const step = Math.floor((bufferLength / 2) / bars);

            for (let i = 0; i < bars; i++) {
                let sum = 0;
                for (let j = 0; j < step; j++) {
                    sum += dataArray[(i * step) + j];
                }
                const avg = sum / step;

                const barHeight = Math.max(4, (avg / 255) * rect.height * 0.9);
                const x = startX + (i * (barWidth + gap));
                const y = (rect.height - barHeight) / 2;

                ctx.fillStyle = '#ef4444'; // Red-500

                ctx.beginPath();
                if (typeof ctx.roundRect === 'function') {
                    ctx.roundRect(x, y, barWidth, barHeight, 4);
                } else {
                    ctx.rect(x, y, barWidth, barHeight);
                }
                ctx.fill();
            }
        };

        draw();

        return () => {
            if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
            if (audioCtx.state !== 'closed') audioCtx.close();
        };
    }
  }, [isRecording]);

  // --- Audio Preview Playback Logic ---
  useEffect(() => {
    if (audioUrl) {
        const audio = new Audio(audioUrl);
        audioRef.current = audio;

        audio.onloadedmetadata = () => {
            if (audio.duration && !isNaN(audio.duration) && audio.duration !== Infinity) {
                setDuration(audio.duration);
            }
        };

        audio.ontimeupdate = () => {
            setCurrentTime(audio.currentTime);
        };

        audio.onended = () => {
            setIsPlaying(false);
            setCurrentTime(0);
        };

        return () => {
            audio.pause();
            audioRef.current = null;
        };
    }
  }, [audioUrl]);

  const togglePlay = () => {
    if (audioRef.current) {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
      const time = parseFloat(e.target.value);
      if (audioRef.current) {
          audioRef.current.currentTime = time;
          setCurrentTime(time);
      }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Global Cleanup
  useEffect(() => {
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (audioUrl) URL.revokeObjectURL(audioUrl);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
    };
  }, []);

  return (
    <div className="w-full relative group">
        <input 
            type="file" 
            accept="audio/*" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            className="hidden" 
        />

        {/* Main Card */}
        <div className={`relative w-full max-w-lg mx-auto bg-white rounded-3xl shadow-2xl transition-all duration-500 overflow-hidden border border-slate-100 ${isRecording ? 'shadow-fs-primary/20 scale-[1.02]' : 'shadow-slate-200/50'}`}>

            {/* Header Status Bar Indicator */}
            <div className={`absolute top-0 left-0 right-0 h-1.5 transition-colors duration-500 ${isRecording ? 'bg-red-500' : (recordedBlob ? 'bg-fs-primary' : 'bg-transparent')}`} />

            {/* Language Selector (Absolute Top Right) - Available unless recording */}
            {!isRecording && (
                <div className="absolute top-5 right-5 z-20">
                    <div className="flex items-center space-x-1.5 bg-slate-50 border border-slate-200 rounded-full px-3 py-1 hover:border-fs-primary/50 transition-colors group/lang">
                        <Globe className="w-3 h-3 text-slate-400 group-hover/lang:text-fs-primary" />
                        <select 
                            value={language}
                            onChange={(e) => setLanguage(e.target.value)}
                            className="bg-transparent text-xs font-medium text-slate-600 focus:outline-none cursor-pointer appearance-none pr-4"
                            style={{ backgroundImage: 'none' }}
                        >
                            {LANGUAGES.map(lang => (
                                <option key={lang.code} value={lang.code}>{lang.label}</option>
                            ))}
                        </select>
                        <ChevronDown className="w-3 h-3 text-slate-400 absolute right-2 pointer-events-none" />
                    </div>
                </div>
            )}

            {/* Content Area */}
            <div className="p-6 md:p-8 flex flex-col items-center justify-center min-h-[250px]">

                {!recordedBlob ? (
                    /* RECORDING STATE UI */
                    <>
                        <div className="h-16 w-full flex items-center justify-center mb-4">
                            {isRecording ? (
                                <canvas ref={canvasRef} className="w-full h-full max-w-[240px]" />
                            ) : (
                                <div className="flex flex-col items-center justify-center text-slate-300">
                                    <div className="w-16 h-16 rounded-full border-4 border-slate-100 flex items-center justify-center mb-2">
                                        <SignalHigh className="w-8 h-8" />
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="flex flex-col items-center mb-4">
                            <div className={`text-5xl font-mono font-bold tracking-wider tabular-nums transition-colors duration-300 ${isRecording ? 'text-slate-800' : 'text-slate-300'}`}>
                                {formatTime(duration)}
                            </div>
                            {isRecording && (
                                <div className="flex items-center mt-2 text-red-500 font-medium text-xs animate-pulse">
                                    <div className="w-1.5 h-1.5 bg-red-500 rounded-full mr-1.5" />
                                    Recording
                                </div>
                            )}
                        </div>

                        <div className="relative">
                            {isRecording && (
                                <div className="absolute inset-0 rounded-full border border-red-200 animate-ping opacity-75 scale-150 pointer-events-none" />
                            )}

                            {!isRecording ? (
                                <button 
                                    onClick={startRecording}
                                    className="group/btn relative w-20 h-20 rounded-full bg-fs-primary hover:bg-emerald-600 text-white shadow-lg hover:shadow-xl hover:shadow-emerald-500/30 transition-all duration-300 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-emerald-100"
                                >
                                    <Mic className="w-9 h-9" />
                                </button>
                            ) : (
                                <button 
                                    onClick={stopRecording}
                                    className="group/btn relative w-20 h-20 rounded-full bg-white border-4 border-red-500 hover:bg-red-50 text-red-500 shadow-lg transition-all duration-200 transform hover:scale-105 flex items-center justify-center focus:outline-none focus:ring-4 focus:ring-red-100"
                                >
                                    <Square className="w-7 h-7 fill-current" />
                                </button>
                            )}
                        </div>

                        {/* Upload Button */}
                        {!isRecording && (
                             <div className="mt-6 flex flex-col items-center">
                                <span className="text-slate-400 text-[10px] mb-1.5">- OR -</span>
                                <button 
                                    onClick={handleUploadClick}
                                    className="flex items-center text-slate-600 hover:text-fs-primary transition-colors text-xs font-medium bg-white hover:bg-slate-50 px-4 py-2 rounded-full border border-slate-200 shadow-sm"
                                >
                                    <Upload className="w-3.5 h-3.5 mr-1.5" />
                                    Upload File
                                </button>
                             </div>
                        )}

                        {/* Cancel Button */}
                        {isRecording && (
                             <button 
                                onClick={cancelRecording}
                                className="mt-6 flex items-center text-slate-400 hover:text-slate-600 px-4 py-2 rounded-full hover:bg-slate-100 transition-all duration-200 text-xs font-medium animate-in fade-in slide-in-from-top-2"
                             >
                                <X className="w-3.5 h-3.5 mr-1.5" />
                                Cancel
                             </button>
                        )}
                    </>
                ) : (
                    /* PREVIEW STATE UI */
                    <div className="w-full flex flex-col items-center animate-in fade-in duration-300 pt-4">
                         {/* Removed Header to save space */}

                         {/* Playback Controls */}
                         <div className="w-full max-w-xs mb-4">
                            <div className="flex justify-between text-[10px] text-slate-500 font-mono mb-1.5 px-1">
                                <span>{formatTime(currentTime)}</span>
                                <span>{formatTime(duration)}</span>
                            </div>
                            <input 
                                type="range"
                                min="0"
                                max={duration}
                                step="0.1"
                                value={currentTime}
                                onChange={handleSeek}
                                className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-fs-primary focus:outline-none focus:ring-2 focus:ring-fs-primary/30"
                            />
                         </div>

                         {/* Notes Input */}
                         <div className="w-full max-w-xs mb-6">
                             <textarea
                                 value={note}
                                 onChange={(e) => setNote(e.target.value)}
                                 placeholder="Add brief notes..."
                                 className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-xs focus:outline-none focus:ring-2 focus:ring-fs-primary/50 resize-none h-12 transition-all placeholder:text-slate-400"
                             />
                         </div>

                         <div className="flex items-center justify-center space-x-6">
                            {/* Discard Button */}
                            <button 
                                onClick={handleDiscard} 
                                disabled={isProcessing}
                                className="flex flex-col items-center justify-center w-14 h-14 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all"
                                title="Discard"
                            >
                                <Trash2 className="w-5 h-5 mb-1" />
                                <span className="text-[9px] font-medium uppercase tracking-wide">Discard</span>
                            </button>

                            {/* Play/Pause Button */}
                            <button 
                                onClick={togglePlay} 
                                className="w-16 h-16 bg-fs-dark text-white rounded-full flex items-center justify-center hover:bg-slate-800 shadow-xl shadow-slate-900/20 transition-transform hover:scale-105"
                            >
                                {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
                            </button>

                            {/* Save Button */}
                            <button 
                                onClick={handleSave} 
                                disabled={isProcessing} 
                                className="flex flex-col items-center justify-center w-14 h-14 rounded-full text-fs-primary hover:bg-emerald-50 transition-all"
                                title="Save"
                            >
                                {isProcessing ? (
                                    <Loader2 className="w-5 h-5 animate-spin mb-1" />
                                ) : (
                                    <Check className="w-5 h-5 mb-1" />
                                )}
                                <span className="text-[9px] font-medium uppercase tracking-wide">{isProcessing ? 'Saving' : 'Save'}</span>
                            </button>
                         </div>
                    </div>
                )}
            </div>

            {/* Footer Hints (Hidden on mobile if space is tight, preserved here for structure but reduced padding) */}
            {!isRecording && !isProcessing && !recordedBlob && (
                 <div className="bg-slate-50 py-3 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-[10px] font-medium uppercase tracking-wide">
                        Ready to capture
                    </p>
                 </div>
            )}

            {recordedBlob && !isProcessing && (
                <div className="bg-slate-50 py-3 px-6 text-center border-t border-slate-100">
                    <p className="text-slate-400 text-[10px] font-medium uppercase tracking-wide">
                        Review before saving
                    </p>
                 </div>
            )}
        </div>

        {/* Error Toast */}
        {error && (
            <div className="absolute -bottom-20 left-0 right-0 flex justify-center px-4 z-50">
                <div className="bg-red-50 text-red-800 px-4 py-3 rounded-xl text-sm font-medium shadow-lg border border-red-200 animate-in slide-in-from-bottom-2 fade-in duration-300 max-w-sm text-center flex items-center">
                    <span className="mr-2 text-xl">⚠️</span>
                    {error}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, RotateCcw, Trophy, Home } from 'lucide-react';

/**
 * "HOA Hurdles" - An Endless Runner Minigame
 * 
 * A fun easter egg component displayed when there are no recordings in the list.
 * Built using HTML5 Canvas and a requestAnimationFrame loop.
 */
export const MusicalNotesGame: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [gameState, setGameState] = useState<'start' | 'playing' | 'gameover'>('start');
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);

  // Game State Refs
  // We use refs for the game loop to avoid closure staleness issues in the requestAnimationFrame callback
  const requestRef = useRef<number>(0);
  const gameStateRef = useRef<'start' | 'playing' | 'gameover'>('start');
  const scoreRef = useRef(0);

  // Physics & Gameplay Constants
  const GRAVITY = 0.5; 
  const JUMP_FORCE = -9.5;
  const SPEED = 4;
  const GROUND_HEIGHT = 20;

  // Entity State
  const playerRef = useRef({
    x: 50,
    y: 0, 
    width: 34,
    height: 34,
    dy: 0,
    grounded: false,
    rotation: 0
  });

  // Obstacle Pool
  const obstaclesRef = useRef<Array<{
      x: number, 
      width: number, 
      height: number, 
      passed: boolean, 
      type: 'trash' | 'flamingo' | 'fence' | 'car'
  }>>([]);

  const frameCountRef = useRef(0);

  // Initialize/Reset Game State
  const resetGame = () => {
    if (canvasRef.current) {
        playerRef.current = {
            x: 50,
            y: canvasRef.current.height - GROUND_HEIGHT - 34,
            width: 34,
            height: 34,
            dy: 0,
            grounded: true,
            rotation: 0
        };
        obstaclesRef.current = [];
        frameCountRef.current = 0;
        scoreRef.current = 0;
        setScore(0);
        setGameState('playing');
        gameStateRef.current = 'playing';
    }
  };

  const jump = () => {
    // Start game on first click if not playing
    if (gameStateRef.current !== 'playing') {
        resetGame();
        return;
    }

    // Only jump if on ground
    if (playerRef.current.grounded) {
        playerRef.current.dy = JUMP_FORCE;
        playerRef.current.grounded = false;
    }
  };

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.code === 'Space' || e.code === 'ArrowUp') {
            e.preventDefault();
            jump();
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Main Game Loop
  const update = (time: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // 1. Clear Canvas & Draw Background
    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0, '#f0f9ff'); // Sky blue light
    gradient.addColorStop(1, '#ffffff');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 2. Logic Update
    if (gameStateRef.current === 'playing') {
        frameCountRef.current++;

        // Randomly Spawn Obstacles
        if (frameCountRef.current % Math.floor(100 + Math.random() * 60) === 0) {
             const typeRoll = Math.random();
             let type: 'trash' | 'flamingo' | 'fence' | 'car';
             let width = 0;
             let height = 0;

             // Obstacle types (Violations)
             if (typeRoll < 0.3) {
                 type = 'trash';
                 width = 22;
                 height = 32;
             } else if (typeRoll < 0.55) {
                 type = 'flamingo';
                 width = 18;
                 height = 38;
             } else if (typeRoll < 0.8) {
                 type = 'fence';
                 width = 24;
                 height = 28;
             } else {
                 type = 'car';
                 width = 50;
                 height = 24;
             }

             obstaclesRef.current.push({
                 x: canvas.width,
                 width: width,
                 height: height,
                 passed: false,
                 type: type
             });
        }

        // Update Obstacles position & check collisions
        for (let i = obstaclesRef.current.length - 1; i >= 0; i--) {
            let obs = obstaclesRef.current[i];
            obs.x -= SPEED;

            // Remove if off screen
            if (obs.x + obs.width < 0) {
                obstaclesRef.current.splice(i, 1);
                continue;
            }

            // Score update
            if (!obs.passed && obs.x + obs.width < playerRef.current.x) {
                scoreRef.current++;
                setScore(scoreRef.current);
                obs.passed = true;
            }

            // AABB Collision Detection with padding
            const p = playerRef.current;
            const padding = 6;

            const playerBottom = p.y + p.height - padding;
            const playerRight = p.x + p.width - padding;
            const playerLeft = p.x + padding;
            const playerTop = p.y + padding;

            const obsLeft = obs.x + 2; 
            const obsRight = obs.x + obs.width - 2;
            const obsTop = canvas.height - GROUND_HEIGHT - obs.height + 2;

            if (playerRight > obsLeft && 
                playerLeft < obsRight && 
                playerBottom > obsTop) {

                gameStateRef.current = 'gameover';
                setGameState('gameover');
                if (scoreRef.current > highScore) {
                    setHighScore(scoreRef.current);
                }
            }
        }

        // Update Player Physics
        const p = playerRef.current;
        p.dy += GRAVITY;
        p.y += p.dy;

        // Ground collision
        if (p.y + p.height >= canvas.height - GROUND_HEIGHT) {
            p.y = canvas.height - GROUND_HEIGHT - p.height;
            p.dy = 0;
            p.grounded = true;
            p.rotation = 0; 
        } else {
            // Slight rotation feedback when jumping
            p.rotation = Math.min(Math.PI / 8, p.dy * 0.05);
        }
    }

    // 3. Render Objects

    // Ground
    ctx.fillStyle = '#86efac';
    ctx.fillRect(0, canvas.height - GROUND_HEIGHT, canvas.width, GROUND_HEIGHT);
    ctx.beginPath();
    ctx.strokeStyle = '#22c55e';
    ctx.lineWidth = 2;
    ctx.moveTo(0, canvas.height - GROUND_HEIGHT);
    ctx.lineTo(canvas.width, canvas.height - GROUND_HEIGHT);
    ctx.stroke();

    // Obstacles
    obstaclesRef.current.forEach(obs => {
        const y = canvas.height - GROUND_HEIGHT - obs.height;
        const centerX = obs.x + obs.width/2;

        if (obs.type === 'trash') {
            ctx.fillStyle = '#64748b';
            ctx.fillRect(obs.x + 2, y + 4, obs.width - 4, obs.height - 4);
            ctx.fillStyle = '#475569';
            ctx.fillRect(obs.x, y, obs.width, 4);
        } else if (obs.type === 'flamingo') {
            ctx.beginPath();
            ctx.strokeStyle = '#f472b6';
            ctx.lineWidth = 2;
            ctx.moveTo(centerX, y + obs.height);
            ctx.lineTo(centerX, y + obs.height/2);
            ctx.stroke();
            ctx.fillStyle = '#ec4899';
            ctx.beginPath();
            ctx.ellipse(centerX, y + obs.height/2 - 5, 9, 7, -0.2, 0, Math.PI * 2);
            ctx.fill();
        } else if (obs.type === 'fence') {
            ctx.fillStyle = '#a16207';
            const postWidth = 4;
            ctx.fillRect(obs.x, y, postWidth, obs.height);
            ctx.fillRect(obs.x + obs.width - postWidth, y, postWidth, obs.height);
            ctx.fillRect(obs.x, y + 8, obs.width, 4);
        } else if (obs.type === 'car') {
            ctx.fillStyle = '#ef4444';
            ctx.beginPath();
            if (typeof ctx.roundRect === 'function') {
                ctx.roundRect(obs.x, y + 8, obs.width, obs.height - 8, 4);
            } else {
                ctx.rect(obs.x, y + 8, obs.width, obs.height - 8);
            }
            ctx.fill();
            ctx.fillStyle = '#1e293b';
            ctx.beginPath();
            ctx.arc(obs.x + 10, y + obs.height, 5, 0, Math.PI * 2);
            ctx.arc(obs.x + obs.width - 10, y + obs.height, 5, 0, Math.PI * 2);
            ctx.fill();
        }
    });

    // Player (House Icon)
    const p = playerRef.current;
    ctx.save();
    ctx.translate(p.x + p.width/2, p.y + p.height/2);
    ctx.rotate(p.rotation);

    ctx.fillStyle = '#3b82f6';
    const bodyHeight = p.height * 0.6;
    const roofHeight = p.height * 0.4;
    ctx.fillRect(-p.width/2 + 2, -p.height/2 + roofHeight, p.width - 4, bodyHeight);

    // Roof
    ctx.beginPath();
    ctx.fillStyle = '#1d4ed8';
    ctx.moveTo(-p.width/2, -p.height/2 + roofHeight);
    ctx.lineTo(0, -p.height/2);
    ctx.lineTo(p.width/2, -p.height/2 + roofHeight);
    ctx.fill();

    ctx.restore();

    requestRef.current = requestAnimationFrame(update);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(update);
    return () => cancelAnimationFrame(requestRef.current);
  }, []);

  return (
    <div className="mt-8 w-full max-w-md mx-auto relative group select-none">

        {/* Game Canvas */}
        <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-inner relative" onClick={jump}>
            <canvas 
                ref={canvasRef}
                width={400} 
                height={220} 
                className="w-full h-auto cursor-pointer block"
            />

            {/* Score Overlay */}
            <div className="absolute top-3 right-4 font-mono font-bold text-slate-500 text-lg bg-white/50 px-2 rounded">
                {String(score).padStart(3, '0')}
            </div>

            {/* High Score */}
            {highScore > 0 && (
                <div className="absolute top-3 left-4 flex items-center text-xs font-bold text-amber-500 bg-white/50 px-2 rounded">
                    <Trophy className="w-3 h-3 mr-1" />
                    HI: {highScore}
                </div>
            )}

            {/* Start Screen Overlay */}
            {gameState === 'start' && (
                <div className="absolute inset-0 bg-white/80 flex flex-col items-center justify-center p-4">
                    <p className="text-fs-primary font-bold text-xs animate-pulse mb-2 tracking-wide">Play me!</p>
                    <div className="bg-fs-primary text-white p-3 rounded-full mb-3 shadow-lg hover:scale-110 transition-transform duration-200">
                        <Play className="w-6 h-6 ml-1" />
                    </div>
                    <div className="flex items-center text-slate-800 font-bold text-sm uppercase tracking-wider mb-1">
                        <Home className="w-4 h-4 mr-2 text-fs-primary" />
                        HOA Hurdles
                    </div>
                    <p className="text-slate-400 text-xs text-center px-8">
                        Jump over trash, flamingos, broken fences, and parked cars!
                    </p>
                </div>
            )}

            {/* Game Over Overlay */}
            {gameState === 'gameover' && (
                <div className="absolute inset-0 bg-slate-900/10 backdrop-blur-[1px] flex flex-col items-center justify-center p-4">
                    <div className="bg-white p-4 rounded-xl shadow-xl flex flex-col items-center animate-in zoom-in duration-200">
                        <p className="text-slate-800 font-bold text-lg mb-1">Violation!</p>
                        <p className="text-slate-500 text-xs mb-3 text-center px-4">You hit a compliance issue.</p>
                        <p className="text-fs-primary font-mono font-bold text-xl mb-4">Score: {score}</p>
                        <button 
                            onClick={(e) => { e.stopPropagation(); resetGame(); }}
                            className="flex items-center bg-fs-primary text-white px-4 py-2 rounded-lg hover:bg-emerald-600 transition-colors shadow-md text-sm font-medium"
                        >
                            <RotateCcw className="w-4 h-4 mr-2" />
                            Appeal & Retry
                        </button>
                    </div>
                </div>
            )}
        </div>
        <p className="text-center text-[10px] text-slate-300 mt-2 font-mono">
             Waiting for the meeting to start? Clear some violations.
        </p>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Recording, UserRole } from './types';
import { getRecordingsMeta, saveRecordingsMeta, getUserSession, saveUserSession, clearUserSession } from './services/storageService';
import { AuthScreen } from './components/AuthScreen';
import { Recorder } from './components/Recorder';
import { RecordingList } from './components/RecordingList';
import { LogOut, LayoutGrid, Menu, Mic, List, History, UserCircle2, LogIn, ShieldCheck, Info, Bell } from 'lucide-react';
import { transcribeAudio } from './services/aiService';
import { getAudioBlob } from './services/dbService';
import { requestNotificationPermission, sendNotification, getNotificationPermission } from './services/notificationService';
import { logGuestActivity } from './services/loggingService'; // Service to track unauthenticated usage

const App: React.FC = () => {
  // --- State Management ---
  const [user, setUser] = useState<User | null>(null);
  const [recordings, setRecordings] = useState<Recording[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [currentView, setCurrentView] = useState<'record' | 'history'>('record');
  const [showAuth, setShowAuth] = useState(false);
  const [pendingShareRecording, setPendingShareRecording] = useState<Recording | null>(null);
  const [notificationPermission, setNotificationPermission] = useState(getNotificationPermission());

  // --- Initialization Effects ---

  // Load user session and local recordings on mount
  useEffect(() => {
    const session = getUserSession();
    if (session) {
      setUser(session);
    }
    const savedRecs = getRecordingsMeta();
    setRecordings(savedRecs);
    setIsLoading(false);
  }, []);

  // Persist recordings to LocalStorage whenever they change
  useEffect(() => {
    if (!isLoading) {
      saveRecordingsMeta(recordings);
    }
  }, [recordings, isLoading]);

  // Handle pending share action after successful login
  useEffect(() => {
    if (user && pendingShareRecording) {
      performShare(pendingShareRecording);
      setPendingShareRecording(null);
    }
  }, [user]);

  // --- Handlers ---

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    saveUserSession(newUser);
    setShowAuth(false);
  };

  const handleLogout = () => {
    setUser(null);
    clearUserSession();
  };

  const handleEnableNotifications = async () => {
    await requestNotificationPermission();
    setNotificationPermission(getNotificationPermission());
  };

  /**
   * Handles the completion of a recording session.
   * Creates the recording object, saves it to state, initiates transcription,
   * and logs metadata if the user is a guest.
   */
  const handleRecordingComplete = async (blobId: string, duration: number, defaultName: string, note: string, language: string) => {
    const newRecording: Recording = {
      id: crypto.randomUUID(),
      title: defaultName,
      timestamp: new Date().toISOString(),
      duration: duration,
      note: note,
      blobId: blobId,
      status: 'ready',
      isTranscribing: true,
      language: language,
    };

    // --- Guest Logging Logic ---
    // If no user is logged in, we capture anonymized metadata about the recording
    // to our backend for product analytics.
    if (!user) {
        logGuestActivity('RECORDING_COMPLETED', {
            recordingId: newRecording.id,
            durationSeconds: duration,
            hasNotes: !!note,
            timestamp: newRecording.timestamp,
            // Detect if user is on mobile or desktop for usage segmentation
            deviceType: /Mobi|Android/i.test(navigator.userAgent) ? 'mobile' : 'desktop',
            language: language
        });
    }

    // Optimistically switch to history to show progress immediately
    setRecordings(prev => [newRecording, ...prev]);
    setCurrentView('history');

    try {
      // Fetch the blob to send for transcription
      const blob = await getAudioBlob(blobId);
      if (blob) {
        // AI Service call
        const transcription = await transcribeAudio(blob, language);

        // Update recording with transcription result
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, transcription, isTranscribing: false } 
            : rec
        ));

        // Notify user via browser notification
        sendNotification("Transcription Ready", `Processing complete for "${defaultName}"`);

      } else {
        // Handle edge case where blob is missing
        setRecordings(prev => prev.map(rec => 
          rec.id === newRecording.id 
            ? { ...rec, isTranscribing: false } 
            : rec
        ));
      }
    } catch (error) {
      console.error('Transcription failed', error);
      setRecordings(prev => prev.map(rec => 
        rec.id === newRecording.id 
          ? { ...rec, isTranscribing: false } 
          : rec
      ));
      sendNotification("Transcription Failed", `Could not generate transcript for "${defaultName}"`);
    }
  };

  const handleUpdateRecording = (updated: Recording) => {
    setRecordings(prev => prev.map(r => r.id === updated.id ? updated : r));
  };

  const performShare = (rec: Recording) => {
    // Mock API Push to ALLi
    const confirmShare = window.confirm(`Push "${rec.title}" to ALLi? This will make it available to the board.`);
    if (!confirmShare) return;

    // Optimistic update
    handleUpdateRecording({ ...rec, status: 'shared' });

    // Mock redirection based on Role
    setTimeout(() => {
      sendNotification("Shared to ALLi", `"${rec.title}" is now available to board members.`);

      if (user?.role === UserRole.BOARD_MEMBER) {
        // Deep link simulation
        alert("Redirecting to FRONTSTEPS Community App...");
      } else if (user?.role === UserRole.MANAGER) {
        window.open('https://suite.frontsteps.com/#/steps/overview', '_blank');
      } else {
        // Fallback for edge cases
        alert("Shared to ALLi successfully.");
      }
    }, 1000);
  };

  const handleShareClick = (rec: Recording) => {
    if (!user) {
      setPendingShareRecording(rec);
      setShowAuth(true);
      return;
    }
    performShare(rec);
  };

  if (isLoading) return null;

  return (
    <div className="h-screen bg-slate-50 flex flex-col md:flex-row overflow-hidden relative">

      {/* Auth Modal */}
      {showAuth && (
        <AuthScreen 
            onLogin={handleLogin} 
            onCancel={() => {
                setShowAuth(false);
                setPendingShareRecording(null);
            }} 
        />
      )}

      {/* Sidebar (Desktop) */}
      <div className="hidden md:flex md:w-64 bg-fs-dark flex-shrink-0 flex-col justify-between shadow-xl z-10">
        <div className="p-6">
           {/* Logo Section */}
           <div className="flex items-center space-x-3 mb-8 px-1">
               <div className="h-10 w-10 bg-gradient-to-br from-fs-primary to-emerald-600 rounded-lg flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-fs-primary/20">
                   <span className="font-sans">F</span>
               </div>
               <div className="flex flex-col">
                    <span className="text-lg font-bold text-white tracking-tight leading-none">
                        FRONTST<span className="text-fs-primary">Ξ</span>PS
                    </span>
                    <span className="text-[10px] text-slate-400 font-bold tracking-widest uppercase mt-0.5">Note Taker</span>
               </div>
           </div>

           {/* Navigation Items */}
           <nav className="space-y-2">
              <button 
                onClick={() => setCurrentView('record')}
                className={`w-full flex items-center space-x-3 px-3 py-3 rounded-lg transition-all duration-200 ${
                    currentView === 'record' 
                    ? 'bg-slate-800 text-white shadow-md border-l-4 border-fs-primary' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                }`}
              >
                 <Mic className={`w-5 h-5 ${currentView === 'record' ? 'text-fs-primary' : ''}`} />
                 <span className="text-sm font-medium">Record</span>
              </button>

              <button 
                onClick={() => setCurrentView('history')}
                className={`w-full flex items-center space-x-3 px-3 py-3 rounded-lg transition-all duration-200 ${
                    currentView === 'history' 
                    ? 'bg-slate-800 text-white shadow-md border-l-4 border-fs-primary' 
                    : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
                }`}
              >
                 <History className={`w-5 h-5 ${currentView === 'history' ? 'text-fs-primary' : ''}`} />
                 <span className="text-sm font-medium">History</span>
                 {recordings.length > 0 && (
                    <span className="ml-auto text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded-full">
                        {recordings.length}
                    </span>
                 )}
              </button>

              {notificationPermission === 'default' && (
                  <button 
                    onClick={handleEnableNotifications}
                    className="w-full flex items-center space-x-3 px-3 py-3 rounded-lg text-slate-400 hover:text-white hover:bg-slate-800/50 transition-all duration-200"
                  >
                     <Bell className="w-5 h-5" />
                     <span className="text-sm font-medium">Enable Alerts</span>
                  </button>
              )}
           </nav>
        </div>

        {/* User Profile Snippet */}
        <div className="p-4 bg-fs-darker border-t border-slate-800">
          <div className="flex items-center justify-between">
            {user ? (
                <>
                    <div className="flex items-center space-x-3 overflow-hidden">
                    <div className="w-8 h-8 rounded-full bg-slate-600 flex items-center justify-center text-white text-xs ring-2 ring-slate-700">
                        {user.email.substring(0,2).toUpperCase()}
                    </div>
                    <div className="flex flex-col min-w-0">
                        <span className="text-sm text-white truncate font-medium">{user.email.split('@')[0]}</span>
                        <span className="text-xs text-slate-400 capitalize">{user.role.replace('_', ' ')}</span>
                    </div>
                    </div>
                    <button onClick={handleLogout} className="text-slate-400 hover:text-white p-2 hover:bg-slate-800 rounded-full transition-colors" title="Logout">
                    <LogOut className="w-4 h-4" />
                    </button>
                </>
            ) : (
                <div className="flex items-center justify-between w-full">
                    <div className="flex items-center space-x-3">
