```typescript
import React, { useEffect, useState } from 'react';

const Sidebar: React.FC = () => {
    const [notificationPermission, setNotificationPermission] = useState<'granted' | 'denied' | 'default' | 'unsupported'>('default');

    useEffect(() => {
        const getNotificationPermission = async () => {
            if (!("Notification" in window)) {
                setNotificationPermission('unsupported');
                return;
            }

            try {
                const permission = await Notification.requestPermission();
                setNotificationPermission(permission as 'granted' | 'denied' | 'default');
            } catch (error) {
                console.error("Failed to request notification permission:", error);
                setNotificationPermission('default'); // Or a suitable default state
            }
        };

        getNotificationPermission();
    }, []);

    const requestNotificationPermission = async () => {
        if (!("Notification" in window)) {
            return;
        }

        try {
            const permission = await Notification.requestPermission();
            setNotificationPermission(permission as 'granted' | 'denied' | 'default');
        } catch (error) {
            console.error("Failed to request notification permission:", error);
            setNotificationPermission('default');
        }
    };

    return (
        <div>
            {/* ... other sidebar content ... */}
            <div className="mt-6 pt-6 border-t border-slate-700/50">
                <div className="px-3 mb-2 flex items-center justify-between">
                    <span className="text-xs font-medium text-slate-500 uppercase tracking-wider">Notifications</span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded border capitalize ${
                        notificationPermission === 'granted' ? 'text-emerald-400 border-emerald-500/30 bg-emerald-500/10' :
                        notificationPermission === 'denied' ? 'text-red-400 border-red-500/30 bg-red-500/10' :
                        'text-amber-400 border-amber-500/30 bg-amber-500/10'
                    }`}>
                        {notificationPermission}
                    </span>
                </div>

                {notificationPermission !== 'granted' && notificationPermission !== 'unsupported' && (
                    <button className="w-full px-3 py-1.5 text-xs rounded-md bg-slate-800 text-slate-300 hover:bg-slate-700 active:bg-slate-900 border border-slate-700/50"
                        onClick={requestNotificationPermission}>
                        Enable Alerts
                    </button>
                )}
            </div>
            {/* ... rest of sidebar ... */}
        </div>
    );
};

export default Sidebar;
```


