import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SignalHigh, Play, Pause, Trash2, Check, RotateCcw, X, Upload, Globe, ChevronDown } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string, note: string, language: string) => void;
}

const LANGUAGES = [
    { code: 'English', label: 'English' },
    { code: 'Spanish', label: 'Spanish' },
    { code: 'French', label: 'French' },
    { code: 'German', label: 'German' },
    { code: 'Portuguese', label: 'Portuguese' },
    { code: 'Chinese', label: 'Chinese' },
];

const AUTOSAVE_KEY = 'fs_recorder_autosave_note';

/**
 * Recorder Component
 * 
 * JUNIOR DEV NOTE:
 * This component is complex because it handles the Recording State Machine:
 * 1. Idle -> 2. Recording -> 3. Preview/Review -> 4. Saving/Uploading
 * 
 * Key APIs used:
 * - MediaRecorder: The browser standard API for capturing audio from the microphone.
 * - AudioContext & AnalyserNode: Used to get real-time frequency data to draw the red bar visualizer.
 * - localStorage: Used for auto-saving notes so users don't lose data if they refresh.
 */
export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete }) => {
  // --- State: Recording ---
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0); // Tracks seconds elapsed

  // --- State: Preview/Playback ---
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0); // For seek bar
  const [note, setNote] = useState(''); 
  const [uploadedFileName, setUploadedFileName] = useState<string | null>(null);
  const [language, setLanguage] = useState('English');

  // --- State: Processing ---
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Refs: Audio Infrastructure ---
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]); // Accumulates audio data chunks
  const audioRef = useRef<HTMLAudioElement | null>(null); // For preview playback
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Refs: Visualizer ---
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  // --- Refs: Auto-save ---
  const noteRef = useRef(note);

  // Keep noteRef in sync with state for event listeners
  useEffect(() => {
    noteRef.current = note;
  }, [note]);

  // Auto-save Effect
  useEffect(() => {
    // 1. Load saved note on mount
    const savedNote = localStorage.getItem(AUTOSAVE_KEY);
    if (savedNote) {
        setNote(savedNote);
    }

    const saveToStorage = () => {
        if (noteRef.current) {
            localStorage.setItem(AUTOSAVE_KEY, noteRef.current);
        }
    };

    // 2. Save every 10 seconds
    const intervalId = setInterval(saveToStorage, 10000);

    // 3. Save on visibility change (tab switch) or unload
    const handleVisibilityChange = () => {
        if (document.visibilityState === 'hidden') {
            saveToStorage();
        }
    };
    const handleBeforeUnload = () => {
        saveToStorage();
    };

    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('beforeunload', handleBeforeUnload);

    return () => {
        clearInterval(intervalId);
        window.removeEventListener('visibilitychange', handleVisibilityChange);
        window.removeEventListener('beforeunload', handleBeforeUnload);
        // Save on unmount
        saveToStorage();
    };
  }, []);

  /**
   * Initializes the MediaStream and MediaRecorder.
   * Handles browser permission errors gracefully.
   */
  const startRecording = async () => {
    setError(null);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setCurrentTime(0);
    setDuration(0);
    // Note: We do NOT clear the note here to preserve autosaved content if recovering from a crash.

    // Feature detection
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Audio recording is not supported in this browser. Please use a modern browser.");
        return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Prefer webm, fallback to mp4
      const mimeType = MediaRecorder.isTypeSupported('audio/webm')
        ? 'audio/webm'
        : 'audio/mp4';

      let recorder;
      try {
         recorder = new MediaRecorder(stream, { mimeType });
      } catch (e) {
         stream.getTracks().forEach(t => t.stop());
         streamRef.current = null;
         setError("Failed to create MediaRecorder. Your browser might not support the selected audio format.");
         return;
      }

      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      // Collect data chunks as they become available
      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      // Finalize recording on stop
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const url = URL.createObjectURL(blob);
        setRecordedBlob(blob);
        setAudioUrl(url);
        setIsRecording(false);

        // Release hardware resources
        streamRef.current?.getTracks().forEach(track => track.stop());
        streamRef.current = null;

        if (timerIntervalRef.current) {
            clearInterval(timerIntervalRef.current);
            timerIntervalRef.current = null;
        }
      };

      recorder.start();
      setIsRecording(true);

      // Start duration timer
      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => {
        setDuration(Math.floor((Date.now() - startTime) / 1000));
      }, 1000);

    } catch (err: any) {
      console.error("Microphone access error:", err);

      // Cleanup if stream was opened but error occurred later
      if (streamRef.current) {
         streamRef.current.getTracks().forEach(t => t.stop());
         streamRef.current = null;
      }

      // Provide user-friendly error messages
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setError("Access denied. Please enable microphone permissions in your browser settings.");
      } else if (err.name === 'NotFoundError') {
        setError("No microphone found.");
      } else {
        setError(`Could not start recording: ${err.message || "Unknown error"}.`);
      }
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      // Logic continues in onstop event handler above
    }
  };

  const cancelRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      // Prevent onstop from triggering a save flow
      mediaRecorderRef.current.onstop = null;
      mediaRecorderRef.current.stop();

      if (streamRef.current) {
         streamRef.current.getTracks().forEach(track => track.stop());
         streamRef.current = null;
      }

      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
      }

      setIsRecording(false);
      setDuration(0);
      setNote(''); // Clear note on explicit cancel
      localStorage.removeItem(AUTOSAVE_KEY);
      setError(null);
    }
  };

  const handleUploadClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
        setError(null);
        setRecordedBlob(file);
        const url = URL.createObjectURL(file);
        setAudioUrl(url);
        setUploadedFileName(file.name);
        setCurrentTime(0);
        setDuration(0); // Will be updated by audio.onloadedmetadata
        setIsRecording(false);
        // Note: Preserving note content here too
    }
  };

  const handleDiscard = () => {
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setDuration(0);
    setCurrentTime(0);
    setIsPlaying(false);
    setNote('');
    localStorage.removeItem(AUTOSAVE_KEY); // Clear autosave on discard
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  /**
   * Saves the recording to IndexedDB and triggers the parent completion handler.
   */
  const handleSave = async () => {
    if (!recordedBlob) return;

    setIsProcessing(true);
    const blobId = `rec_${Date.now()}`;

    try {
        // Persist blob to IndexedDB
        await saveAudioBlob(blobId, recordedBlob);

        const now = new Date();
        let defaultName = `Board Meeting ${now.toLocaleDateString()}`;

        if (uploadedFileName) {
            defaultName = uploadedFileName.replace(/\.[^/.]+$/, "");
        }

        // Cleanup URL
        if (audioUrl) URL.revokeObjectURL(audioUrl);
        setRecordedBlob(null);
        setAudioUrl(null);
        setUploadedFileName(null);

        // Clear autosave on success
        localStorage.removeItem(AUTOSAVE_KEY);

        onRecordingComplete(blobId, duration, defaultName, note, language);
    } catch (err) {
        setError("Failed to save recording. Storage might be full.");
        console.error(err);
    } finally {
        setIsProcessing(false);
        setDuration(0);
        setNote('');
    }
  };

  // --- Visualizer Effect ---
  // Connects the audio stream to a canvas analyser when recording starts
  // JUNIOR DEV NOTE: This is complex canvas math to draw the frequency bars
  useEffect(() => {
    if (isRecording && streamRef.current && canvasRef.current) {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const audioCtx = new AudioContextClass();
        const analyser = audioCtx.createAnalyser();
        const source = audioCtx.createMediaStreamSource(streamRef.current);

        source.connect(analyser);
        analyser.fftSize = 256; 
        analyser.smoothingTimeConstant = 0.5;

        audioContextRef.current = audioCtx;
        analyserRef.current = analyser;

        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Retina display scaling
        const dpr = window.devicePixelRatio || 1;
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
        ctx.scale(dpr, dpr);

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        // Animation Loop
        const draw = () => {
            animationFrameRef.current = requestAnimationFrame(draw);
            analyser.getByteFrequencyData(dataArray);

            ctx.clearRect(0, 0, rect.width, rect.height);

            // Draw configuration
            const bars = 24; 
            const gap = 4;
            const totalGapSpace = (bars - 1) * gap;
            const availableWidth = rect.width * 0.8;
            const barWidth = (availableWidth - totalGapSpace) / bars;
            const startX = (rect.width - availableWidth) / 2;

            // Downsample the frequency data to fit the number of bars
            const step = Math.floor((bufferLength / 2) / bars);

            for (let i = 0; i < bars; i++) {
                let sum = 0;
                for (let j = 0; j < step; j++) {
                    sum += dataArray[(i * step) + j];
                }
                const avg = sum / step;

                const barHeight = Math.max(4, (avg / 255) * rect.height * 0.9);
                const x = startX + (i * (barWidth + gap));
                const y = (rect.height - barHeight) / 2;

                ctx.fillStyle = '#ef4444'; // Red-500

                ctx.beginPath();
                if (typeof ctx.roundRect === 'function') {
                    ctx.roundRect(x, y, barWidth, barHeight, 4);
                } else {
                    ctx.rect(x, y, barWidth, barHeight);
                }
                ctx.fill();
            }
        };

        draw();

        return () => {
            if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
            if (audioCtx.state !== 'closed') audioCtx.close();
        };
    }
  }, [isRecording]);

  // --- Audio Preview Playback Logic ---
  useEffect(() => {
    if (audioUrl) {
        const audio = new Audio(audioUrl);
        audioRef.current = audio;

        audio.onloadedmetadata = () => {
            if (audio.duration && !isNaN(audio.duration) && audio.duration !== Infinity) {
                setDuration(audio.duration);
            }
        };

        audio.ontimeupdate = () => {
            setCurrentTime(audio.currentTime);
        };

        audio.onended = () => {
            setIsPlaying(false);
            setCurrentTime(0);
        };

        return () => {
            audio.pause();
            audioRef.current = null;
        };
    }
  }, [audioUrl]);

  const togglePlay = () => {
    if (audioRef.current) {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
      const time = parseFloat(e.target.value);
      if (audioRef.current) {
          audioRef.current.currentTime = time;
          setCurrentTime(time);
      }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Global Cleanup
  useEffect(() => {
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (audioUrl) URL.revokeObjectURL(audioUrl);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
    };
  }, []);

  return (
    <div className="w-full relative group">
        <input 
            type="file" 
            accept="audio/*" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            className="hidden" 
        />

        {/* Main Card */}
        <div className={`relative w-full max-w-lg mx-auto bg-white dark:bg-slate-900 rounded-3xl shadow-2xl transition-all duration-500 overflow-hidden border border-slate-100 dark:border-slate-800 ${isRecording ? 'shadow-fs-primary/20 scale-[1.02]' : 'shadow-slate-200/50 dark:shadow-slate-950/50'}`}>

            {/* Header Status Bar Indicator */}
            <div className={`absolute top-0 left-0 right-0 h-1.5 transition-colors duration-500 ${isRecording ? 'bg-red-500' : (recordedBlob ? 'bg-fs-primary' : 'bg-transparent')}`} />

            {/* Content Area */}
            <div className="p-6 md:p-8 flex flex-col items-center justify-center min-h-[250px]">

                {!recordedBlob ? (
                    /* RECORDING STATE UI */
                    <>
