                         <div className="flex items-center justify-center space-x-6">
                            {/* Discard Button */}
                            <button 
                                onClick={handleDiscard} 
                                disabled={isProcessing}
                                className="flex flex-col items-center justify-center w-14 h-14 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-all"
                                title="Discard"
                            >
                                <Trash2 className="w-5 h-5 mb-1" />
                                <span className="text-[9px] font-medium uppercase tracking-wide">Discard</span>
                            </button>

                            {/* Play/Pause Button */}
                            <button 
                                onClick={togglePlay} 
                                className="w-16 h-16 bg-fs-dark dark:bg-slate-700 text-white rounded-full flex items-center justify-center hover:bg-slate-800 dark:hover:bg-slate-600 shadow-xl shadow-slate-900/20 transition-transform hover:scale-105"
                            >
                                {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
                            </button>

                            {/* Save Button */}
                            <button 
                                onClick={handleSave} 
                                disabled={isProcessing} 
                                className="flex flex-col items-center justify-center w-14 h-14 rounded-full text-fs-primary hover:bg-emerald-50 dark:hover:bg-emerald-900/20 transition-all"
                                title="Save"
                            >
                                {isProcessing ? (
                                    <Loader2 className="w-5 h-5 animate-spin mb-1" />
                                ) : (
                                    <Check className="w-5 h-5 mb-1" />
                                )}
                                <span className="text-[9px] font-medium uppercase tracking-wide">{isProcessing ? 'Saving' : 'Save'}</span>
                            </button>
                         </div>
                    </div>
                )}
            </div>

            {/* Footer Hints (Hidden on mobile if space is tight, preserved here for structure but reduced padding) */}
            {!isRecording && !isProcessing && !recordedBlob && (
                 <div className="bg-slate-50 dark:bg-slate-800/50 py-3 px-6 text-center border-t border-slate-100 dark:border-slate-800">
                    <p className="text-slate-400 dark:text-slate-500 text-[10px] font-medium uppercase tracking-wide">
                        Ready to capture
                    </p>
                 </div>
            )}

            {recordedBlob && !isProcessing && (
                <div className="bg-slate-50 dark:bg-slate-800/50 py-3 px-6 text-center border-t border-slate-100 dark:border-slate-800">
                    <p className="text-slate-400 dark:text-slate-500 text-[10px] font-medium uppercase tracking-wide">
                        Review before saving
                    </p>
                 </div>
            )}
        </div>

        {/* Error Toast */}
        {error && (
            <div className="absolute -bottom-20 left-0 right-0 flex justify-center px-4 z-50">
                <div className="bg-red-50 dark:bg-red-900/90 text-red-800 dark:text-red-100 px-4 py-3 rounded-xl text-sm font-medium shadow-lg border border-red-200 dark:border-red-800 animate-in slide-in-from-bottom-2 fade-in duration-300 max-w-sm text-center flex items-center">
                    <span className="mr-2 text-xl">⚠️</span>
                    {error}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
