/**
 * Helper: Generate consistent colors for speakers based on name hash.
 * 
 * JUNIOR DEV NOTE:
 * We need 'Speaker 1' to always be Blue, and 'Speaker 2' to always be Green, etc.
 * Instead of storing this in the database, we use a "Hash Function".
 * 1. We sum the ASCII character codes of the name string.
 * 2. We use the Modulo operator (%) to wrap that number around the length of our color array.
 * This guarantees the same input name always yields the same color index.
 */
const getSpeakerColor = (name: string) => {
  const colors = [
    'bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800',
    'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-800',
    'bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-900/30 dark:text-amber-300 dark:border-amber-800',
    'bg-purple-100 text-purple-700 border-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-800',
    'bg-pink-100 text-pink-700 border-pink-200 dark:bg-pink-900/30 dark:text-pink-300 dark:border-pink-800',
    'bg-indigo-100 text-indigo-700 border-indigo-200 dark:bg-indigo-900/30 dark:text-indigo-300 dark:border-indigo-800',
    'bg-cyan-100 text-cyan-700 border-cyan-200 dark:bg-cyan-900/30 dark:text-cyan-300 dark:border-cyan-800',
    'bg-rose-100 text-rose-700 border-rose-200 dark:bg-rose-900/30 dark:text-rose-300 dark:border-rose-800',
  ];
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return colors[Math.abs(hash) % colors.length];
};

/**
 * Helper: Highlights matching text query case-insensitively.
 * 
 * JUNIOR DEV NOTE:
 * Used for the search feature.
 * 1. Escapes special regex characters (like ? or *) from the query.
 * 2. Splits the text by the query, capturing the delimiter (the query itself).
 * 3. Maps through parts; if a part matches the query, wraps it in a <mark> tag.
 */
const highlightText = (text: string, query: string) => {
  if (!query || !query.trim()) return text;
  // Escape regex characters to prevent crashes if user types "[" or "("
  const safeQuery = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(`(${safeQuery})`, 'gi');
  const parts = text.split(regex);

  return parts.map((part, i) => 
    part.toLowerCase() === query.toLowerCase() 
      ? <mark key={i} className="bg-yellow-200 dark:bg-yellow-600 text-slate-900 dark:text-white rounded-sm px-0.5 font-normal">{part}</mark> 
      : part
  );
};

/**
 * Helper: Simple Markdown Parser.
 * 
 * JUNIOR DEV NOTE:
 * The AI returns text with **Bold** and *Italics*. React renders this as raw string by default.
 * We need to parse these markers and replace them with <strong> and <em> React components.
 * This function recursively splits strings by these markers.
 */
const parseMarkdown = (text: string, query: string = '') => {
  // Split by bold (**...**)
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return parts.map((part, i) => {
    // If this part is bold text
    if (part.startsWith('**') && part.endsWith('**')) {
      const content = part.slice(2, -2);
      return <strong key={i} className="font-bold text-slate-900 dark:text-white">{highlightText(content, query)}</strong>;
    }
    // Split by italic (*...*) inside non-bold parts
    const subParts = part.split(/(\*.*?\*)/g);
    return subParts.map((subPart, j) => {
       if (subPart.startsWith('*') && subPart.endsWith('*') && subPart.length > 2) {
         const content = subPart.slice(1, -1);
         return <em key={`${i}-${j}`} className="italic text-slate-800 dark:text-slate-200">{highlightText(content, query)}</em>;
       }
       return <React.Fragment key={`${i}-${j}`}>{highlightText(subPart, query)}</React.Fragment>;
    });
  });
};

/**
 * RecordingList Component
 * 
 * Displays the list of past recordings (History View).
 * Features:
 * - Audio Playback
 * - Expanding/Collapsing Details
 * - Editing Titles/Notes
 * - Displaying AI Transcripts
 * - Search Filtering
 */
export const RecordingList: React.FC<RecordingListProps> = ({ 
  recordings, 
  currentUser,
  onUpdateRecording,
  onShare
}) => {
  // State: ID of the recording currently playing audio
  const [playingId, setPlayingId] = useState<string | null>(null);
  // State: Reference to the actual HTMLAudioElement to control pause/play
  const [audioEl, setAudioEl] = useState<HTMLAudioElement | null>(null);

  // State: Editing Mode
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNote, setEditNote] = useState('');

  // State: UI Toggles
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // State: Set of IDs for expanded transcripts (allows multiple open at once)
  const [transcriptExpandedIds, setTranscriptExpandedIds] = useState<Set<string>>(new Set());

  // Effect: Cleanup audio when component unmounts to prevent memory leaks or playing in background
  useEffect(() => {
    return () => {
      if (audioEl) {
        audioEl.pause();
        audioEl.src = '';
      }
    };
  }, [audioEl]);

  // Handler: Plays audio from IndexedDB
  const handlePlay = async (recording: Recording) => {
    // If clicking the same one, toggle pause
    if (playingId === recording.id && audioEl) {
      audioEl.pause();
      setPlayingId(null);
      return;
    }

    // Stop currently playing if switching
    if (audioEl) {
      audioEl.pause();
    }

    try {
      // 1. Fetch binary data from IndexedDB
      const blob = await getAudioBlob(recording.blobId);
      if (!blob) {
        alert("Audio file not found.");
        return;
      }

      // 2. Create Object URL for browser playback
      const url = URL.createObjectURL(blob);
      const audio = new Audio(url);

      // 3. Reset state when audio finishes
      audio.onended = () => setPlayingId(null);
      audio.play();

      setAudioEl(audio);
      setPlayingId(recording.id);
    } catch (e) {
      console.error("Error playing audio", e);
    }
  };

  const handleStartEdit = (rec: Recording) => {
    setEditingId(rec.id);
    setEditTitle(rec.title);
    setEditNote(rec.note);
    setExpandedId(rec.id);
  };

  const handleSaveEdit = (rec: Recording) => {
    onUpdateRecording({
      ...rec,
      title: editTitle,
      note: editNote
    });
    setEditingId(null);
  };

  // Handler: Download MP3
  const handleDownload = async (rec: Recording) => {
      try {
        const blob = await getAudioBlob(rec.blobId);
        if (blob) {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.mp3`; 
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
      } catch (e) {
          console.error(e);
      }
  };

  // Handler: Generate and download text report
  const handleExportReport = (rec: Recording) => {
    const date = new Date(rec.timestamp).toLocaleDateString();
    const time = new Date(rec.timestamp).toLocaleTimeString();
    const duration = `${Math.floor(rec.duration / 60)} minutes ${rec.duration % 60} seconds`;

    let content = `FRONTSTEPS NOTE TAKER REPORT\n`;
    content += `==================================================\n`;
    content += `Title:    ${rec.title}\n`;
    content += `Date:     ${date} at ${time}\n`;
    content += `Duration: ${duration}\n`;
    content += `==================================================\n\n`;

    if (rec.note) {
        content += `NOTES\n`;
        content += `-----\n`;
        content += `${rec.note}\n\n`;
    }

    if (rec.transcription) {
        content += `TRANSCRIPT & AI INSIGHTS\n`;
        content += `------------------------\n`;
        content += `${rec.transcription}\n`;
    } else {
         content += `(No transcript available)\n`;
    }

    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${rec.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_report.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCopyTranscript = (text: string, id: string) => {
    navigator.clipboard.writeText(text).then(() => {
        setCopiedId(id);
        setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const toggleTranscript = (id: string) => {
    setTranscriptExpandedIds(prev => {
        const next = new Set(prev);
        if (next.has(id)) {
            next.delete(id);
        } else {
            next.add(id);
        }
        return next;
    });
  };

  // Helper to render transcript with speaker labels and markdown
  const renderFormattedTranscript = (text: string) => {
      if (!text) return <span className="text-slate-400 dark:text-slate-500 italic">Transcript not available.</span>;

      // Split by newlines to handle paragraphs/lines
      const lines = text.split('\n');

      return (
          <div className="space-y-6">
              {lines.map((line, idx) => {
                  const trimmed = line.trim();
                  if (!trimmed) return null;

                  // Detect "Speaker Name:" pattern
                  // Matches "**Speaker Name:** Content" or "Speaker Name: Content"
                  // We look for a colon in the first 40 chars as a heuristic
                  const colonIndex = trimmed.indexOf(':');

                  if (colonIndex > 0 && colonIndex < 40) {
                      const rawSpeaker = trimmed.substring(0, colonIndex);
                      // Clean up markdown chars from speaker name (e.g. **Speaker**)
                      const speakerName = rawSpeaker.replace(/[\*\_]/g, '').trim();
                      const content = trimmed.substring(colonIndex + 1).trim();

                      // Generate initials
                      const initials = speakerName.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
                      const colorClass = getSpeakerColor(speakerName);

                      return (
                          <div key={idx} className="flex flex-row items-start gap-3 group">
                              <div className={`flex-shrink-0 mt-1 w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold border ${colorClass} shadow-sm select-none`}>
                                  {initials}
                              </div>
                              <div className="flex-1 min-w-0">
                                  <span className={`inline-block mb-1.5 px-2.5 py-0.5 rounded-md text-[11px] font-bold uppercase tracking-wider border ${colorClass}`}>
                                      {highlightText(speakerName, searchQuery)}
                                  </span>
                                  <p className="text-slate-700 dark:text-slate-300 leading-relaxed text-sm">
                                      {parseMarkdown(content, searchQuery)}
                                  </p>
                              </div>
                          </div>
                      );
                  }

                  // Default paragraph if no speaker detected
                  // Indent slightly to align better with text in speaker blocks
                  return (
                      <p key={idx} className="text-slate-700 dark:text-slate-300 leading-relaxed text-sm pl-0 sm:pl-12">
                          {parseMarkdown(trimmed, searchQuery)}
                      </p>
                  );
              })}
          </div>
      );
  };

  // Render Empty State (Game)
  if (recordings.length === 0) {
    return (
        <div className="text-center py-12 px-4">
            <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileText className="w-8 h-8 text-slate-300 dark:text-slate-600" />
            </div>
            <h3 className="text-lg font-medium text-slate-900 dark:text-white">No recordings yet</h3>
            <p className="text-slate-500 dark:text-slate-400 max-w-sm mx-auto mt-2 mb-8">
                Tap the microphone button in the record menu to start recording your board meeting.
            </p>

            {/* Creative Microgame when list is empty */}
            <HOAgame />
        </div>
    );
  }

  const filteredRecordings = recordings.filter(rec => {
      const query = searchQuery.toLowerCase();
      const matchTitle = rec.title.toLowerCase().includes(query);
      const matchNote = rec.note && rec.note.toLowerCase().includes(query);
      const matchTranscript = rec.transcription && rec.transcription.toLowerCase().includes(query);

      return matchTitle || matchNote || matchTranscript;
  });

  return (
    <div className="space-y-6">
      {/* Search Bar */}
      <div className="relative max-w-md">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-slate-400" />
        </div>
        <input 
            type="text"
            placeholder="Search by title, notes, or transcript..."
            className="block w-full pl-10 pr-10 py-2.5 border border-slate-300 dark:border-slate-700 rounded-lg leading-5 bg-white dark:bg-slate-900 placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-fs-primary/50 focus:border-fs-primary sm:text-sm transition-shadow shadow-sm text-slate-900 dark:text-white"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
        />
        {searchQuery && (
            <button 
                onClick={() => setSearchQuery('')}
                className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600 dark:hover:text-slate-300"
            >
                <X className="h-4 w-4" />
            </button>
        )}
      </div>

      {filteredRecordings.length === 0 ? (
          <div className="text-center py-12 bg-white dark:bg-slate-900 rounded-lg border border-dashed border-slate-300 dark:border-slate-700">
              <Search className="w-8 h-8 mx-auto mb-2 text-slate-300 dark:text-slate-600" />
              <p className="text-slate-500 dark:text-slate-400 text-sm">No recordings found for "{searchQuery}"</p>
              <button 
                onClick={() => setSearchQuery('')}
                className="mt-2 text-fs-primary text-sm font-medium hover:underline"
              >
                  Clear search
              </button>
          </div>
      ) : (
          <div className="space-y-4">
            {filteredRecordings.map((rec) => {
                // Parse Action Items if present
                const parts = rec.transcription ? rec.transcription.split('### ACTION ITEMS') : [];
                const mainTranscript = parts[0] ? parts[0].trim() : '';
                const actionItems = parts[1] ? parts[1].trim() : null;
                const isTranscriptExpanded = transcriptExpandedIds.has(rec.id);

                // Determine if there is a match in the transcript for the current search query
                const query = searchQuery.toLowerCase();
                const matchInTranscript = query && rec.transcription && rec.transcription.toLowerCase().includes(query);

                return (
                <div key={rec.id} className="bg-white dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-200 hover:shadow-lg hover:bg-slate-50 dark:hover:bg-slate-800 hover:border-slate-300 dark:hover:border-slate-700">
                <div className="p-4">

                    {/* Header / Title */}
                    <div className="flex items-start justify-between mb-2">
                    <div className="flex-1 mr-4">
                        {editingId === rec.id ? (
                            <input 
                                type="text" 
                                value={editTitle}
                                onChange={(e) => setEditTitle(e.target.value)}
                                className="w-full text-lg font-semibold text-slate-900 dark:text-white border-b-2 border-fs-primary focus:outline-none bg-transparent"
                                autoFocus
                            />
                        ) : (
                            <h3 className="text-lg font-semibold text-slate-900 dark:text-white leading-tight">
                                {rec.title}
                            </h3>
                        )}
                        <div className="flex items-center text-xs text-slate-500 dark:text-slate-400 mt-1 space-x-3">
                            {/* Timestamp Formatting */}
                            <span className="flex items-center">
                                <Clock className="w-3 h-3 mr-1" />
                                {/* Display Date (e.g. Oct 24, 2023) */}
                                {new Date(rec.timestamp).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                                <span className="mx-1.5 opacity-50">|</span>
                                {/* Display Time (e.g. 2:30 PM) using local locale */}
                                {new Date(rec.timestamp).toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit' })}
                            </span>
                            <span className="font-mono bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded">
                                {Math.floor(rec.duration / 60)}:{String(rec.duration % 60).padStart(2, '0')}
                            </span>
                        </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex items-center space-x-1">
                        {editingId === rec.id ? (
                            <button 
                                onClick={() => handleSaveEdit(rec)}
                                className="p-2 text-fs-primary hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-full"
                            >
                                <Check className="w-5 h-5" />
                            </button>
                        ) : (
                            <button 
                                onClick={() => handleStartEdit(rec)}
                                className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-full"
                            >
                                <Edit2 className="w-4 h-4" />
                            </button>
                        )}
                    </div>
                    </div>

                    {/* Notes Section */}
                    {(expandedId === rec.id || rec.note) && (
                        <div className="mt-3 bg-slate-50 dark:bg-slate-800/50 rounded p-3 text-sm">
                            <h4 className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide mb-1">Notes</h4>
                            {editingId === rec.id ? (
                                <textarea 
                                    value={editNote}
                                    onChange={(e) => setEditNote(e.target.value)}
                                    placeholder="Add meeting notes, agenda items, or action points..."
                                    className="w-full bg-transparent focus:outline-none min-h-[60px] text-slate-700 dark:text-slate-300 resize-none"
                                />
                            ) : (
                                <p className="text-slate-600 dark:text-slate-300 whitespace-pre-wrap">
                                    {rec.note || <span className="text-slate-400 dark:text-slate-500 italic">No notes added.</span>}
                                </p>
                            )}
                        </div>
                    )}

                    {/* AI Insights & Transcription */}
                    {(expandedId === rec.id || rec.transcription || rec.isTranscribing) && (
                        <div className="mt-4 border-t border-slate-100 dark:border-slate-800 pt-3">
                            {/* Action Items Highlight */}
                            {actionItems && (
                                <div className="mb-4 bg-amber-50 dark:bg-amber-900/10 border border-amber-200 dark:border-amber-900/30 rounded-md p-3">
                                    <div className="flex items-center mb-2">
                                        <ListChecks className="w-4 h-4 text-amber-600 dark:text-amber-500 mr-2" />
                                        <h4 className="text-xs font-bold text-amber-800 dark:text-amber-400 uppercase tracking-wide">Action Items</h4>
                                    </div>
                                    <div className="text-amber-900 dark:text-amber-300 text-sm whitespace-pre-wrap pl-6">
                                        {parseMarkdown(actionItems, searchQuery)}
                                    </div>
                                </div>
                            )}

                            {/* Transcript Header & Toggle */}
                            <div 
                                className="flex items-center justify-between cursor-pointer py-2 hover:bg-slate-50 dark:hover:bg-slate-800 rounded transition-colors"
                                onClick={() => toggleTranscript(rec.id)}
                            >
                                <div className="flex items-center">
                                <Sparkles className="w-3 h-3 text-purple-500 mr-2" />
                                <h4 className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide">Transcript</h4>
                                {matchInTranscript && !isTranscriptExpanded && (
                                    <span className="ml-2 px-1.5 py-0.5 bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200 text-[10px] font-bold uppercase rounded-full">
                                        Match
                                    </span>
                                )}
                                </div>
                                <div className="flex items-center space-x-2">
                                    {rec.transcription && !rec.isTranscribing && isTranscriptExpanded && (
                                        <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleCopyTranscript(rec.transcription!, rec.id);
                                                }}
                                                className="flex items-center text-xs text-slate-400 hover:text-fs-primary transition-colors mr-2"
                                                title="Copy transcript"
                                        >
                                            {copiedId === rec.id ? <Check className="w-3 h-3 mr-1" /> : <Copy className="w-3 h-3 mr-1" />}
                                            {copiedId === rec.id ? 'Copied' : 'Copy'}
                                        </button>
                                    )}
                                    {isTranscriptExpanded ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
                                </div>
                            </div>

                            {/* Collapsible Transcript Body */}
                            {rec.isTranscribing ? (
                                <div className="flex items-center space-x-2 text-slate-500 dark:text-slate-400 py-3 px-2 bg-slate-50/50 dark:bg-slate-800/50 rounded animate-pulse">
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                    <span className="text-sm italic">Generating transcript...</span>
                                </div>
                            ) : (
                                isTranscriptExpanded && (
                                    <div className="mt-2 bg-white dark:bg-slate-900 p-3 sm:p-4 rounded-lg border border-slate-100 dark:border-slate-800 shadow-inner bg-slate-50/30 dark:bg-slate-950/30">
                                        {renderFormattedTranscript(mainTranscript)}
                                    </div>
                                )
                            )}
                        </div>
                    )}

                    {/* Expanded Controls for non-editing state */}
                    {editingId !== rec.id && (
                        <div className="mt-4 flex items-center justify-between border-t border-slate-100 dark:border-slate-800 pt-3">
                            <button 
                                onClick={() => handlePlay(rec)}
                                className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                    playingId === rec.id 
                                    ? 'bg-slate-900 dark:bg-slate-700 text-white' 
                                    : 'bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700'
                                }`}
                            >
                                {playingId === rec.id ? <Pause className="w-4 h-4 mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                                {playingId === rec.id ? 'Pause' : 'Play'}
                            </button>

                            <div className="flex space-x-2">
                                <button 
                                    onClick={() => handleDownload(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-md"
                                    title="Download MP3"
                                >
                                    <Download className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => handleExportReport(rec)}
                                    className="p-2 text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-md"
                                    title="Export Transcript & Notes"
                                >
                                    <FileDown className="w-5 h-5" />
                                </button>
                                <button 
                                    onClick={() => onShare(rec)}
                                    disabled={rec.status === 'shared'}
                                    className={`flex items-center px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                                        rec.status === 'shared'
                                        ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300 cursor-default'
                                        : 'bg-fs-primary text-white hover:bg-emerald-600 shadow-sm'
                                    }`}
                                >
                                    {rec.status === 'shared' ? (
                                        <>
                                            <Check className="w-4 h-4 mr-2" />
                                            Shared to ALLi
                                        </>
                                    ) : (
                                        <>
                                            <Share2 className="w-4 h-4 mr-2" />
                                            Share to ALLi
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>
                    )}

                </div>
                </div>
                );
            })}
          </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { Mail, ArrowRight, Loader2, ShieldCheck, X } from 'lucide-react';

interface AuthScreenProps {
  onLogin: (user: User) => void;
  onCancel: () => void;
}

/**
 * Auth Screen Component
 * 
 * JUNIOR DEV NOTE:
 * This component mocks a "Passwordless" login flow (Email -> One Time Password).
 * In a real application, you would replace the simulated delays with actual API calls
 * to an identity provider like Auth0, Firebase Auth, or WorkOS.
 * 
 * Flow:
 * 1. User enters email -> System sends OTP (Mocked)
 * 2. User enters OTP -> System validates and returns token/user profile.
 */
export const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin, onCancel }) => {
  const [step, setStep] = useState<'email' | 'code'>('email');
  const [email, setEmail] = useState('');
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSendCode = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;
    setLoading(true);
    // Simulate API network delay
    await new Promise(resolve => setTimeout(resolve, 1500));
    setLoading(false);
    setStep('code');
  };

  const handleVerifyCode = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!code) return;
    setLoading(true);
    // Simulate API network delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Simulate backend role assignment logic
    // For demo purposes: containing 'manager' makes you a manager
    const determinedRole = email.toLowerCase().includes('manager') 
        ? UserRole.MANAGER 
        : UserRole.BOARD_MEMBER;

    // Create the session object
    const user: User = {
        email,
        role: determinedRole,
        isAuthenticated: true
    };

    setLoading(false);
    onLogin(user);
  };

  return (
    <div className="fixed inset-0 z-50 min-h-screen bg-fs-dark/95 backdrop-blur-sm flex flex-col items-center justify-center p-4 animate-in fade-in duration-200">
      <div className="w-full max-w-md bg-white dark:bg-slate-900 rounded-2xl shadow-2xl overflow-hidden relative">

        {/* Close Button */}
        <button 
          onClick={onCancel}
          className="absolute top-4 right-4 p-2 text-slate-400 hover:text-white hover:bg-slate-800/50 rounded-full transition-colors z-10"
          title="Cancel login"
        >
          <X className="w-5 h-5" />
        </button>

        {/* Branding Header */}
        <div className="bg-fs-darker p-8 text-center border-b border-slate-800">
             <div className="flex justify-center mb-4">
                 <div className="h-12 w-12 bg-gradient-to-br from-fs-primary to-emerald-600 rounded-xl flex items-center justify-center text-white font-bold text-3xl shadow-lg shadow-fs-primary/20 mb-2">
                   <span className="font-sans">F</span>
                 </div>
             </div>
             <div className="flex flex-col items-center justify-center">
                <span className="text-2xl font-bold text-white tracking-tight">FRONTST<span className="text-fs-primary">Ξ</span>PS</span>
                <span className="text-sm text-slate-400 font-bold tracking-widest uppercase mt-1">Note Taker</span>
             </div>
             <p className="text-slate-500 text-xs mt-4">Secure recording companion for ALLi</p>
        </div>

        <div className="p-8">
            {step === 'email' ? (
                <form onSubmit={handleSendCode} className="space-y-6">
                    <div>
                        <label htmlFor="email" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Email Address</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <Mail className="h-5 w-5 text-slate-400" />
                            </div>
                            <input
                                id="email"
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                className="block w-full pl-10 pr-3 py-3 border border-slate-300 dark:border-slate-700 rounded-lg focus:ring-fs-primary focus:border-fs-primary text-sm bg-white dark:bg-slate-950 text-slate-900 dark:text-white"
                                placeholder="name@community.com"
                                required
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex justify-center items-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <>Continue <ArrowRight className="ml-2 w-4 h-4" /></>}
                    </button>

                    <p className="text-xs text-center text-slate-400">
                        Powered by WorkOS Passwordless Auth
                    </p>
                </form>
            ) : (
                <form onSubmit={handleVerifyCode} className="space-y-6">
                    <div className="text-center mb-6">
                        <div className="bg-green-50 dark:bg-green-900/30 w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-3">
                            <Mail className="w-6 h-6 text-green-600 dark:text-green-400" />
                        </div>
                        <h3 className="text-lg font-medium text-slate-900 dark:text-white">Check your email</h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">We sent a verification code to <span className="font-medium text-slate-800 dark:text-slate-200">{email}</span></p>
                    </div>

                    <div>
                        <label htmlFor="code" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Verification Code</label>
                        <input
                            id="code"
                            type="text"
                            value={code}
                            onChange={(e) => setCode(e.target.value)}
                            className="block w-full text-center tracking-[0.5em] text-2xl font-mono py-3 border border-slate-300 dark:border-slate-700 rounded-lg focus:ring-fs-primary focus:border-fs-primary bg-white dark:bg-slate-950 text-slate-900 dark:text-white"
                            placeholder="123456"
                            maxLength={6}
                            required
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex justify-center items-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-fs-primary hover:bg-emerald-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <><ShieldCheck className="mr-2 w-4 h-4" /> Verify & Login</>}
                    </button>

                    <button 
                        type="button"
                        onClick={() => setStep('email')}
                        className="w-full text-sm text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200"
                    >
                        Back to email
                    </button>
                </form>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Mail, Users, FileCheck, Check, ArrowRight, X, Sparkles, Loader2 } from 'lucide-react';
import { Recording } from '../types';

interface WorkflowSelectorProps {
  recording: Recording;
  onClose: () => void;
}

type WorkflowType = 'email' | 'board' | 'arc' | null;

export const WorkflowSelector: React.FC<WorkflowSelectorProps> = ({ recording, onClose }) => {
  const [selected, setSelected] = useState<WorkflowType>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isFinished, setIsFinished] = useState(false);

  const handleSelect = async (type: WorkflowType) => {
    setSelected(type);
    setIsProcessing(true);

    // Simulate API workflow trigger
    await new Promise(resolve => setTimeout(resolve, 1800));

    setIsProcessing(false);
    setIsFinished(true);
  };

  const workflows = [
    {
      id: 'email',
      title: 'Email me a summary',
      description: 'Receive a high-level overview of key decisions directly in your inbox.',
      icon: Mail,
      color: 'text-blue-500',
      bgColor: 'bg-blue-50 dark:bg-blue-900/20',
    },
    {
      id: 'board',
      title: 'Distribute Board Report',
      description: 'Generate a detailed PDF report and share it with all verified board members.',
      icon: Users,
      color: 'text-emerald-500',
      bgColor: 'bg-emerald-50 dark:bg-emerald-900/20',
    },
    {
      id: 'arc',
      title: 'Generate ARC Letters',
      description: 'Draft approval or rejection letters for architectural requests discussed.',
      icon: FileCheck,
      color: 'text-purple-500',
      bgColor: 'bg-purple-50 dark:bg-purple-900/20',
    }
  ];

  if (isFinished) {
    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
        <div className="w-full max-w-md bg-white dark:bg-slate-900 rounded-3xl p-8 text-center shadow-2xl border border-slate-100 dark:border-slate-800 animate-in zoom-in duration-300">
          <div className="w-20 h-20 bg-fs-primary/10 rounded-full flex items-center justify-center mx-auto mb-6">
            <Check className="w-10 h-10 text-fs-primary" />
          </div>
          <h2 className="text-2xl font-black text-slate-900 dark:text-white mb-2 tracking-tight">Workflow Initiated!</h2>
          <p className="text-slate-500 dark:text-slate-400 mb-8 text-sm leading-relaxed">
            The requested task has been added to our automation queue. You'll receive a notification in ALLi once it's finalized.
          </p>
          <button 
            onClick={onClose}
            className="w-full py-4 bg-fs-dark dark:bg-slate-700 text-white font-bold rounded-2xl hover:bg-slate-800 transition-all shadow-lg"
          >
            CONTINUE TO ARCHIVE
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="w-full max-w-xl bg-white dark:bg-slate-900 rounded-[2.5rem] overflow-hidden shadow-2xl border border-slate-100 dark:border-slate-800 animate-in slide-in-from-bottom-8 duration-500">

        {/* Header */}
        <div className="p-8 pb-4 text-center">
            <div className="flex justify-center mb-4">
                <div className="bg-fs-primary/10 p-3 rounded-2xl">
                    <Sparkles className="w-6 h-6 text-fs-primary" />
                </div>
            </div>
            <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">Recording Saved! What's next?</h2>
            <p className="text-slate-500 dark:text-slate-400 text-sm mt-2">Choose an automated workflow for <span className="font-bold text-slate-700 dark:text-slate-200">{recording.title}</span>.</p>
        </div>

        {/* Workflow Grid */}
        <div className="p-8 pt-0 space-y-3">
          {workflows.map((wf) => (
            <button
              key={wf.id}
              disabled={isProcessing}
              onClick={() => handleSelect(wf.id as WorkflowType)}
              className={`w-full group flex items-start gap-4 p-5 rounded-2xl border border-slate-100 dark:border-slate-800 text-left transition-all ${
                isProcessing && selected === wf.id 
                  ? 'bg-fs-primary/5 border-fs-primary' 
                  : 'bg-slate-50/50 dark:bg-slate-800/30 hover:bg-white dark:hover:bg-slate-800 hover:shadow-xl hover:border-slate-200 dark:hover:border-slate-700'
              }`}
            >
              <div className={`p-3 rounded-xl ${wf.bgColor} ${wf.color} flex-shrink-0 transition-transform group-hover:scale-110`}>
                {isProcessing && selected === wf.id ? (
                  <Loader2 className="w-6 h-6 animate-spin" />
                ) : (
                  <wf.icon className="w-6 h-6" />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center justify-between">
                  <h3 className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-wider">{wf.title}</h3>
                  <ArrowRight className="w-4 h-4 text-slate-300 group-hover:text-fs-primary transition-colors" />
                </div>
                <p className="text-xs text-slate-500 dark:text-slate-400 mt-1 leading-relaxed">
                  {wf.description}
                </p>
              </div>
            </button>
          ))}

          <button 
            onClick={onClose}
            disabled={isProcessing}
            className="w-full mt-4 py-3 text-xs font-bold text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 uppercase tracking-[0.2em] transition-colors"
          >
            Skip for now
          </button>
        </div>

        {/* Footer Hint */}
        <div className="bg-slate-50 dark:bg-slate-800/50 p-6 border-t border-slate-100 dark:border-slate-800 flex items-center justify-center gap-2">
            <Sparkles className="w-3.5 h-3.5 text-fs-primary" />
            <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Powered by Gemini Board Intelligence</span>
        </div>
      </div>
    </div>
  );
};

