import { WorkflowSelector } from './components/WorkflowSelector';
import { 
  LogOut, Mic, History, LogIn, 
  Moon, Sun, Link as LinkIcon, 
  Video, Settings, ChevronRight
} from 'lucide-react';
import { transcribeAudio } from './services/aiService';
import { getAudioBlob, deleteAudioBlob } from './services/dbService';
import { sendNotification, getNotificationPermission } from './services/notificationService';
import { logGuestActivity } from './services/loggingService';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [recordings, setRecordings] = useState<Recording[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [currentView, setCurrentView] = useState<'record' | 'history' | 'integrations' | 'companion'>('record');
  const [showAuth, setShowAuth] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(() => localStorage.getItem('fs_theme') === 'dark');
  const [activeTranscription, setActiveTranscription] = useState<{ startTime: number; title: string } | null>(null);
  const [lastCompletedRecording, setLastCompletedRecording] = useState<Recording | null>(null);
  const [showWorkflowSelector, setShowWorkflowSelector] = useState(false);

  useEffect(() => {
    const session = getUserSession();
    if (session) setUser(session);
    setRecordings(getRecordingsMeta());
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (!isLoading) saveRecordingsMeta(recordings);
  }, [recordings, isLoading]);

  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) {
      root.classList.add('dark');
      localStorage.setItem('fs_theme', 'dark');
    } else {
      root.classList.remove('dark');
      localStorage.setItem('fs_theme', 'light');
    }
  }, [isDarkMode]);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    saveUserSession(newUser);
    setShowAuth(false);
  };

  const handleLogout = () => {
    setUser(null);
    clearUserSession();
    if (['integrations', 'companion'].includes(currentView)) setCurrentView('record');
  };

  const handleUpdateRecording = (updated: Recording) => {
    setRecordings(prev => prev.map(r => r.id === updated.id ? updated : r));
  };

  const handleDeleteRecording = async (id: string, blobId: string) => {
    if (window.confirm("Are you sure you want to permanently delete this recording? This action cannot be undone.")) {
      try {
        await deleteAudioBlob(blobId);
        setRecordings(prev => prev.filter(r => r.id !== id));
      } catch (error) {
        console.error("Failed to delete recording:", error);
        alert("An error occurred while trying to delete the recording.");
      }
    }
  };

  const handleRecordingComplete = async (blobId: string, duration: number, defaultName: string, note: string, language: string) => {
    const newRec: Recording = { 
      id: crypto.randomUUID(), 
      title: defaultName, 
      timestamp: new Date().toISOString(), 
      duration, 
      note, 
      blobId, 
      status: 'ready', 
      isTranscribing: true, 
      language 
    };

    if (!user) logGuestActivity('RECORDING_COMPLETED', { recordingId: newRec.id, duration });

    setRecordings(prev => [newRec, ...prev]);
    setLastCompletedRecording(newRec);
    setShowWorkflowSelector(true);

    // Set active transcription state for the Recorder component to display
    setActiveTranscription({ startTime: Date.now(), title: defaultName });

    try {
      const blob = await getAudioBlob(blobId);
      if (blob) {
        const transcription = await transcribeAudio(blob, language);
        setRecordings(prev => prev.map(rec => rec.id === newRec.id ? { ...rec, transcription, isTranscribing: false } : rec));
        sendNotification("Transcription Ready", `Processing complete for "${defaultName}"`);
      }
    } catch (error) {
      setRecordings(prev => prev.map(rec => rec.id === newRec.id ? { ...rec, isTranscribing: false } : rec));
    } finally {
      // Clear the active transcription state once finished
      setActiveTranscription(null);
    }
  };

  const isAnyAccountConnected = user?.connectedAccounts?.some(a => a.connected);

  if (isLoading) return null;

  const NavItem = ({ view, icon: Icon, label, badge }: { view: typeof currentView, icon: any, label: string, badge?: number }) => (
    <button 
      onClick={() => setCurrentView(view)} 
      className={`w-full flex items-center justify-between px-3 py-2.5 rounded-xl transition-all duration-200 group ${
        currentView === view 
          ? 'bg-fs-primary/10 text-fs-primary border border-fs-primary/20' 
          : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800/50 hover:text-slate-900 dark:hover:text-slate-200'
      }`}
    >
      <div className="flex items-center gap-3">
        <Icon className={`w-5 h-5 transition-transform group-hover:scale-110 ${currentView === view ? 'text-fs-primary' : ''}`} />
        <span className="text-sm font-semibold tracking-tight">{label}</span>
      </div>
      {badge !== undefined && badge > 0 ? (
        <span className="text-[10px] bg-fs-primary text-white px-1.5 py-0.5 rounded-full font-bold">{badge}</span>
      ) : (
        <ChevronRight className={`w-4 h-4 opacity-0 group-hover:opacity-100 transition-opacity ${currentView === view ? 'opacity-100 text-fs-primary/50' : ''}`} />
      )}
    </button>
  );

  return (
    <div className="h-screen bg-slate-50 dark:bg-slate-950 flex flex-col md:flex-row overflow-hidden relative font-sans">
      {showAuth && <AuthScreen onLogin={handleLogin} onCancel={() => setShowAuth(false)} />}

      {showWorkflowSelector && lastCompletedRecording && (
        <WorkflowSelector 
          recording={lastCompletedRecording} 
          onClose={() => {
            setShowWorkflowSelector(false);
            setCurrentView('history');
          }} 
        />
      )}

      {/* Desktop Sidebar */}
      <aside className="hidden md:flex md:w-72 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 flex-shrink-0 flex-col z-30">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-10">
            <div className="h-10 w-10 bg-gradient-to-br from-fs-primary to-emerald-600 rounded-xl flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-fs-primary/20">
              F
            </div>
            <div>
              <h1 className="text-lg font-black text-slate-900 dark:text-white leading-none tracking-tight">FRONTSTEPS</h1>
              <p className="text-[10px] text-fs-primary font-bold uppercase tracking-[0.2em] mt-1">Note Taker</p>
            </div>
          </div>

          <div className="space-y-6">
            <section>
              <p className="px-3 mb-3 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Core</p>
              <div className="space-y-1">
                <NavItem view="record" icon={Mic} label="New Recording" />
                <NavItem view="history" icon={History} label="History" badge={recordings.length} />
              </div>
            </section>

            {user && (
              <section>
                <p className="px-3 mb-3 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">Connect</p>
                <div className="space-y-1">
                  <NavItem view="integrations" icon={LinkIcon} label="Integrations" />
                  {isAnyAccountConnected && (
                    <NavItem view="companion" icon={Video} label="Meeting HUD" />
                  )}
                </div>
              </section>
            )}
          </div>
        </div>

        <div className="mt-auto p-4 border-t border-slate-100 dark:border-slate-800 space-y-4">
          <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-2xl flex items-center justify-between border border-slate-200 dark:border-slate-700">
             <div className="flex items-center gap-2">
               {isDarkMode ? <Moon className="w-4 h-4 text-slate-400" /> : <Sun className="w-4 h-4 text-amber-500" />}
               <span className="text-xs font-bold text-slate-600 dark:text-slate-300">{isDarkMode ? 'Dark' : 'Light'}</span>
             </div>
             <button 
                onClick={() => setIsDarkMode(!isDarkMode)}
                className={`relative w-10 h-5 rounded-full transition-colors duration-300 ${isDarkMode ? 'bg-fs-primary' : 'bg-slate-300'}`}
             >
                <div className={`absolute top-1 left-1 w-3 h-3 bg-white rounded-full transition-transform duration-300 ${isDarkMode ? 'translate-x-5' : ''}`} />
             </button>
          </div>

          <div className="flex items-center justify-between p-2">
            {user ? (
              <div className="flex items-center justify-between w-full group">
                <div className="flex items-center gap-3 min-w-0">
                  <div className="w-9 h-9 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center text-xs font-bold text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-700">
                    {user.email[0].toUpperCase()}
                  </div>
                  <div className="flex flex-col min-w-0">
                    <span className="text-xs font-bold text-slate-900 dark:text-white truncate">{user.email.split('@')[0]}</span>
                    <span className="text-[10px] text-slate-500 uppercase font-bold tracking-tighter truncate">{user.role.replace('_', ' ')}</span>
                  </div>
                </div>
                <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                  <LogOut className="w-4 h-4" />
                </button>
              </div>
            ) : (
              <button 
                onClick={() => setShowAuth(true)} 
                className="w-full py-2.5 bg-slate-900 dark:bg-fs-primary text-white rounded-xl text-xs font-bold shadow-lg shadow-slate-900/10 hover:scale-[1.02] active:scale-95 transition-all"
              >
                Sign In to ALLi
              </button>
            )}
          </div>
        </div>
      </aside>

      {/* Mobile Top Navigation */}
      <header className="md:hidden bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 py-3 flex items-center justify-between z-40">
        <div className="flex items-center gap-2">
          <div className="h-7 w-7 bg-fs-primary rounded-lg flex items-center justify-center text-white font-bold text-lg">F</div>
          <span className="font-bold text-slate-900 dark:text-white tracking-tight">FRONTSTEPS</span>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 text-slate-500 dark:text-slate-400">
            {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
          {user ? (
            <button onClick={handleLogout} className="p-2 text-slate-500 dark:text-slate-400">
              <LogOut className="w-5 h-5" />
            </button>
          ) : (
            <button onClick={() => setShowAuth(true)} className="text-fs-primary font-bold text-sm">Login</button>
          )}
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col min-w-0 h-full overflow-hidden bg-white dark:bg-slate-950">
        <div className="flex-1 overflow-y-auto">
          {currentView === 'record' && (
            <div className="h-full flex items-center justify-center p-6 md:p-12">
               <div className="w-full max-w-xl">
                 <div className="text-center mb-10">
                   <h2 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight">Record Meeting</h2>
                   <p className="text-slate-500 dark:text-slate-400 text-base mt-2 max-w-lg mx-auto leading-relaxed">High-fidelity audio capture with real-time transcription.</p>
                 </div>
                 <Recorder onRecordingComplete={handleRecordingComplete} activeTranscription={activeTranscription} />
               </div>
            </div>
          )}

          {currentView === 'history' && (
            <div className="p-6 md:p-12 max-w-5xl mx-auto w-full">
              <div className="text-center mb-10">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight">Meeting Archives</h2>
                <p className="text-slate-500 dark:text-slate-400 text-base mt-2 max-w-lg mx-auto leading-relaxed">Access and manage all historical board minutes.</p>
              </div>
              <RecordingList 
                recordings={recordings} 
                currentUser={user} 
                onUpdateRecording={handleUpdateRecording} 
                onDeleteRecording={handleDeleteRecording}
                onShare={() => {}} 
              />
            </div>
          )}

          {currentView === 'integrations' && user && <Integrations user={user} onUpdateUser={setUser} />}
          {currentView === 'companion' && <MeetingCompanion />}
        </div>

        {/* Mobile Bottom Navigation Bar */}
        <nav className="md:hidden bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 flex items-center justify-around py-3 px-2 z-40">
           <button onClick={() => setCurrentView('record')} className={`flex flex-col items-center gap-1 ${currentView === 'record' ? 'text-fs-primary' : 'text-slate-400'}`}>
              <Mic className="w-5 h-5" />
              <span className="text-[10px] font-bold uppercase">Record</span>
           </button>
           <button onClick={() => setCurrentView('history')} className={`flex flex-col items-center gap-1 ${currentView === 'history' ? 'text-fs-primary' : 'text-slate-400'}`}>
              <History className="w-5 h-5" />
              <span className="text-[10px] font-bold uppercase">History</span>
           </button>
           {user && (
             <button onClick={() => setCurrentView('integrations')} className={`flex flex-col items-center gap-1 ${currentView === 'integrations' ? 'text-fs-primary' : 'text-slate-400'}`}>
                <Settings className="w-5 h-5" />
                <span className="text-[10px] font-bold uppercase">Settings</span>
             </button>
           )}
        </nav>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SignalHigh, Play, Pause, Trash2, Check, X, Upload, Globe, ChevronDown, Save, Sparkles, Volume2 } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string, note: string, language: string) => void;
  activeTranscription?: { startTime: number; title: string } | null;
}

const LANGUAGES = [
    { code: 'English', label: 'English' },
    { code: 'Spanish', label: 'Español (Spanish)' },
    { code: 'French', label: 'Français (French)' },
    { code: 'German', label: 'Deutsch (German)' },
    { code: 'Portuguese', label: 'Português (Portuguese)' },
    { code: 'Chinese', label: '中文 (Chinese)' },
];

const AUTOSAVE_KEY = 'fs_recorder_autosave_note';

export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete, activeTranscription }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [note, setNote] = useState(''); 
  const [uploadedFileName, setUploadedFileName] = useState<string | null>(null);
  const [language, setLanguage] = useState('English');
  const [sensitivity, setSensitivity] = useState(1.0); // 1.0 = 100% gain
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [elapsedTranscriptionTime, setElapsedTranscriptionTime] = useState(0);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  // Load draft on mount
  useEffect(() => {
    const savedNote = localStorage.getItem(AUTOSAVE_KEY);
    if (savedNote) {
      setNote(savedNote);
      setLastSaved(new Date());
    }
  }, []);

  // Transcription Timer logic
  useEffect(() => {
    let interval: number | null = null;
    if (activeTranscription) {
      interval = window.setInterval(() => {
        setElapsedTranscriptionTime(Math.floor((Date.now() - activeTranscription.startTime) / 1000));
      }, 1000);
    } else {
      setElapsedTranscriptionTime(0);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [activeTranscription]);

  // Auto-save logic
  useEffect(() => {
    const interval = setInterval(() => {
      if (note.trim()) {
        localStorage.setItem(AUTOSAVE_KEY, note);
        setLastSaved(new Date());
        setIsAutoSaving(true);
        setTimeout(() => setIsAutoSaving(false), 2000);
      }
    }, 10000);

    const handleBeforeUnload = () => {
      if (note.trim()) {
        localStorage.setItem(AUTOSAVE_KEY, note);
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);

    return () => {
      clearInterval(interval);
      window.removeEventListener('beforeunload', handleBeforeUnload);
      if (note.trim()) {
        localStorage.setItem(AUTOSAVE_KEY, note);
      }
    };
  }, [note]);

  // Update gain in real-time if sensitivity changes while recording
  useEffect(() => {
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.setTargetAtTime(sensitivity, audioContextRef.current?.currentTime || 0, 0.1);
    }
  }, [sensitivity]);

  const startRecording = async () => {
    setError(null);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setDuration(0);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Setup Web Audio for gain control
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const audioCtx = new AudioContextClass();
      audioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const gainNode = audioCtx.createGain();
      gainNode.gain.value = sensitivity;
      gainNodeRef.current = gainNode;

      const destination = audioCtx.createMediaStreamDestination();

      // Route: Mic -> Gain -> Destination -> MediaRecorder
      source.connect(gainNode);
      gainNode.connect(destination);

      const mimeType = MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : 'audio/mp4';
      const recorder = new MediaRecorder(destination.stream, { mimeType });
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      recorder.ondataavailable = (e) => e.data.size > 0 && chunksRef.current.push(e.data);
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const url = URL.createObjectURL(blob);
        setRecordedBlob(blob);
        setAudioUrl(url);
        setIsRecording(false);
        streamRef.current?.getTracks().forEach(track => track.stop());
        if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
        if (audioContextRef.current) audioContextRef.current.close();
      };

      recorder.start();
      setIsRecording(true);
      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => setDuration(Math.floor((Date.now() - startTime) / 1000)), 1000);

      // Start visualizer from the gain node
      const analyser = audioCtx.createAnalyser();
      gainNode.connect(analyser);
      analyser.fftSize = 256;

      const ctx = canvasRef.current?.getContext('2d');
      if (ctx) {
        const draw = () => {
            animationFrameRef.current = requestAnimationFrame(draw);
            const dataArray = new Uint8Array(analyser.frequencyBinCount);
            analyser.getByteFrequencyData(dataArray);
            ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
            ctx.fillStyle = '#47b881';
            for (let i = 0; i < 20; i++) {
                const barHeight = (dataArray[i * 2] / 255) * canvasRef.current!.height;
                ctx.fillRect(i * 6, (canvasRef.current!.height - barHeight) / 2, 4, barHeight);
            }
        };
        draw();
      }

    } catch (err: any) {
      setError(err.name === 'NotAllowedError' ? "Microphone access denied." : "Failed to start recorder.");
    }
  };

  const stopRecording = () => mediaRecorderRef.current?.stop();

  const handleSave = async () => {
    if (!recordedBlob) return;
    setIsProcessing(true);
    const blobId = `rec_${Date.now()}`;
    try {
        await saveAudioBlob(blobId, recordedBlob);
        localStorage.removeItem(AUTOSAVE_KEY);
        onRecordingComplete(blobId, duration, uploadedFileName?.replace(/\.[^/.]+$/, "") || `Meeting ${new Date().toLocaleDateString()}`, note, language);
    } catch (err) {
        setError("Failed to save.");
    } finally {
        setIsProcessing(false);
        setNote('');
        setAudioUrl(null);
        setRecordedBlob(null);
    }
  };

  const formatTime = (seconds: number) => `${Math.floor(seconds / 60)}:${String(seconds % 60).padStart(2, '0')}`;

  return (
    <div className="w-full space-y-6">
      <input type="file" accept="audio/*" className="hidden" id="file-upload" onChange={(e) => {
        const file = e.target.files?.[0];
        if (file) {
            setRecordedBlob(file);
            setAudioUrl(URL.createObjectURL(file));
            setUploadedFileName(file.name);
        }
      }} />

      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-10 shadow-2xl shadow-slate-200 dark:shadow-none border border-slate-100 dark:border-slate-800 flex flex-col items-center transition-all duration-300">

        {!recordedBlob ? (
          <>
            <div className="h-12 w-full mb-6 flex justify-center">
              {isRecording ? <canvas ref={canvasRef} width={120} height={40} /> : <div className="text-slate-300"><SignalHigh className="w-10 h-10 opacity-20" /></div>}
            </div>

            <div className="text-6xl font-black text-slate-900 dark:text-white mb-10 tabular-nums">
              {formatTime(duration)}
            </div>

            <div className="flex flex-col items-center gap-6 w-full">
              {!isRecording ? (
                <button onClick={startRecording} className="w-24 h-24 bg-fs-primary text-white rounded-full flex items-center justify-center shadow-xl shadow-fs-primary/30 hover:scale-110 active:scale-95 transition-all">
                  <Mic className="w-10 h-10" />
                </button>
              ) : (
                <div className="relative">
                  {/* Multi-layered ripple pings */}
                  <div className="absolute inset-0 rounded-full bg-red-500 animate-ping opacity-20" style={{ animationDuration: '3s' }} />
                  <div className="absolute inset-0 rounded-full bg-red-500 animate-ping opacity-10" style={{ animationDuration: '2s', animationDelay: '0.5s' }} />
                  <div className="absolute inset-0 rounded-full bg-red-500 animate-pulse opacity-40 scale-110" />

                  <button 
                    onClick={stopRecording} 
                    className="relative z-10 w-24 h-24 bg-red-500 text-white rounded-full flex items-center justify-center shadow-2xl shadow-red-500/50 hover:scale-105 active:scale-95 transition-all"
                  >
                    <Square className="w-8 h-8 fill-current" />
                  </button>
                </div>
              )}

              {/* Controls Group */}
              <div className="flex flex-wrap items-center justify-center gap-4">
                  {/* Language Selector */}
                  <div className="relative inline-block">
                    <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
                      <Globe className="w-4 h-4 text-slate-400" />
                    </div>
                    <select 
                      value={language}
                      onChange={(e) => setLanguage(e.target.value)}
                      className="appearance-none pl-9 pr-10 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-300 focus:outline-none focus:ring-2 focus:ring-fs-primary/30 transition-all cursor-pointer"
                    >
                      {LANGUAGES.map(lang => (
                        <option key={lang.code} value={lang.code}>{lang.label}</option>
                      ))}
                    </select>
                    <div className="absolute inset-y-0 right-3 flex items-center pointer-events-none">
                      <ChevronDown className="w-3 h-3 text-slate-400" />
                    </div>
                  </div>

                  {/* Sensitivity Slider */}
                  <div className="flex items-center gap-3 bg-slate-50 dark:bg-slate-800 px-4 py-2 rounded-xl border border-slate-200 dark:border-slate-700">
                    <div className="text-slate-400" title="Adjust Input Sensitivity">
                      <Volume2 className="w-4 h-4" />
                    </div>
                    <input 
                      type="range"
                      min="0.5"
                      max="2.5"
                      step="0.1"
                      value={sensitivity}
                      onChange={(e) => setSensitivity(parseFloat(e.target.value))}
                      className="w-20 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-fs-primary"
                    />
                    <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 w-8">{Math.round(sensitivity * 100)}%</span>
                  </div>
              </div>

              {!isRecording && (
                <button onClick={() => document.getElementById('file-upload')?.click()} className="text-xs font-bold text-slate-500 dark:text-slate-400 hover:text-fs-primary flex items-center gap-2 uppercase tracking-widest">
                  <Upload className="w-4 h-4" /> Import Audio
                </button>
              )}

              {(isRecording || note) && (
                <div className="w-full space-y-2">
                  <div className="flex items-center justify-between px-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Live Meeting Notes ({language})</label>
                    <div className="flex items-center gap-1.5">
                      <div className={`w-1.5 h-1.5 rounded-full ${isAutoSaving ? 'bg-fs-primary animate-ping' : 'bg-slate-300'}`} />
                      <span className="text-[9px] font-bold text-slate-400 uppercase">
                        {isAutoSaving ? 'Auto-saving...' : (lastSaved ? `Draft saved ${lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}` : '')}
                      </span>
                    </div>
                  </div>
                  <textarea 
                    value={note}
                    onChange={(e) => setNote(e.target.value)}
                    placeholder="Type live annotations here..."
                    className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl text-sm border-none focus:ring-2 focus:ring-fs-primary/50 resize-none h-32 dark:text-white shadow-inner"
                  />
                </div>
              )}
            </div>
          </>
        ) : (
          <div className="w-full flex flex-col items-center">
            <div className="w-full bg-slate-50 dark:bg-slate-800 p-6 rounded-3xl mb-8 flex flex-col items-center border border-slate-100 dark:border-slate-800 shadow-inner">
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Review Mode ({language})</p>
               <h3 className="text-sm font-bold text-slate-700 dark:text-slate-200 mb-4 truncate max-w-full px-4">{uploadedFileName || 'New Recording'}</h3>
               <div className="flex items-center gap-6">
                 <button onClick={() => setIsPlaying(!isPlaying)} className="w-16 h-16 bg-slate-900 dark:bg-slate-700 text-white rounded-full flex items-center justify-center shadow-lg hover:scale-105 transition-transform">
                   {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
                 </button>
               </div>
            </div>

            <div className="w-full space-y-2 mb-6">
              <div className="flex items-center justify-between px-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Finalize Notes</label>
                {lastSaved && (
                  <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1">
                    <Save className="w-2.5 h-2.5" /> Draft Persisted
                  </span>
                )}
              </div>
              <textarea 
                value={note}
                onChange={(e) => setNote(e.target.value)}
                placeholder="Finalize notes before saving..."
                className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl text-sm border-none focus:ring-2 focus:ring-fs-primary/50 resize-none h-32 dark:text-white shadow-inner"
              />
            </div>

            <div className="flex w-full gap-4">
               <button onClick={() => {
                 if (window.confirm("Are you sure? This will discard the session.")) {
                   setRecordedBlob(null);
                   setAudioUrl(null);
                 }
               }} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 font-bold rounded-2xl hover:bg-red-50 hover:text-red-500 transition-colors">DISCARD</button>
               <button onClick={handleSave} disabled={isProcessing} className="flex-[2] py-4 bg-fs-primary text-white font-bold rounded-2xl shadow-lg shadow-fs-primary/20 flex items-center justify-center gap-2 hover:scale-[1.02] transition-transform active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Check className="w-5 h-5" />}
                 {isProcessing ? 'SAVING...' : 'SAVE TO HISTORY'}
               </button>
            </div>
          </div>
        )}
      </div>

      {/* Transcription Progress Indicator */}
      {activeTranscription && (
        <div className="bg-slate-900 dark:bg-slate-100 p-5 rounded-3xl shadow-xl flex items-center gap-4 animate-in slide-in-from-bottom-4 duration-500">
           <div className="relative">
             <div className="w-10 h-10 bg-fs-primary rounded-full flex items-center justify-center">
               <Sparkles className="w-5 h-5 text-white animate-pulse" />
             </div>
             <div className="absolute -inset-1 bg-fs-primary rounded-full animate-ping opacity-20 pointer-events-none" />
           </div>
           <div className="flex-1 min-w-0">
             <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-0.5">AI Transcription in Progress</p>
             <h4 className="text-sm font-bold text-white dark:text-slate-900 truncate">{activeTranscription.title}</h4>
           </div>
           <div className="text-right">
             <div className="text-sm font-mono font-bold text-fs-primary tracking-tighter tabular-nums">
               {formatTime(elapsedTranscriptionTime)}
             </div>
             <p className="text-[10px] text-slate-500 dark:text-slate-400 font-bold uppercase">Elapsed</p>
           </div>
        </div>
      )}

      {error && <p className="mt-4 text-center text-xs font-bold text-red-500 bg-red-50 dark:bg-red-900/10 py-2 rounded-lg">{error}</p>}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SignalHigh, Play, Pause, Trash2, Check, X, Upload, Globe, ChevronDown, Save, Sparkles, Volume2 } from 'lucide-react';
import { saveAudioBlob } from '../services/dbService';

interface RecorderProps {
  onRecordingComplete: (blobId: string, duration: number, defaultName: string, note: string, language: string) => void;
  activeTranscription?: { startTime: number; title: string } | null;
}

const LANGUAGES = [
    { code: 'English', label: 'English' },
    { code: 'Spanish', label: 'Español (Spanish)' },
    { code: 'French', label: 'Français (French)' },
    { code: 'German', label: 'Deutsch (German)' },
    { code: 'Portuguese', label: 'Português (Portuguese)' },
    { code: 'Chinese', label: '中文 (Chinese)' },
];

const AUTOSAVE_KEY = 'fs_recorder_autosave_note';

export const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete, activeTranscription }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [note, setNote] = useState(''); 
  const [uploadedFileName, setUploadedFileName] = useState<string | null>(null);
  const [language, setLanguage] = useState('English');
  const [sensitivity, setSensitivity] = useState(1.0); // 1.0 = 100% gain
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [elapsedTranscriptionTime, setElapsedTranscriptionTime] = useState(0);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerIntervalRef = useRef<number | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const chunksRef = useRef<BlobPart[]>([]);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  // Load draft on mount
  useEffect(() => {
    const savedNote = localStorage.getItem(AUTOSAVE_KEY);
    if (savedNote) {
      setNote(savedNote);
      setLastSaved(new Date());
    }
  }, []);

  // Transcription Timer logic
  useEffect(() => {
    let interval: number | null = null;
    if (activeTranscription) {
      interval = window.setInterval(() => {
        setElapsedTranscriptionTime(Math.floor((Date.now() - activeTranscription.startTime) / 1000));
      }, 1000);
    } else {
      setElapsedTranscriptionTime(0);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [activeTranscription]);

  // Auto-save logic
  useEffect(() => {
    const interval = setInterval(() => {
      if (note.trim()) {
        localStorage.setItem(AUTOSAVE_KEY, note);
        setLastSaved(new Date());
        setIsAutoSaving(true);
        setTimeout(() => setIsAutoSaving(false), 2000);
      }
    }, 10000);

    const handleBeforeUnload = () => {
      if (note.trim()) {
        localStorage.setItem(AUTOSAVE_KEY, note);
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);

    return () => {
      clearInterval(interval);
      window.removeEventListener('beforeunload', handleBeforeUnload);
      if (note.trim()) {
        localStorage.setItem(AUTOSAVE_KEY, note);
      }
    };
  }, [note]);

  // Update gain in real-time if sensitivity changes while recording
  useEffect(() => {
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.setTargetAtTime(sensitivity, audioContextRef.current?.currentTime || 0, 0.1);
    }
  }, [sensitivity]);

  const startRecording = async () => {
    setError(null);
    setRecordedBlob(null);
    setAudioUrl(null);
    setUploadedFileName(null);
    setDuration(0);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const audioCtx = new AudioContextClass();
      audioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const gainNode = audioCtx.createGain();
      gainNode.gain.value = sensitivity;
      gainNodeRef.current = gainNode;

      const destination = audioCtx.createMediaStreamDestination();
      source.connect(gainNode);
      gainNode.connect(destination);

      const mimeType = MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : 'audio/mp4';
      const recorder = new MediaRecorder(destination.stream, { mimeType });
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];

      recorder.ondataavailable = (e) => e.data.size > 0 && chunksRef.current.push(e.data);
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const url = URL.createObjectURL(blob);
        setRecordedBlob(blob);
        setAudioUrl(url);
        setIsRecording(false);
        streamRef.current?.getTracks().forEach(track => track.stop());
        if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
        if (audioContextRef.current) audioContextRef.current.close();
      };

      recorder.start();
      setIsRecording(true);
      const startTime = Date.now();
      timerIntervalRef.current = window.setInterval(() => setDuration(Math.floor((Date.now() - startTime) / 1000)), 1000);

      const analyser = audioCtx.createAnalyser();
      gainNode.connect(analyser);
      analyser.fftSize = 256;

      const ctx = canvasRef.current?.getContext('2d');
      if (ctx) {
        const draw = () => {
            animationFrameRef.current = requestAnimationFrame(draw);
            const dataArray = new Uint8Array(analyser.frequencyBinCount);
            analyser.getByteFrequencyData(dataArray);
            ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
            ctx.fillStyle = '#47b881';
            for (let i = 0; i < 20; i++) {
                const barHeight = (dataArray[i * 2] / 255) * canvasRef.current!.height;
                ctx.fillRect(i * 6, (canvasRef.current!.height - barHeight) / 2, 4, barHeight);
            }
        };
        draw();
      }

    } catch (err: any) {
      setError(err.name === 'NotAllowedError' ? "Microphone access denied." : "Failed to start recorder.");
    }
  };

  const stopRecording = () => mediaRecorderRef.current?.stop();

  const cancelRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      // Clear onstop to prevent state change to review mode
      mediaRecorderRef.current.onstop = null;
      mediaRecorderRef.current.stop();

      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
      }

      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
      }

      if (audioContextRef.current) {
        audioContextRef.current.close();
        audioContextRef.current = null;
      }

      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
        animationFrameRef.current = null;
      }

      setIsRecording(false);
      setDuration(0);
      // We keep the notes draft in case the user wants to keep them for the next try
      // but clear the UI error
      setError(null);
    }
  };

  const handleSave = async () => {
    if (!recordedBlob) return;
    setIsProcessing(true);
    const blobId = `rec_${Date.now()}`;
    try {
        await saveAudioBlob(blobId, recordedBlob);
        localStorage.removeItem(AUTOSAVE_KEY);
        onRecordingComplete(blobId, duration, uploadedFileName?.replace(/\.[^/.]+$/, "") || `Meeting ${new Date().toLocaleDateString()}`, note, language);
    } catch (err) {
        setError("Failed to save.");
    } finally {
        setIsProcessing(false);
        setNote('');
        setAudioUrl(null);
        setRecordedBlob(null);
    }
  };

  const formatTime = (seconds: number) => `${Math.floor(seconds / 60)}:${String(seconds % 60).padStart(2, '0')}`;

  return (
    <div className="w-full space-y-6">
      <input type="file" accept="audio/*" className="hidden" id="file-upload" onChange={(e) => {
        const file = e.target.files?.[0];
        if (file) {
            setRecordedBlob(file);
            setAudioUrl(URL.createObjectURL(file));
            setUploadedFileName(file.name);
        }
      }} />

      <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-10 shadow-2xl shadow-slate-200 dark:shadow-none border border-slate-100 dark:border-slate-800 flex flex-col items-center transition-all duration-300">

        {!recordedBlob ? (
          <>
            <div className="h-12 w-full mb-6 flex justify-center">
              {isRecording ? <canvas ref={canvasRef} width={120} height={40} /> : <div className="text-slate-300"><SignalHigh className="w-10 h-10 opacity-20" /></div>}
            </div>

            <div className="text-6xl font-black text-slate-900 dark:text-white mb-10 tabular-nums">
              {formatTime(duration)}
            </div>

            <div className="flex flex-col items-center gap-6 w-full">
              {!isRecording ? (
                <button onClick={startRecording} className="w-24 h-24 bg-fs-primary text-white rounded-full flex items-center justify-center shadow-xl shadow-fs-primary/30 hover:scale-110 active:scale-95 transition-all">
                  <Mic className="w-10 h-10" />
                </button>
              ) : (
                <div className="flex flex-col items-center gap-4">
                  <div className="relative">
                    <div className="absolute inset-0 rounded-full bg-red-500 animate-ping opacity-20" style={{ animationDuration: '3s' }} />
                    <div className="absolute inset-0 rounded-full bg-red-500 animate-ping opacity-10" style={{ animationDuration: '2s', animationDelay: '0.5s' }} />
                    <div className="absolute inset-0 rounded-full bg-red-500 animate-pulse opacity-40 scale-110" />

                    <button 
                      onClick={stopRecording} 
                      className="relative z-10 w-24 h-24 bg-red-500 text-white rounded-full flex items-center justify-center shadow-2xl shadow-red-500/50 hover:scale-105 active:scale-95 transition-all"
                    >
                      <Square className="w-8 h-8 fill-current" />
                    </button>
                  </div>

                  <button 
                    onClick={cancelRecording}
                    className="flex items-center gap-2 px-4 py-2 text-xs font-bold text-slate-400 hover:text-red-500 transition-colors uppercase tracking-widest bg-slate-50 dark:bg-slate-800/50 rounded-full border border-slate-100 dark:border-slate-800"
                  >
                    <X className="w-3 h-3" /> Cancel Session
                  </button>
                </div>
              )}

              {/* Controls Group */}
              <div className="flex flex-wrap items-center justify-center gap-4">
                  {/* Language Selector */}
                  <div className="relative inline-block">
                    <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
                      <Globe className="w-4 h-4 text-slate-400" />
                    </div>
                    <select 
                      value={language}
                      onChange={(e) => setLanguage(e.target.value)}
                      className="appearance-none pl-9 pr-10 py-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-bold text-slate-600 dark:text-slate-300 focus:outline-none focus:ring-2 focus:ring-fs-primary/30 transition-all cursor-pointer"
                    >
                      {LANGUAGES.map(lang => (
                        <option key={lang.code} value={lang.code}>{lang.label}</option>
                      ))}
                    </select>
                    <div className="absolute inset-y-0 right-3 flex items-center pointer-events-none">
                      <ChevronDown className="w-3 h-3 text-slate-400" />
                    </div>
                  </div>

                  {/* Sensitivity Slider */}
                  <div className="flex items-center gap-3 bg-slate-50 dark:bg-slate-800 px-4 py-2 rounded-xl border border-slate-200 dark:border-slate-700">
                    <div className="text-slate-400" title="Adjust Input Sensitivity">
                      <Volume2 className="w-4 h-4" />
                    </div>
                    <input 
                      type="range"
                      min="0.5"
                      max="2.5"
                      step="0.1"
                      value={sensitivity}
                      onChange={(e) => setSensitivity(parseFloat(e.target.value))}
                      className="w-20 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-fs-primary"
                    />
                    <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 w-8">{Math.round(sensitivity * 100)}%</span>
                  </div>
              </div>

              {!isRecording && (
                <button onClick={() => document.getElementById('file-upload')?.click()} className="text-xs font-bold text-slate-500 dark:text-slate-400 hover:text-fs-primary flex items-center gap-2 uppercase tracking-widest">
                  <Upload className="w-4 h-4" /> Import Audio
                </button>
              )}

              {(isRecording || note) && (
                <div className="w-full space-y-2">
                  <div className="flex items-center justify-between px-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Live Meeting Notes ({language})</label>
                    <div className="flex items-center gap-1.5">
                      <div className={`w-1.5 h-1.5 rounded-full ${isAutoSaving ? 'bg-fs-primary animate-ping' : 'bg-slate-300'}`} />
                      <span className="text-[9px] font-bold text-slate-400 uppercase">
                        {isAutoSaving ? 'Auto-saving...' : (lastSaved ? `Draft saved ${lastSaved.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}` : '')}
                      </span>
                    </div>
                  </div>
                  <textarea 
                    value={note}
                    onChange={(e) => setNote(e.target.value)}
                    placeholder="Type live annotations here..."
                    className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl text-sm border-none focus:ring-2 focus:ring-fs-primary/50 resize-none h-32 dark:text-white shadow-inner"
                  />
                </div>
              )}
            </div>
          </>
        ) : (
          <div className="w-full flex flex-col items-center">
            <div className="w-full bg-slate-50 dark:bg-slate-800 p-6 rounded-3xl mb-8 flex flex-col items-center border border-slate-100 dark:border-slate-800 shadow-inner">
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Review Mode ({language})</p>
               <h3 className="text-sm font-bold text-slate-700 dark:text-slate-200 mb-4 truncate max-w-full px-4">{uploadedFileName || 'New Recording'}</h3>
               <div className="flex items-center gap-6">
                 <button onClick={() => setIsPlaying(!isPlaying)} className="w-16 h-16 bg-slate-900 dark:bg-slate-700 text-white rounded-full flex items-center justify-center shadow-lg hover:scale-105 transition-transform">
                   {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
                 </button>
               </div>
            </div>

            <div className="w-full space-y-2 mb-6">
              <div className="flex items-center justify-between px-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Finalize Notes</label>
                {lastSaved && (
                  <span className="text-[9px] font-bold text-slate-400 uppercase flex items-center gap-1">
                    <Save className="w-2.5 h-2.5" /> Draft Persisted
                  </span>
                )}
              </div>
              <textarea 
                value={note}
                onChange={(e) => setNote(e.target.value)}
                placeholder="Finalize notes before saving..."
                className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl text-sm border-none focus:ring-2 focus:ring-fs-primary/50 resize-none h-32 dark:text-white shadow-inner"
              />
            </div>

            <div className="flex w-full gap-4">
               <button onClick={() => {
                 if (window.confirm("Are you sure? This will discard the session.")) {
                   setRecordedBlob(null);
                   setAudioUrl(null);
                 }
               }} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 font-bold rounded-2xl hover:bg-red-50 hover:text-red-500 transition-colors">DISCARD</button>
               <button onClick={handleSave} disabled={isProcessing} className="flex-[2] py-4 bg-fs-primary text-white font-bold rounded-2xl shadow-lg shadow-fs-primary/20 flex items-center justify-center gap-2 hover:scale-[1.02] transition-transform active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Check className="w-5 h-5" />}
                 {isProcessing ? 'SAVING...' : 'SAVE TO HISTORY'}
               </button>
            </div>
          </div>
        )}
      </div>

      {activeTranscription && (
        <div className="bg-slate-900 dark:bg-slate-100 p-5 rounded-3xl shadow-xl flex items-center gap-4 animate-in slide-in-from-bottom-4 duration-500">
           <div className="relative">
             <div className="w-10 h-10 bg-fs-primary rounded-full flex items-center justify-center">
               <Sparkles className="w-5 h-5 text-white animate-pulse" />
             </div>
             <div className="absolute -inset-1 bg-fs-primary rounded-full animate-ping opacity-20 pointer-events-none" />
           </div>
           <div className="flex-1 min-w-0">
             <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-0.5">AI Transcription in Progress</p>
             <h4 className="text-sm font-bold text-white dark:text-slate-900 truncate">{activeTranscription.title}</h4>
           </div>
           <div className="text-right">
             <div className="text-sm font-mono font-bold text-fs-primary tracking-tighter tabular-nums">
               {formatTime(elapsedTranscriptionTime)}
             </div>
             <p className="text-[10px] text-slate-500 dark:text-slate-400 font-bold uppercase">Elapsed</p>
           </div>
        </div>
      )}

      {error && <p className="mt-4 text-center text-xs font-bold text-red-500 bg-red-50 dark:bg-red-900/10 py-2 rounded-lg">{error}</p>}
    </div>
  );
};
